          </div>

          <div>
            <label className="block text-xs font-black text-slate-500 uppercase tracking-widest mb-2 ml-1">Nama Penyulang</label>
            {ulpData ? (
              <select 
                required
                className="w-full px-4 py-3 border border-slate-200 rounded-xl focus:ring-4 focus:ring-primary/10 outline-none font-bold text-sm bg-white"
                value={penyulang}
                onChange={(e) => setPenyulang(e.target.value)}
              >
                <option value="">-- Pilih Penyulang --</option>
                {ulpData.penyulang.map(p => <option key={p} value={p}>{p}</option>)}
              </select>
            ) : (
              <input 
                required
                type="text"
                className="w-full px-4 py-3 border border-slate-200 rounded-xl outline-none font-bold text-sm"
                placeholder="Masukkan penyulang"
                value={penyulang}
                onChange={(e) => setPenyulang(e.target.value)}
              />
            )}
          </div>

          <div className="md:col-span-2">
             <label className="block text-xs font-black text-slate-500 uppercase tracking-widest mb-2 ml-1">Nama Keypoint</label>
             <input 
              required
              type="text" 
              className="w-full px-4 py-3 border border-slate-200 rounded-xl focus:ring-4 focus:ring-primary/10 outline-none font-bold text-sm transition-all uppercase"
              placeholder="CONTOH: RECLOSER / ABSW / FCO"
              value={keypoint}
              onChange={(e) => setKeypoint(e.target.value)}
            />
          </div>

          <div>
             <label className="block text-xs font-black text-slate-500 uppercase tracking-widest mb-2 ml-1">Titik Start</label>
             <input 
              required
              type="text" 
              className="w-full px-4 py-3 border border-slate-200 rounded-xl focus:ring-4 focus:ring-primary/10 outline-none font-bold text-sm transition-all"
              placeholder="LOKASI MULAI PATROL"
              value={titikStart}
              onChange={(e) => setTitikStart(e.target.value)}
            />
          </div>

          <div>
             <label className="block text-xs font-black text-slate-500 uppercase tracking-widest mb-2 ml-1">Titik Finish</label>
             <input 
              required
              type="text" 
              className="w-full px-4 py-3 border border-slate-200 rounded-xl focus:ring-4 focus:ring-primary/10 outline-none font-bold text-sm transition-all"
              placeholder="LOKASI SELESAI PATROL"
              value={titikFinish}
              onChange={(e) => setTitikFinish(e.target.value)}
            />
          </div>
        </div>

        <div className="border-t border-slate-100 pt-8">
          <div className="flex justify-between items-center mb-6">
             <div>
                <h3 className="text-lg font-black text-slate-800 uppercase tracking-tight">Dokumentasi Foto</h3>
                <p className="text-[9px] text-slate-400 font-bold uppercase tracking-widest">Minimal lampirkan foto sebelum dan sesudah pekerjaan</p>
             </div>
             <span className="text-[9px] font-black text-primary bg-cyan-50 border border-cyan-100 px-3 py-1.5 rounded-full uppercase tracking-widest">Maksimal 12 Foto</span>
          </div>

          <div className="space-y-8">
            {PHOTO_SECTIONS.map((num, idx) => (
              <div key={num} className="bg-slate-50/50 p-6 rounded-[2rem] border border-slate-200 transition-all hover:shadow-md hover:bg-white group">
                <div className="flex items-center gap-2 mb-4">
                  <span className="w-6 h-6 rounded-full bg-primary text-white flex items-center justify-center text-[10px] font-black">0{num}</span>
                  <h4 className="font-black text-slate-700 text-xs uppercase tracking-widest">Titik Pengamatan {num}</h4>
                </div>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                  <PhotoUpload 
                    id={`sebelum-${num}`}
                    label={`Kondisi Sebelum`}
                    imageSrc={photosSebelum[idx]}
                    onImageChange={(file) => handlePhotoChange(idx, 'sebelum', file)}
                  />
                  <PhotoUpload 
                    id={`sesudah-${num}`}
                    label={`Kondisi Sesudah`}
                    imageSrc={photosSesudah[idx]}
                    onImageChange={(file) => handlePhotoChange(idx, 'sesudah', file)}
                  />
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="flex items-center justify-end gap-3 pt-6 border-t border-slate-100 sticky bottom-0 bg-white/95 backdrop-blur py-6 z-10 px-6 -mx-6">
          <button 
            type="button" 
            onClick={onCancel}
            disabled={isSubmitting}
            className="px-6 py-3.5 rounded-2xl text-slate-400 hover:text-slate-600 hover:bg-slate-100 font-black uppercase text-[10px] tracking-widest transition-all"
          >
            Batal
          </button>
          <button 
            type="submit" 
            disabled={isSubmitting}
            className="px-10 py-3.5 rounded-2xl bg-primary text-white font-black uppercase text-[10px] tracking-widest hover:bg-cyan-800 shadow-xl shadow-cyan-100 transition-all flex items-center justify-center gap-3 disabled:opacity-50 disabled:scale-95"
          >
            {isSubmitting ? (
              <>
                <div className="w-3 h-3 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                Memproses...
              </>
            ) : editData ? 'Perbarui Laporan' : 'Simpan Laporan'}
          </button>
        </div>
      </form>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { UserRole, ViewState, ReportData, ULPName, ULPData, LoginSession } from './types';
import { InputForm } from './components/InputForm';
import { Dashboard } from './components/Dashboard';
import { DataTable } from './components/DataTable';
import { AdminSettings } from './components/AdminSettings';
import { AdminRekap } from './components/AdminRekap';
import { LoginConfig } from './components/LoginConfig';
import { DATA_ULP as INITIAL_DATA_ULP, APP_VERSION } from './constants';
import { api } from './services/api';

const LOGO_URL = "https://plnes.co.id/_next/image?url=https%3A%2F%2Fcms.plnes.co.id%2Fuploads%2FLogo_HP_New_Temporary_09a9c5a521.png&w=750&q=75"; 
const APP_LOGO = "https://raw.githubusercontent.com/plnesbukittinggi-ai/yandal_patrol/main/ChatGPT%20Image%2018%20Des%202025%2C%2011.11.52.png";

declare global {
  interface Window {
    ExcelJS: any;
  }
}

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [view, setView] = useState<ViewState>('LOGIN');
  const [isLoading, setIsLoading] = useState(false);
  const [errorLoad, setErrorLoad] = useState<string | null>(null);
  const [isDemoMode, setIsDemoMode] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);

  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [adminPassword, setAdminPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  const [session, setSession] = useState<LoginSession>({ ulp: null, petugas1: null, petugas2: null });

  const [tableStartDate, setTableStartDate] = useState('');
  const [tableEndDate, setTableEndDate] = useState('');
  const [tableUlpFilter, setTableUlpFilter] = useState<ULPName | ''>('');

  const [reports, setReports] = useState<ReportData[]>([]);
  const [masterData, setMasterData] = useState<Record<string, ULPData>>(INITIAL_DATA_ULP);
  const [editingReport, setEditingReport] = useState<ReportData | null>(null);

  // Ref untuk menyimpan ID yang baru saja di-edit agar tidak tertimpa data lama dari server saat sync
  const pendingUpdatesRef = useRef<Map<string, string>>(new Map());

  useEffect(() => {
    const savedDemo = localStorage.getItem('yandal_demo_mode');
    if (savedDemo === 'true') {
      setIsDemoMode(true);
      const savedReports = localStorage.getItem('yandal_local_reports');
      if (savedReports) setReports(JSON.parse(savedReports));
    }
    fetchData(true);
  }, []);

  // Autorefresh otomatis saat filter berubah
  useEffect(() => {
    if (view === 'TABLE' && !isDemoMode) {
      fetchData(false);
    }
  }, [tableStartDate, tableEndDate, tableUlpFilter, view]);

  const fetchData = async (showLoading = true) => {
    if (isDemoMode) return;

    if (showLoading) {
      setIsLoading(true);
      setErrorLoad(null);
    }
    try {
      const data = await api.getAllData();
      if (data && data.reports) {
        setReports(prevReports => {
          const reportMap = new Map<string, ReportData>();

          // 1. Masukkan data yang ada di state sekarang
          prevReports.forEach(r => reportMap.set(r.id, r));

          // 2. Masukkan data dari server
          data.reports.forEach((serverReport: ReportData) => {
            const existing = reportMap.get(serverReport.id);
            const pendingTimestamp = pendingUpdatesRef.current.get(serverReport.id);

            // JIKA ada update lokal yang baru saja dilakukan (pending), 
            // JANGAN pakai data server kecuali timestamp server lebih baru dari update kita.
            if (pendingTimestamp && new Date(serverReport.timestamp) < new Date(pendingTimestamp)) {
              return; // Abaikan data server yang usang
            }

            if (!existing || new Date(serverReport.timestamp) >= new Date(existing.timestamp)) {
              reportMap.set(serverReport.id, serverReport);
            }
          });

          return Array.from(reportMap.values());
        });

        if (data.masterData) setMasterData(data.masterData);
      }
    } catch (error: any) {
      console.error("Fetch failed:", error);
      if (showLoading) setErrorLoad(error.message || "Gagal terhubung ke database.");
    } finally {
      if (showLoading) setIsLoading(false);
    }
  };

  const startDemoMode = () => {
    setIsDemoMode(true);
    localStorage.setItem('yandal_demo_mode', 'true');
    setErrorLoad(null);
  };

  const handleInitialRoleSelect = (selectedRole: UserRole) => {
    setRole(selectedRole);
    if (selectedRole === UserRole.ADMIN) return; 
    setView('CONFIG');
  };

  const handleAdminLoginSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminPassword === 'Adminbkt') {
      setRole(UserRole.ADMIN);
      setView('DASHBOARD');
      setShowAdminLogin(false);
    } else {
      setLoginError('Password salah!');
    }
  };

  const handleConfigConfirm = (conf: LoginSession) => {
    setSession(conf);
    setView(role === UserRole.GUEST ? 'TABLE' : 'INPUT');
  };

  const handleLogout = () => {
    setRole(null);
    setView('LOGIN');
    setShowAdminLogin(false);
    setSession({ ulp: null, petugas1: null, petugas2: null });
    setEditingReport(null);
  };

  const handleBackToMenu = () => {
     if (view === 'CONFIG') {
        setView('LOGIN');
        setRole(null);
     } else {
        if (role === UserRole.ADMIN) {
           setView('DASHBOARD');
        } else {
           setView('LOGIN');
           setRole(null);
        }
     }
     setEditingReport(null);
  };

  const handleSaveReport = async (data: ReportData, isEditMode: boolean) => {
    setIsSyncing(true);

    // Simpan timestamp update lokal ke ref untuk kontrol sinkronisasi
    pendingUpdatesRef.current.set(data.id, data.timestamp);

    // OPTIMISTIC UPDATE: Perbarui UI secara instan agar user tidak merasa aplikasi lambat
    setReports(prev => {
      const filtered = prev.filter(r => r.id !== data.id);
      return [data, ...filtered];
    });

    try {
      if (isDemoMode) {
        const currentReports = [data, ...reports.filter(r => r.id !== data.id)];
        localStorage.setItem('yandal_local_reports', JSON.stringify(currentReports));
      } else {
        // Kirim ke API dengan flag isEdit yang eksplisit
        await api.saveReport(data, isEditMode);

        // Jeda 5 detik sebelum sinkronisasi ulang dari server
        // untuk memastikan Google Sheets telah selesai melakukan pemrosesan data.
        setTimeout(() => {
          fetchData(false);
          pendingUpdatesRef.current.delete(data.id);
        }, 5000);
      }

      setEditingReport(null);
      setView('TABLE');
    } catch (e) {
      console.error("Save report failed:", e);
      alert("Gagal mengirim data ke Spreadsheet. Periksa koneksi internet Anda.");
    } finally {
      setIsSyncing(false);
    }
  };

  const openEditForm = (report: ReportData) => {
    setEditingReport(report);
    setView('INPUT');
  };

  const filteredReportsForTable = useMemo(() => {
    const uniqueMap = new Map<string, ReportData>();

    // Urutkan dari yang paling lama ke paling baru sebelum dimasukkan ke Map
    // ID yang sama dengan timestamp lebih baru akan menimpa ID lama
    const sortedRaw = [...reports].sort((a, b) => 
      new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime()
    );

    sortedRaw.forEach(r => uniqueMap.set(r.id, r));
    const uniqueReportsList = Array.from(uniqueMap.values());

    return uniqueReportsList
      .filter(r => {
        const sessionMatch = !session.ulp || r.ulp === session.ulp;
        if (!sessionMatch) return false;
        const adminUlpMatch = role !== UserRole.ADMIN || !tableUlpFilter || r.ulp === tableUlpFilter;
        if (!adminUlpMatch) return false;
        const reportDate = new Date(r.timestamp).toISOString().split('T')[0];
        const startMatch = !tableStartDate || reportDate >= tableStartDate;
        const endMatch = !tableEndDate || reportDate <= tableEndDate;
        return startMatch && endMatch;
      })
      .sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
  }, [reports, session.ulp, role, tableUlpFilter, tableStartDate, tableEndDate]);

  const fixBase64 = (str: string) => {
    if (!str || !str.includes(',')) return null;
    const [meta, data] = str.split(',');
    return meta + ',' + data.replace(/\s/g, '+');
  };

  const formatDriveUrl = (url: string) => {
    if (url.includes('drive.google.com/file/d/')) {
      const id = url.split('/d/')[1]?.split('/')[0];
      if (id) return `https://lh3.googleusercontent.com/d/${id}`;
    }
    return url;
  };

  const getBase64FromUrl = async (url: string): Promise<string | null> => {
    if (!url) return null;
    if (url.startsWith('data:image')) return fixBase64(url);
    try {
      const formattedUrl = formatDriveUrl(url);
      const response = await fetch(formattedUrl);
      if (!response.ok) return null;
      const blob = await response.blob();
      return new Promise((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result as string);
        reader.onerror = () => resolve(null);
        reader.readAsDataURL(blob);
      });
    } catch (e) {
      console.error("Failed to fetch image", e);
      return null;
    }
  };

  const ensureExcelJS = (): Promise<any> => {
    return new Promise((resolve, reject) => {
      const existing = window.ExcelJS || (window as any).Excel;
      if (existing) {
        resolve(existing);
        return;
      }
      const script = document.createElement('script');
      script.src = 'https://cdnjs.cloudflare.com/ajax/libs/exceljs/4.4.0/exceljs.min.js';
      script.onload = () => resolve(window.ExcelJS || (window as any).Excel);
      script.onerror = () => reject(new Error("Gagal memuat library ExcelJS"));
      document.head.appendChild(script);
    });
  };

  const handleDownloadExcel = async () => {
    let ExcelJS;
    try {
      ExcelJS = await ensureExcelJS();
    } catch (err) {
      alert("Library ExcelJS tidak dapat dimuat.");
      return;
    }

    setIsSyncing(true);

    const workbook = new ExcelJS.Workbook();
    const worksheet = workbook.addWorksheet('Laporan Patrol');

    const columns: any[] = [
      { header: 'No', key: 'no', width: 5 },
      { header: 'Tanggal', key: 'tanggal', width: 15 },
      { header: 'No. Penugasan', key: 'noPenugasan', width: 25 },
      { header: 'ULP', key: 'ulp', width: 20 },
      { header: 'Petugas 1', key: 'petugas1', width: 20 },
      { header: 'Petugas 2', key: 'petugas2', width: 20 },
      { header: 'Penyulang', key: 'penyulang', width: 15 },
      { header: 'Keypoint', key: 'keypoint', width: 25 },
      { header: 'Start', key: 'start', width: 25 },
      { header: 'Finish', key: 'finish', width: 25 },
    ];

    for (let i = 1; i <= 6; i++) {
      columns.push({ header: `Foto Sebelum ${i}`, key: `sebelum_${i}`, width: 35 });
      columns.push({ header: `Foto Sesudah ${i}`, key: `sesudah_${i}`, width: 35 });
    }

    worksheet.columns = columns;
    worksheet.getRow(1).font = { bold: true };
    worksheet.getRow(1).alignment = { vertical: 'middle', horizontal: 'center' };
    worksheet.getRow(1).height = 25;

    for (const [index, r] of filteredReportsForTable.entries()) {
      const row = worksheet.addRow({
        no: index + 1,
        tanggal: new Date(r.timestamp).toLocaleDateString('id-ID'),
        noPenugasan: r.noPenugasan,
        ulp: r.ulp,
        petugas1: r.petugas1,
        petugas2: r.petugas2,
        penyulang: r.penyulang,
        keypoint: r.keypoint,
        start: r.titikStart,
        finish: r.titikFinish,
      });

      row.height = 110; 
      row.alignment = { vertical: 'middle', horizontal: 'center' };

      for (let s = 0; s < 6; s++) {
        const fotoSebelumUrl = r.photos?.sebelum?.[s];
        const fotoSesudahUrl = r.photos?.sesudah?.[s];
        const colSebelum = 10 + s * 2;
        const colSesudah = 11 + s * 2;

        if (fotoSebelumUrl) {
          try {
            const base64 = await getBase64FromUrl(fotoSebelumUrl);
            if (base64) {
              const imgId = workbook.addImage({ 
                base64, 
                extension: base64.startsWith('data:image/png') ? 'png' : 'jpeg' 
              });
              worksheet.addImage(imgId, {
                tl: { col: colSebelum, row: row.number - 1 },
                ext: { width: 220, height: 130 }
              });
            }
          } catch (e) {}
        }

        if (fotoSesudahUrl) {
          try {
            const base64 = await getBase64FromUrl(fotoSesudahUrl);
            if (base64) {
              const imgId = workbook.addImage({ 
                base64, 
                extension: base64.startsWith('data:image/png') ? 'png' : 'jpeg' 
              });
              worksheet.addImage(imgId, {
                tl: { col: colSesudah, row: row.number - 1 },
                ext: { width: 220, height: 130 }
              });
            }
          } catch (e) {}
        }
      }
    }

    const dateStr = new Date().toISOString().split('T')[0];
    const filename = `Laporan_Patrol_${tableUlpFilter || 'Semua_ULP'}_${dateStr}.xlsx`;

    try {
      const buffer = await workbook.xlsx.writeBuffer();
      const blob = new Blob([buffer], {
        type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      });
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = filename;
      a.click();
      window.URL.revokeObjectURL(url);
    } catch (err) {
      alert("Terjadi kesalahan saat mengolah file Excel.");
    } finally {
      setIsSyncing(false);
    }
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50 gap-4 p-4 text-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary"></div>
        <p className="text-slate-700 font-bold">Menghubungkan ke Database...</p>
      </div>
    );
  }

  if (errorLoad && !isDemoMode) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50 p-6 text-center">
        <div className="bg-white p-8 rounded-3xl shadow-2xl max-w-lg border border-red-100 animate-fade-in">
          <div className="text-red-500 mb-6">
            <svg className="w-16 h-16 mx-auto" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
            </svg>
          </div>
          <h2 className="text-xl font-black text-slate-800 mb-2 uppercase tracking-tight">Koneksi Bermasalah</h2>
          <div className="bg-red-50 p-4 rounded-xl border border-red-100 mb-6 text-left">
            <p className="text-red-700 text-xs font-bold leading-relaxed">{errorLoad}</p>
          </div>

          <div className="space-y-3">
            <button 
              onClick={() => fetchData(true)}
              className="w-full bg-primary text-white px-6 py-4 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-cyan-800 transition-all shadow-lg shadow-cyan-100"
            >
              Coba Sinkron Ulang
            </button>
            <button 
              onClick={startDemoMode}
              className="w-full bg-slate-100 text-slate-700 px-6 py-4 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-slate-200 transition-all border border-slate-200"
            >
              Gunakan Mode Demo (Offline)
            </button>
          </div>
        </div>
      </div>
    );
  }

  if (view === 'LOGIN') {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
        <div className="bg-white p-8 rounded-2xl shadow-xl max-w-md w-full border border-slate-200">
          <div className="text-center mb-8">
            <img src={LOGO_URL} alt="Logo PLN" className="h-16 mx-auto mb-4 object-contain" />
            <h2 className="text-sm font-bold text-slate-500 uppercase tracking-widest mb-1">PLN Electricity Services</h2>
            <h1 className="text-lg font-extrabold text-slate-800 mb-6 uppercase tracking-tight">Unit Layanan Bukittinggi</h1>
            <div className="relative group mb-6">
              <img src={APP_LOGO} alt="Logo App" className="relative h-48 mx-auto object-contain transition-transform duration-500 hover:scale-110" />
            </div>
            <h2 className="text-2xl font-bold text-primary mb-1 leading-none">Aplikasi Monitoring</h2>
            <h2 className="text-2xl font-bold text-primary mb-2">Yandal Patrol</h2>
          </div>
          <div className="space-y-4">
            <button onClick={() => handleInitialRoleSelect(UserRole.USER)} className="w-full bg-primary hover:bg-cyan-800 text-white font-black py-4 px-6 rounded-2xl transition-all transform hover:scale-[1.02] flex items-center justify-center gap-2 shadow-lg shadow-cyan-100 uppercase text-xs tracking-widest">
              Login sebagai Petugas
            </button>
            {!showAdminLogin ? (
              <>
                <button onClick={() => setShowAdminLogin(true)} className="w-full bg-slate-800 hover:bg-slate-900 text-white font-black py-4 px-6 rounded-2xl transition-all transform hover:scale-[1.02] flex items-center justify-center gap-2 uppercase text-xs tracking-widest">
                  Login sebagai Admin
                </button>
                <button onClick={() => handleInitialRoleSelect(UserRole.GUEST)} className="w-full bg-white border-2 border-slate-200 hover:border-primary hover:text-primary text-slate-600 font-black py-4 px-6 rounded-2xl transition-all transform hover:scale-[1.02] flex items-center justify-center gap-2 uppercase text-xs tracking-widest">
                  Tampilkan Data
                </button>
              </>
            ) : (
              <form onSubmit={handleAdminLoginSubmit} className="bg-slate-50 p-5 rounded-2xl border border-slate-200 animate-fade-in">
                <h3 className="text-xs font-black text-slate-500 uppercase mb-3 tracking-widest">Verifikasi Admin</h3>
                <input 
                  type="password"
                  autoFocus
                  className={`w-full px-4 py-3 border rounded-xl mb-3 outline-none transition-all focus:ring-2 focus:ring-primary/20 ${loginError ? 'border-red-500 bg-red-50' : 'border-slate-300'}`}
                  value={adminPassword}
                  onChange={(e) => { setAdminPassword(e.target.value); setLoginError(''); }}
                  placeholder="Password Admin..."
