import { ReportData, ULPData } from '../types';

/**
 * URL Google Apps Script
 */
const GOOGLE_SCRIPT_URL: string = 'https://script.google.com/macros/s/AKfycbw4uVV-vGPeL0Peg-bdco6VL8zKAH8Z5N3ZBJo3bYEZt8IVHNkBAuKluLsQLlu7msQ/exec'; 

export const api = {
  getAllData: async () => {
    try {
      const response = await fetch(`${GOOGLE_SCRIPT_URL}?action=getAll`, {
        method: 'GET',
        mode: 'cors',
        headers: { 'Accept': 'application/json' }
      });

      if (!response.ok) {
        throw new Error(`HTTP Error: ${response.status}`);
      }

      const text = await response.text();

      if (text.trim().startsWith('<')) {
        throw new Error("Database mengembalikan format HTML. Pastikan skrip dideploy sebagai 'Anyone'.");
      }

      return JSON.parse(text);
    } catch (error: any) {
      console.error("API Error (GetAll):", error);
      throw error;
    }
  },

  saveReport: async (report: ReportData, isEdit: boolean = false) => {
    try {
      const action = isEdit ? 'updateReport' : 'saveReport';
      const payload = JSON.stringify({
        action: action,
        data: report
      });

      /**
       * PENTING: Untuk POST ke Google Apps Script, mode 'no-cors' adalah yang paling stabil
       * untuk menghindari error 'Failed to fetch'. Browser akan mengirimkan data 
       * tanpa melakukan pre-flight check yang sering gagal pada redirect Google.
       */
      await fetch(GOOGLE_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 
          'Content-Type': 'text/plain' 
        },
        body: payload
      });

      // Pada mode no-cors, kita tidak bisa membaca respon (opaque response), 
      // tapi selama tidak throw error, request dianggap berhasil dikirim.
      return true;
    } catch (error) {
      console.error("API Error (Save/Update):", error);
      throw error;
    }
  },

  updateMasterData: async (masterData: Record<string, ULPData>) => {
    try {
      const payload = JSON.stringify({
        action: 'updateMaster',
        data: masterData
      });

      await fetch(GOOGLE_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'text/plain' },
        body: payload
      });
      return true;
    } catch (error) {
      console.error("API Error (UpdateMaster):", error);
      return true;
    }
  }
};

