### Penting: Periksa Kode Google Apps Script Anda!
Agar update data bekerja, fungsi `doPost(e)` di skrip Google Anda **harus** mampu menangani perintah dari URL. Berikut adalah struktur kode GAS yang disarankan:

```javascript
function doPost(e) {
  // 1. Ambil 'action' dari parameter URL (?action=...)
  var action = e.parameter.action;
  var jsonData;

  // 2. Jika di URL tidak ada, coba ambil dari body JSON
  try {
    jsonData = JSON.parse(e.postData.contents);
    if (!action) action = jsonData.action;
  } catch (err) {
    // Penanganan jika JSON tidak valid
  }

  var sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("Laporan"); // Ganti sesuai nama sheet Anda

  if (action === "updateReport") {
    var report = jsonData.data;
    var data = sheet.getDataRange().getValues();
    var idToFind = report.id;

    // Cari baris berdasarkan ID (asumsi ID ada di kolom pertama / indeks 0)
    for (var i = 1; i < data.length; i++) {
      if (data[i][0] == idToFind) {
        // Lakukan pembaruan di baris tersebut
        // Contoh: sheet.getRange(i + 1, 2).setValue(report.timestamp);
        // ... teruskan untuk kolom lainnya ...
        return ContentService.createTextOutput("Update Success");
      }
    }
  }

  // Kode saveReport Anda di bawah sini...
}
```

**Kenapa ini penting?**
Dengan menyertakan `?action=updateReport` di URL, Google Apps Script akan lebih mudah membedakan antara laporan baru dan laporan yang sedang diupdate sebelum ia mulai memproses data gambar (Base64) yang sangat panjang.

Langsung perbaiki GAS ini sesuai perubahan diatas  :
var SPREADSHEET_ID = '1kb1olb-l-9EeX8nrRaW_rrbuRv1BkLVG6nbxVa32Ux4';
var DRIVE_FOLDER_ID = '1zMK33wH2daWieijYsw3csJJtAXwwOGaj';

function doGet(e) {
  var action = e.parameter.action;
  if (action == 'getAll') {
    return getAllData();
  }
}

function doPost(e) {
  try {
    var contents = JSON.parse(e.postData.contents);
    var action = contents.action;

    if (action == 'saveReport') {
      return saveReport(contents.data);
    } else if (action == 'updateMaster') {
      return updateMaster(contents.data);
    }
  } catch (error) {
    return ContentService.createTextOutput(JSON.stringify({ status: 'error', message: error.toString() })).setMimeType(ContentService.MimeType.JSON);
  }
}

function getAllData() {
  var ss = SpreadsheetApp.openById(SPREADSHEET_ID);
  var sheetLaporan = ss.getSheetByName('Laporan');
  var reports = [];

  if (sheetLaporan.getLastRow() > 1) {
    var dataLaporan = sheetLaporan.getDataRange().getValues();

    for (var i = 1; i < dataLaporan.length; i++) {
      var row = dataLaporan[i];
      if (!row[0]) continue;

      var photoSeb = [];
      var photoSes = [];
      // Perbaikan index: i*2 diganti p*2 untuk iterasi foto yang benar
      for(var p=0; p<6; p++) {
         photoSeb.push(row[11 + (p * 2)]);
         photoSes.push(row[12 + (p * 2)]);
      }

      var ts = row[1];
      if (ts instanceof Date) { ts = ts.toISOString(); }

      reports.push({
        id: String(row[0]),
        timestamp: ts,
        bulan: row[2],
        noPenugasan: row[3],
        ulp: row[4],
        petugas1: row[5],
        petugas2: row[6],
        penyulang: row[7],
        keypoint: row[8],
        titikStart: row[9],
        titikFinish: row[10],
        photos: { sebelum: photoSeb, sesudah: photoSes }
      });
    }
  }

  var sheetMaster = ss.getSheetByName('MasterData');
  var masterData = {};
  if (sheetMaster.getLastRow() > 1) {
    var dataMaster = sheetMaster.getDataRange().getValues();
    for (var i = 1; i < dataMaster.length; i++) {
      if (dataMaster[i][0] && dataMaster[i][1]) {
        try {
          masterData[dataMaster[i][0]] = JSON.parse(dataMaster[i][1]);
        } catch(e) {}
      }
    }
  }

  return ContentService.createTextOutput(JSON.stringify({ reports: reports, masterData: masterData })).setMimeType(ContentService.MimeType.JSON);
}

function uploadToDrive(folder, base64Data, fileName) {
  if (!base64Data || base64Data.length < 100) return "";
  // JIKA DATA SUDAH BERUPA URL (http), JANGAN UPLOAD LAGI
  if (String(base64Data).indexOf("http") === 0) return base64Data;

  try {
    var contentType = base64Data.substring(5, base64Data.indexOf(';'));
    var bytes = Utilities.base64Decode(base64Data.substring(base64Data.indexOf('base64,') + 7));
    var blob = Utilities.newBlob(bytes, contentType, fileName);

    var file = folder.createFile(blob);
    file.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);
    return file.getUrl();
  } catch (e) {
    return "Error Upload: " + e.toString();
  }
}

function saveReport(data) {
  var ss = SpreadsheetApp.openById(SPREADSHEET_ID);
  var sheet = ss.getSheetByName('Laporan');
  var folder = DriveApp.getFolderById(DRIVE_FOLDER_ID);

  // 1. Proses Upload Foto (Hanya jika ada data baru)
  var photosSebLinks = [];
  var photosSesLinks = [];

  for (var i = 0; i < 6; i++) {
      var safeNo = (data.noPenugasan || 'NoID').replace(/[^a-zA-Z0-9-_]/g, '_');
      var safeKP = (data.keypoint || 'KP').replace(/[^a-zA-Z0-9-_]/g, '_');
      var nameBase = safeNo + "_" + safeKP + "_Area" + (i+1);

      var linkSeb = uploadToDrive(folder, data.photos.sebelum[i], nameBase + "_SBLM.jpg");
      var linkSes = uploadToDrive(folder, data.photos.sesudah[i], nameBase + "_SSDH.jpg");

      photosSebLinks.push(linkSeb);
      photosSesLinks.push(linkSes);
  }

  // 2. Siapkan Array Baris Baru
  var rowData = [
    data.id,
    data.timestamp,
    data.bulan,
    data.noPenugasan,
    data.ulp,
    data.petugas1,
    data.petugas2,
    data.penyulang,
    data.keypoint,
    data.titikStart,
    data.titikFinish
  ];

  for(var i=0; i<6; i++) {
    rowData.push(photosSebLinks[i]);
    rowData.push(photosSesLinks[i]);
  }

  // 3. LOGIKA UPDATE ATAU INSERT
  var values = sheet.getDataRange().getValues();
  var targetRow = -1;

  // Cari ID yang sama di Kolom A (index 0)
  for (var r = 1; r < values.length; r++) {
    if (values[r][0] == data.id) {
      targetRow = r + 1; // Baris ditemukan (ditambah 1 karena index Sheets mulai dari 1)
      break;
    }
  }

  if (targetRow !== -1) {
    // JIKA DITEMUKAN: Update baris tersebut
    sheet.getRange(targetRow, 1, 1, rowData.length).setValues([rowData]);
  } else {
    // JIKA TIDAK DITEMUKAN: Buat baris baru di paling bawah
    sheet.appendRow(rowData);
  }

  return ContentService.createTextOutput(JSON.stringify({ status: 'success' })).setMimeType(ContentService.MimeType.JSON);
}

function updateMaster(fullMasterData) {
  var ss = SpreadsheetApp.openById(SPREADSHEET_ID);
  var sheet = ss.getSheetByName('MasterData');
  if (sheet.getLastRow() > 1) {
    sheet.getRange(2, 1, sheet.getLastRow() - 1, 2).clearContent();
  }
  var rows = [];
  for (var key in fullMasterData) {
    rows.push([key, JSON.stringify(fullMasterData[key])]);
  }
  if (rows.length > 0) {
    sheet.getRange(2, 1, rows.length, 2).setValues(rows);
  }
  return ContentService.createTextOutput(JSON.stringify({ status: 'success' })).setMimeType(ContentService.MimeType.JSON);
}

