  }

  if (targetRow !== -1) {
    // Update baris yang sudah ada
    sheet.getRange(targetRow, 1, 1, rowData.length).setValues([rowData]);
  } else {
    // Tambah baris baru jika ID tidak ditemukan
    sheet.appendRow(rowData);
  }

  return ContentService.createTextOutput(JSON.stringify({ status: 'success' }))
    .setMimeType(ContentService.MimeType.JSON);
}

function updateMaster(fullMasterData) {
  var ss = SpreadsheetApp.openById(SPREADSHEET_ID);
  var sheet = ss.getSheetByName('MasterData');
  if (sheet.getLastRow() > 1) {
    sheet.getRange(2, 1, sheet.getLastRow() - 1, 2).clearContent();
  }
  var rows = [];
  for (var key in fullMasterData) {
    rows.push([key, JSON.stringify(fullMasterData[key])]);
  }
  if (rows.length > 0) {
    sheet.getRange(2, 1, rows.length, 2).setValues(rows);
  }
  return ContentService.createTextOutput(JSON.stringify({ status: 'success' }))
    .setMimeType(ContentService.MimeType.JSON);
}
```

### Apa yang diperbaiki?
1.  **Dukungan `updateReport`**: Sekarang kode mengenali aksi `updateReport` yang dikirim aplikasi. Tanpa ini, perintah edit dari aplikasi akan diabaikan oleh server.
2.  **Identifikasi via URL**: Ditambahkan `e.parameter.action` agar GAS bisa langsung tahu apa yang harus dilakukan sebelum memproses file gambar yang besar.
3.  **Logika Upload Foto Cerdas**: Jika data foto yang dikirim adalah URL (karena saat edit, foto lama tidak diubah), sistem tidak akan melakukan upload ulang ke Drive, sehingga proses simpan menjadi jauh lebih cepat.
4.  **Deduplikasi**: Pengecekan ID dilakukan di seluruh baris yang ada di Spreadsheet untuk memastikan tidak ada data ganda saat melakukan pembaharuan.

