import { ReportData, ULPData } from '../types';

/**
 * URL Google Apps Script - Pastikan ini adalah URL "Web App" versi terbaru yang sudah di-deploy sebagai "Anyone"
 */
const GOOGLE_SCRIPT_URL: string = 'https://script.google.com/macros/s/AKfycbyDL89H5NYsQwFdu2tFAinm81bl0kQRLhC5eQLVH6rHVXgHBz23tGXStIhsuhCwDNii/exec'; 

export const api = {
  getAllData: async () => {
    try {
      const response = await fetch(`${GOOGLE_SCRIPT_URL}?action=getAll`, {
        method: 'GET',
        mode: 'cors',
        headers: { 'Accept': 'application/json' }
      });

      if (!response.ok) {
        throw new Error(`HTTP Error: ${response.status}`);
      }

      const text = await response.text();

      if (text.trim().startsWith('<')) {
        throw new Error("Database mengembalikan format HTML. Pastikan skrip dideploy sebagai 'Anyone' (Bahkan anonim).");
      }

      return JSON.parse(text);
    } catch (error: any) {
      console.error("API Error (GetAll):", error);
      throw error;
    }
  },

  saveReport: async (report: ReportData, isEdit: boolean = false) => {
    try {
      const action = isEdit ? 'updateReport' : 'saveReport';

      // Bungkus data dalam objek yang dikenali GAS
      const payload = JSON.stringify({
        action: action,
        data: report
      });

      /**
       * PENTING UNTUK GOOGLE APPS SCRIPT:
       * 1. Gunakan 'no-cors' agar browser tidak memblokir redirect Google.
       * 2. Gunakan 'text/plain' agar browser tidak mengirim pre-flight OPTIONS request.
       * 3. Sertakan action di URL query string sebagai cadangan.
       */
      const targetUrl = `${GOOGLE_SCRIPT_URL}?action=${action}`;

      console.log(`Mengirim data ke: ${targetUrl}`);

      await fetch(targetUrl, {
        method: 'POST',
        mode: 'no-cors', // Menghindari error "Failed to Fetch" akibat CORS
        headers: { 
          'Content-Type': 'text/plain;charset=utf-8' 
        },
        body: payload
      });

      // Pada mode 'no-cors', kita tidak bisa membaca respon sukses/gagal dari server.
      // Kita asumsikan terkirim jika tidak ada error throw dari fetch itu sendiri.
      return true;
    } catch (error) {
      console.error("API Error (Save/Update):", error);
      throw error;
    }
  },

  updateMasterData: async (masterData: Record<string, ULPData>) => {
    try {
      const payload = JSON.stringify({
        action: 'updateMaster',
        data: masterData
      });

      const targetUrl = `${GOOGLE_SCRIPT_URL}?action=updateMaster`;

      await fetch(targetUrl, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'text/plain' },
        body: payload
      });
      return true;
    } catch (error) {
      console.error("API Error (UpdateMaster):", error);
      return true;
    }
  }
};

