import { ReportData, ULPData } from '../types';

/**
 * URL Google Apps Script
 * PENTING: Setiap kali Anda mengubah kode di GAS, Anda harus melakukan "New Deployment" 
 * dan pastikan akses disetel ke "Anyone". Salin URL barunya ke sini.
 */
const GOOGLE_SCRIPT_URL: string = 'https://script.google.com/macros/s/AKfycbyDL89H5NYsQwFdu2tFAinm81bl0kQRLhC5eQLVH6rHVXgHBz23tGXStIhsuhCwDNii/exec'; 

export const api = {
  getAllData: async () => {
    try {
      const response = await fetch(`${GOOGLE_SCRIPT_URL}?action=getAll`, {
        method: 'GET',
        headers: { 'Accept': 'application/json' }
      });

      if (!response.ok) throw new Error(`HTTP Error: ${response.status}`);
      const text = await response.text();
      return JSON.parse(text);
    } catch (error: any) {
      console.error("API Error (GetAll):", error);
      throw error;
    }
  },

  saveReport: async (report: ReportData, isEdit: boolean = false) => {
    try {
      const action = isEdit ? 'updateReport' : 'saveReport';
      const payload = JSON.stringify({
        action: action,
        data: report
      });

      // Kirim sebagai text/plain untuk menghindari pre-flight CORS yang rumit di Google
      // Kita tambahkan parameter action di URL agar GAS bisa mendeteksi aksi meskipun parsing body gagal
      const targetUrl = `${GOOGLE_SCRIPT_URL}?action=${action}`;

      console.log("Mengirim Laporan ke GAS...", action);

      const response = await fetch(targetUrl, {
        method: 'POST',
        mode: 'cors', // Kita coba cors dulu agar bisa menangkap error jika gagal
        headers: { 
          'Content-Type': 'text/plain;charset=utf-8' 
        },
        body: payload
      });

      // Google Apps Script Web App selalu melakukan redirect (302).
      // fetch akan mengikuti redirect tersebut secara otomatis.
      return true;
    } catch (error) {
      console.error("Gagal mengirim ke GAS:", error);

      // Jika error 'Failed to fetch', biasanya karena masalah CORS pada redirect Google.
      // Kita coba fallback menggunakan mode no-cors jika cara pertama gagal.
      try {
        const action = isEdit ? 'updateReport' : 'saveReport';
        await fetch(`${GOOGLE_SCRIPT_URL}?action=${action}`, {
          method: 'POST',
          mode: 'no-cors',
          headers: { 'Content-Type': 'text/plain' },
          body: JSON.stringify({ action, data: report })
        });
        return true;
      } catch (e) {
        throw e;
      }
    }
  },

  updateMasterData: async (masterData: Record<string, ULPData>) => {
    try {
      await fetch(`${GOOGLE_SCRIPT_URL}?action=updateMaster`, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'text/plain' },
        body: JSON.stringify({ action: 'updateMaster', data: masterData })
      });
      return true;
    } catch (error) {
      return true;
    }
  }
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { UserRole, ViewState, ReportData, ULPName, ULPData, LoginSession } from './types';
import { InputForm } from './components/InputForm';
import { Dashboard } from './components/Dashboard';
import { DataTable } from './components/DataTable';
import { AdminSettings } from './components/AdminSettings';
import { AdminRekap } from './components/AdminRekap';
import { LoginConfig } from './components/LoginConfig';
import { DATA_ULP as INITIAL_DATA_ULP, APP_VERSION } from './constants';
import { api } from './services/api';

const LOGO_URL = "https://plnes.co.id/_next/image?url=https%3A%2F%2Fcms.plnes.co.id%2Fuploads%2FLogo_HP_New_Temporary_09a9c5a521.png&w=750&q=75"; 
const APP_LOGO = "https://raw.githubusercontent.com/plnesbukittinggi-ai/yandal_patrol/main/ChatGPT%20Image%2018%20Des%202025%2C%2011.11.52.png";

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [view, setView] = useState<ViewState>('LOGIN');
  const [isLoading, setIsLoading] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [isDemoMode, setIsDemoMode] = useState(false);

  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [adminPassword, setAdminPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  const [session, setSession] = useState<LoginSession>({ ulp: null, petugas1: null, petugas2: null });
  const [reports, setReports] = useState<ReportData[]>([]);
  const [masterData, setMasterData] = useState<Record<string, ULPData>>(INITIAL_DATA_ULP);
  const [editingReport, setEditingReport] = useState<ReportData | null>(null);

  // Filter states
  const [tableStartDate, setTableStartDate] = useState('');
  const [tableEndDate, setTableEndDate] = useState('');
  const [tableUlpFilter, setTableUlpFilter] = useState<ULPName | ''>('');

  const pendingUpdatesRef = useRef<Map<string, string>>(new Map());

  useEffect(() => {
    // Cek apakah mode demo aktif di browser ini
    const savedDemo = localStorage.getItem('yandal_demo_mode');
    if (savedDemo === 'true') {
      setIsDemoMode(true);
      const savedReports = localStorage.getItem('yandal_local_reports');
      if (savedReports) setReports(JSON.parse(savedReports));
    }
    fetchData(true);
  }, []);

  const fetchData = async (showLoading = true) => {
    if (isDemoMode) return;
    if (showLoading) setIsLoading(true);

    try {
      const data = await api.getAllData();
      if (data && data.reports) {
        setReports(prevReports => {
          const reportMap = new Map<string, ReportData>();
          // Gabungkan data server dengan data lokal yang masih pending
          data.reports.forEach((r: ReportData) => reportMap.set(r.id, r));
          pendingUpdatesRef.current.forEach((ts, id) => {
            const local = prevReports.find(r => r.id === id);
            if (local) reportMap.set(id, local);
          });
          return Array.from(reportMap.values());
        });
        if (data.masterData) setMasterData(data.masterData);
      }
    } catch (error) {
      console.error("Gagal mengambil data:", error);
    } finally {
      if (showLoading) setIsLoading(false);
    }
  };

  const handleSaveReport = async (data: ReportData, isEditMode: boolean) => {
    setIsSyncing(true);

    // Optimistic Update: Munculkan di tabel segera
    pendingUpdatesRef.current.set(data.id, data.timestamp);
    setReports(prev => [data, ...prev.filter(r => r.id !== data.id)]);

    try {
      if (isDemoMode) {
        const currentReports = [data, ...reports.filter(r => r.id !== data.id)];
        localStorage.setItem('yandal_local_reports', JSON.stringify(currentReports));
      } else {
        await api.saveReport(data, isEditMode);
        // Beri waktu 10 detik untuk GAS memproses gambar sebelum refresh
        setTimeout(() => {
          fetchData(false);
          pendingUpdatesRef.current.delete(data.id);
          setIsSyncing(false);
        }, 10000);
      }
      setEditingReport(null);
      setView('TABLE');
    } catch (e) {
      console.error("Gagal simpan:", e);
      alert("Koneksi terganggu. Data tersimpan secara lokal di browser ini, tapi mungkin belum masuk ke Spreadsheet.");
      setIsSyncing(false);
    }
  };

  const handleInitialRoleSelect = (selectedRole: UserRole) => {
    setRole(selectedRole);
    if (selectedRole === UserRole.ADMIN) return; 
    setView('CONFIG');
  };

  const handleAdminLoginSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminPassword === 'Adminbkt') {
      setRole(UserRole.ADMIN);
      setView('DASHBOARD');
      setShowAdminLogin(false);
    } else {
      setLoginError('Password salah!');
    }
  };

  const handleConfigConfirm = (conf: LoginSession) => {
    setSession(conf);
    setView(role === UserRole.GUEST ? 'TABLE' : 'INPUT');
  };

  const handleLogout = () => {
    setRole(null);
    setView('LOGIN');
    setShowAdminLogin(false);
    setSession({ ulp: null, petugas1: null, petugas2: null });
  };

  const filteredReportsForTable = useMemo(() => {
    return reports
      .filter(r => {
        const sessionMatch = !session.ulp || r.ulp === session.ulp;
        const adminUlpMatch = role !== UserRole.ADMIN || !tableUlpFilter || r.ulp === tableUlpFilter;
        const reportDate = new Date(r.timestamp).toISOString().split('T')[0];
        const startMatch = !tableStartDate || reportDate >= tableStartDate;
        const endMatch = !tableEndDate || reportDate <= tableEndDate;
        return sessionMatch && adminUlpMatch && startMatch && endMatch;
      })
      .sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
  }, [reports, session.ulp, role, tableUlpFilter, tableStartDate, tableEndDate]);

  if (isLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50 gap-4">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary"></div>
        <p className="text-slate-700 font-bold uppercase text-[10px] tracking-widest">Sinkronisasi Database...</p>
      </div>
    );
  }

  if (view === 'LOGIN') {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
        <div className="bg-white p-8 rounded-2xl shadow-xl max-w-md w-full border border-slate-200">
          <div className="text-center mb-8">
            <img src={LOGO_URL} alt="Logo PLN" className="h-16 mx-auto mb-4 object-contain" />
            <h1 className="text-lg font-extrabold text-slate-800 mb-6 uppercase">Unit Layanan Bukittinggi</h1>
            <img src={APP_LOGO} alt="Logo App" className="h-48 mx-auto object-contain mb-6" />
            <h2 className="text-2xl font-bold text-primary">Monitoring Yandal Patrol</h2>
            {isDemoMode && <div className="mt-2 bg-amber-100 text-amber-700 text-[9px] font-black py-1 rounded-full uppercase tracking-widest">Aplikasi dalam Mode Demo</div>}
          </div>
          <div className="space-y-4">
            <button onClick={() => handleInitialRoleSelect(UserRole.USER)} className="w-full bg-primary hover:bg-cyan-800 text-white font-black py-4 rounded-2xl transition-all shadow-lg uppercase text-xs tracking-widest">
              Login Petugas
            </button>
            {!showAdminLogin ? (
              <button onClick={() => setShowAdminLogin(true)} className="w-full bg-slate-800 hover:bg-slate-900 text-white font-black py-4 rounded-2xl transition-all uppercase text-xs tracking-widest">
                Login Admin
              </button>
            ) : (
              <form onSubmit={handleAdminLoginSubmit} className="bg-slate-50 p-5 rounded-2xl border border-slate-200 animate-fade-in">
                <input 
                  type="password" 
                  autoFocus
                  className="w-full px-4 py-3 border border-slate-300 rounded-xl mb-3 outline-none focus:ring-2 focus:ring-primary/20"
                  value={adminPassword}
                  onChange={(e) => setAdminPassword(e.target.value)}
                  placeholder="Password..."
                />
                {loginError && <p className="text-[10px] text-red-500 mb-3 font-bold uppercase">{loginError}</p>}
                <div className="flex gap-2">
                  <button type="button" onClick={() => setShowAdminLogin(false)} className="flex-1 py-3 text-xs font-bold text-slate-600 bg-white border border-slate-300 rounded-xl">Batal</button>
                  <button type="submit" className="flex-1 py-3 text-xs font-black bg-slate-800 text-white rounded-xl">Masuk</button>
                </div>
              </form>
            )}
          </div>
        </div>
      </div>
    );
  }

  if (view === 'CONFIG' && role) {
    return (
      <LoginConfig 
        role={role} 
        masterData={masterData} 
        appLogo={APP_LOGO}
        onBack={() => { setView('LOGIN'); setRole(null); }}
        onConfirm={handleConfigConfirm}
      />
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {isSyncing && (
        <div className="fixed top-4 right-4 z-50 bg-white shadow-xl rounded-full px-5 py-2.5 flex items-center gap-2 border border-slate-200 animate-fade-in">
          <div className="animate-spin h-4 w-4 border-2 border-primary border-t-transparent rounded-full"></div>
          <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest">Menyimpan ke Spreadsheet...</span>
        </div>
      )}

      <header className="bg-white shadow-sm z-20 sticky top-0">
        <div className="max-w-7xl mx-auto px-4 h-16 flex justify-between items-center">
            <div className="flex items-center gap-4">
               <button onClick={() => setView('LOGIN')} className="p-2 hover:bg-slate-100 rounded-full transition-all text-slate-600">
                 <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
                 </svg>
               </button>
               <img src={APP_LOGO} alt="App" className="h-8" />
               <span className="font-black text-sm text-slate-800 tracking-tight uppercase">Yandal Patrol</span>
            </div>
            <button onClick={handleLogout} className="text-[10px] text-red-600 font-black uppercase tracking-widest">Logout</button>
        </div>

        <div className="max-w-7xl mx-auto px-4">
          <nav className="-mb-px flex space-x-8 overflow-x-auto no-scrollbar">
            {role === UserRole.ADMIN && (
              <>
                <button onClick={() => setView('DASHBOARD')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'DASHBOARD' ? 'border-primary text-primary' : 'border-transparent text-slate-400'}`}>Dashboard</button>
                <button onClick={() => setView('REKAP')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'REKAP' ? 'border-primary text-primary' : 'border-transparent text-slate-400'}`}>Rekap</button>
                <button onClick={() => setView('SETTINGS')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'SETTINGS' ? 'border-primary text-primary' : 'border-transparent text-slate-400'}`}>Admin</button>
              </>
            )}
            {role === UserRole.USER && (
              <button onClick={() => setView('INPUT')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'INPUT' ? 'border-primary text-primary' : 'border-transparent text-slate-400'}`}>Input</button>
            )}
