    if (isDemoMode) return;
    if (showLoading) setIsLoading(true);

    try {
      const data = await api.getAllData();
      if (data && data.reports) {
        setReports(prevReports => {
          const reportMap = new Map<string, ReportData>();

          // 1. Masukkan data dari server
          data.reports.forEach((r: ReportData) => reportMap.set(r.id, r));

          // 2. Pertahankan data lokal yang masih dalam status "Syncing" 
          // (Data ini akan tetap tampil meskipun belum ada di Spreadsheet)
          prevReports.forEach(r => {
            if (pendingSyncIds.has(r.id) && !reportMap.has(r.id)) {
              reportMap.set(r.id, r);
            }
          });

          const newReports = Array.from(reportMap.values());
          localStorage.setItem('yandal_local_cache', JSON.stringify(newReports));
          return newReports;
        });

        // Bersihkan pending ID yang sudah muncul di server
        setPendingSyncIds(prev => {
          const next = new Set(prev);
          data.reports.forEach((r: ReportData) => next.delete(r.id));
          return next;
        });

        if (data.masterData) setMasterData(data.masterData);
      }
    } catch (error) {
      console.error("Gagal mengambil data:", error);
    } finally {
      if (showLoading) setIsLoading(false);
    }
  };

  const handleSaveReport = async (data: ReportData, isEditMode: boolean) => {
    setIsSyncing(true);

    // Tandai ID ini sebagai pending sinkronisasi
    setPendingSyncIds(prev => new Set(prev).add(data.id));

    // Masukkan ke state utama segera (Optimistic)
    setReports(prev => {
      const updated = [data, ...prev.filter(r => r.id !== data.id)];
