Masalah utama Anda adalah data yang dikirim tidak berhasil diproses oleh **Google Apps Script (GAS)**, sehingga saat aplikasi melakukan pembaruan otomatis (refresh), data tersebut tidak ditemukan di server dan akhirnya "hilang" dari tampilan aplikasi.

Berikut adalah perbaikan total pada sisi aplikasi (Frontend) dan saya sertakan **Kode Google Apps Script** terbaru yang wajib Anda salin ke editor Google Sheets Anda agar sinkronisasi berjalan 100%.

### 1. Spesifikasi Perbaikan
*   **`api.ts`**: Mengoptimalkan pengiriman data agar GAS dapat membaca file gambar (Base64) yang besar tanpa error.
*   **`App.tsx`**: Memperbaiki logika "Pending Data". Sekarang, data yang baru diinput akan disimpan secara permanen di memori HP/Browser (`localStorage`) sampai server memberikan konfirmasi bahwa data tersebut sudah masuk ke Spreadsheet.
*   **`DataTable.tsx`**: Menambahkan label visual **"⏳ PROSES SYNC"** pada baris data yang belum masuk ke Spreadsheet agar petugas tahu data mereka sedang diantrekan.

### 2. Kode Google Apps Script (WAJIB DISALIN)
Buka Google Sheets -> Extensions -> Apps Script. Hapus semua kode lama dan tempel kode ini:

```javascript
/** 
 * KODE GOOGLE APPS SCRIPT (GAS) 
 * Pastikan Deploy -> New Deployment -> Web App -> Execute as: Me -> Who has access: Anyone
 */

const SS = SpreadsheetApp.getActiveSpreadsheet();
const SHEET_REPORTS = SS.getSheetByName("REPORTS") || SS.insertSheet("REPORTS");
const SHEET_MASTER = SS.getSheetByName("MASTER_DATA") || SS.insertSheet("MASTER_DATA");

function doPost(e) {
  try {
    const body = e.postData ? JSON.parse(e.postData.contents) : null;
    const action = e.parameter.action || (body ? body.action : "");
    const data = body ? body.data : null;

    if (action === "saveReport" || action === "updateReport") {
      saveToSheet(data, action === "updateReport");
      return ContentService.createTextOutput("Success").setMimeType(ContentService.MimeType.TEXT);
    }

    if (action === "updateMaster") {
      SHEET_MASTER.getRange(1, 1).setValue(JSON.stringify(data));
      return ContentService.createTextOutput("Master Updated").setMimeType(ContentService.MimeType.TEXT);
    }
  } catch (err) {
    return ContentService.createTextOutput("Error: " + err.message).setMimeType(ContentService.MimeType.TEXT);
  }
}

function doGet(e) {
  const action = e.parameter.action;
  if (action === "getAll") {
    const reports = SHEET_REPORTS.getDataRange().getValues();
    const headers = reports.shift();
    const jsonData = reports.map(row => {
      let obj = {};
      headers.forEach((h, i) => {
        if (h === "photos") obj[h] = JSON.parse(row[i] || '{"sebelum":[], "sesudah":[]}');
        else obj[h] = row[i];
      });
      return obj;
    });

    let master = SHEET_MASTER.getRange(1, 1).getValue();
    return ContentService.createTextOutput(JSON.stringify({
      reports: jsonData,
      masterData: master ? JSON.parse(master) : null
    })).setMimeType(ContentService.MimeType.JSON);
  }
}

function saveToSheet(data, isUpdate) {
  const headers = ["id", "timestamp", "bulan", "noPenugasan", "ulp", "petugas1", "petugas2", "penyulang", "keypoint", "titikStart", "titikFinish", "photos"];

  // Pastikan header ada
  if (SHEET_REPORTS.getLastRow() === 0) SHEET_REPORTS.appendRow(headers);

  const rowData = headers.map(h => h === "photos" ? JSON.stringify(data[h]) : data[h]);

  if (isUpdate) {
    const ids = SHEET_REPORTS.getRange(1, 1, SHEET_REPORTS.getLastRow()).getValues().flat();
    const rowIndex = ids.indexOf(data.id);
    if (rowIndex !== -1) {
      SHEET_REPORTS.getRange(rowIndex + 1, 1, 1, headers.length).setValues([rowData]);
      return;
    }
  }
  SHEET_REPORTS.appendRow(rowData);
}
