import { ReportData, ULPData } from '../types';

/**
 * URL Google Apps Script
 * PENTING: Gunakan URL dari 'New Deployment' terbaru Anda.
 */
const GOOGLE_SCRIPT_URL: string = 'https://script.google.com/macros/s/AKfycbyIfxJ6rNd1p1jM232w9-JxYTU49IZzuTC3qdndnA5DR9TMWcqBSWruVvhATYE6ZkML/exec'; 

export const api = {
  getAllData: async () => {
    try {
      const response = await fetch(`${GOOGLE_SCRIPT_URL}?action=getAll`, {
        method: 'GET',
        cache: 'no-store'
      });

      if (!response.ok) throw new Error(`HTTP Error: ${response.status}`);
      const text = await response.text();
      return JSON.parse(text);
    } catch (error: any) {
      console.error("API Error (GetAll):", error);
      throw error;
    }
  },

  saveReport: async (report: ReportData, isEdit: boolean = false) => {
    try {
      const action = isEdit ? 'updateReport' : 'saveReport';
      const payload = JSON.stringify({
        action: action,
        data: report
      });

      // Menggunakan mode no-cors untuk menghindari blokir CORS saat pengiriman data Base64
      // Parameter action ditaruh di URL agar GAS mudah mengenalinya
      await fetch(`${GOOGLE_SCRIPT_URL}?action=${action}`, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 
          'Content-Type': 'text/plain;charset=utf-8' 
        },
        body: payload
      });

      return true;
    } catch (error) {
      console.error("Gagal mengirim ke GAS:", error);
      throw error;
    }
  },

  updateMasterData: async (masterData: Record<string, ULPData>) => {
    try {
      await fetch(`${GOOGLE_SCRIPT_URL}?action=updateMaster`, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'text/plain' },
        body: JSON.stringify({ action: 'updateMaster', data: masterData })
      });
      return true;
    } catch (error) {
      return true;
    }
  }
};

