               <form onSubmit={handleAdminLoginSubmit} className="space-y-3">
                 <input name="password" type="password" placeholder="Password Admin" className="w-full px-4 py-3 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-primary/20 text-center font-bold" />
                 <button type="submit" className="w-full bg-slate-800 hover:bg-slate-900 text-white font-black py-3 rounded-xl transition-all uppercase text-xs tracking-widest">Masuk Admin</button>
