import React, { useState, useEffect, useMemo } from 'react';
import { UserRole, ViewState, ReportData, ULPName, ULPData, LoginSession } from './types';
import { InputForm } from './components/InputForm';
import { Dashboard } from './components/Dashboard';
import { DataTable } from './components/DataTable';
import { AdminSettings } from './components/AdminSettings';
import { AdminRekap } from './components/AdminRekap';
import { LoginConfig } from './components/LoginConfig';
import { DATA_ULP as INITIAL_DATA_ULP } from './constants';
import { api } from './services/api';

const LOGO_URL = "https://plnes.co.id/_next/image?url=https%3A%2F%2Fcms.plnes.co.id%2Fuploads%2FLogo_HP_New_Temporary_09a9c5a521.png&w=750&q=75"; 
const APP_LOGO = "https://raw.githubusercontent.com/plnesbukittinggi-ai/yandal_patrol/main/ChatGPT%20Image%2018%20Des%202025%2C%2011.11.52.png";

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [view, setView] = useState<ViewState>('LOGIN');
  const [isLoading, setIsLoading] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);

  const [session, setSession] = useState<LoginSession>({ ulp: null, petugas1: null, petugas2: null });
  const [reports, setReports] = useState<ReportData[]>([]);
  const [masterData, setMasterData] = useState<Record<string, ULPData>>(INITIAL_DATA_ULP);
  const [editingReport, setEditingReport] = useState<ReportData | null>(null);

  const [tableStartDate, setTableStartDate] = useState('');
  const [tableEndDate, setTableEndDate] = useState('');
  const [tableUlpFilter, setTableUlpFilter] = useState<ULPName | ''>('');

  const [pendingIds, setPendingIds] = useState<Set<string>>(new Set());

  useEffect(() => {
    const cached = localStorage.getItem('yandal_reports_cache');
    if (cached) setReports(JSON.parse(cached));

    const pending = localStorage.getItem('yandal_pending_ids');
    if (pending) setPendingIds(new Set(JSON.parse(pending)));

    fetchData(true);
  }, []);

  useEffect(() => {
    localStorage.setItem('yandal_pending_ids', JSON.stringify(Array.from(pendingIds)));
  }, [pendingIds]);

  const fetchData = async (showLoading = true) => {
    if (showLoading) setIsLoading(true);
    try {
      const result = await api.getAllData();
      if (result && result.reports) {
        setReports(prev => {
          const reportMap = new Map<string, ReportData>();

          result.reports.forEach((r: ReportData) => reportMap.set(r.id, r));

          prev.forEach(r => {
            if (pendingIds.has(r.id) && !reportMap.has(r.id)) {
              reportMap.set(r.id, r);
            }
          });

          const combined = Array.from(reportMap.values());
          localStorage.setItem('yandal_reports_cache', JSON.stringify(combined));
          return combined;
        });

        setPendingIds(prevPending => {
          const next = new Set(prevPending);
          result.reports.forEach((r: ReportData) => next.delete(r.id));
          return next;
        });

        if (result.masterData) setMasterData(result.masterData);
      }
    } catch (e) {
      console.error("Fetch data failed:", e);
    } finally {
      if (showLoading) setIsLoading(false);
    }
  };

  const handleSaveReport = async (data: ReportData, isEdit: boolean) => {
    setIsSyncing(true);
    setPendingIds(prev => new Set(prev).add(data.id));
    setReports(prev => [data, ...prev.filter(r => r.id !== data.id)]);

    try {
      await api.saveReport(data, isEdit);
      setTimeout(() => fetchData(false).then(() => setIsSyncing(false)), 5000);
      setEditingReport(null);
      setView('TABLE');
    } catch (e) {
      alert("Koneksi bermasalah. Data tetap tersimpan di aplikasi ini dan akan dicoba sinkron ulang nanti.");
      setIsSyncing(false);
    }
  };

  const handleAdminLoginSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const pass = (e.currentTarget.elements.namedItem('password') as HTMLInputElement).value;
    if (pass === 'Adminbkt') {
      setRole(UserRole.ADMIN);
      setView('DASHBOARD');
    } else {
      alert('Password Salah!');
    }
  };

  const handleInitialRoleSelect = (selectedRole: UserRole) => {
    setRole(selectedRole);
    if (selectedRole === UserRole.ADMIN) return; 
    setView('CONFIG');
  };

  const handleConfigConfirm = (conf: LoginSession) => {
    setSession(conf);
    setView(role === UserRole.GUEST ? 'TABLE' : 'INPUT');
  };

  const handleLogout = () => {
    setRole(null);
    setView('LOGIN');
    setSession({ ulp: null, petugas1: null, petugas2: null });
  };

  const filteredReportsForTable = useMemo(() => {
    return reports
      .filter(r => {
        const sessionMatch = !session.ulp || r.ulp === session.ulp;
        const adminUlpMatch = role !== UserRole.ADMIN || !tableUlpFilter || r.ulp === tableUlpFilter;

        // Safety check for date parsing
        const dateObj = new Date(r.timestamp);
        const isValidDate = !isNaN(dateObj.getTime());
        const reportDate = isValidDate ? dateObj.toISOString().split('T')[0] : '';

        const startMatch = !tableStartDate || (reportDate && reportDate >= tableStartDate);
        const endMatch = !tableEndDate || (reportDate && reportDate <= tableEndDate);

        return sessionMatch && adminUlpMatch && startMatch && endMatch;
      })
      .sort((a, b) => {
        const dateA = new Date(a.timestamp).getTime();
        const dateB = new Date(b.timestamp).getTime();
        return (isNaN(dateB) ? 0 : dateB) - (isNaN(dateA) ? 0 : dateA);
      });
  }, [reports, session.ulp, role, tableUlpFilter, tableStartDate, tableEndDate]);

  if (isLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50 gap-4">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary"></div>
        <p className="text-slate-700 font-bold uppercase text-[10px] tracking-widest">Sinkronisasi Database...</p>
      </div>
    );
  }

  if (view === 'LOGIN') {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
        <div className="bg-white p-8 rounded-2xl shadow-xl max-w-md w-full border border-slate-200">
          <div className="text-center mb-8">
            <img src={LOGO_URL} alt="Logo PLN" className="h-16 mx-auto mb-4 object-contain" />
            <h1 className="text-lg font-extrabold text-slate-800 mb-6 uppercase tracking-tight">Unit Layanan Bukittinggi</h1>
            <img src={APP_LOGO} alt="Logo App" className="h-48 mx-auto object-contain mb-6" />
            <h2 className="text-2xl font-bold text-primary">Monitoring Yandal Patrol</h2>
          </div>
          <div className="space-y-4">
            <button onClick={() => handleInitialRoleSelect(UserRole.USER)} className="w-full bg-primary hover:bg-cyan-800 text-white font-black py-4 rounded-2xl transition-all shadow-lg uppercase text-xs tracking-widest">
              Login Petugas
            </button>
            <div className="pt-4 border-t border-slate-100">
               <form onSubmit={handleAdminLoginSubmit} className="space-y-3">
                 <input name="password" type="password" placeholder="Password Admin" className="w-full px-4 py-3 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-primary/20 text-center font-bold" />
                 <button type="submit" className="w-full bg-slate-800 hover:bg-slate-900 text-white font-black py-3 rounded-xl transition-all uppercase text-xs tracking-widest">Masuk Admin</button>
               </form>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {(isSyncing || pendingIds.size > 0) && (
        <div className="fixed top-4 right-4 z-50 bg-white shadow-xl rounded-full px-5 py-2.5 flex items-center gap-2 border border-primary animate-fade-in">
          <div className="animate-spin h-3 w-3 border-2 border-primary border-t-transparent rounded-full"></div>
          <span className="text-[9px] font-black text-primary uppercase tracking-widest">Sinkronisasi Spreadsheet...</span>
        </div>
      )}

      <header className="bg-white shadow-sm z-20 sticky top-0">
        <div className="max-w-7xl mx-auto px-4 h-16 flex justify-between items-center">
            <div className="flex items-center gap-4">
               <button onClick={() => setView('LOGIN')} className="p-2 hover:bg-slate-100 rounded-full text-slate-600">
                 <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
                 </svg>
               </button>
               <img src={APP_LOGO} alt="App" className="h-8" />
               <span className="font-black text-sm text-slate-800 uppercase tracking-tight">Yandal Patrol</span>
            </div>
            <button onClick={handleLogout} className="text-[10px] text-red-600 font-black uppercase tracking-widest">Logout</button>
        </div>

        <div className="max-w-7xl mx-auto px-4">
          <nav className="-mb-px flex space-x-8 overflow-x-auto no-scrollbar">
            {role === UserRole.ADMIN && (
              <>
                <button onClick={() => setView('DASHBOARD')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'DASHBOARD' ? 'border-primary text-primary' : 'border-transparent text-slate-400'}`}>Dashboard</button>
                <button onClick={() => setView('REKAP')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'REKAP' ? 'border-primary text-primary' : 'border-transparent text-slate-400'}`}>Rekap</button>
                <button onClick={() => setView('SETTINGS')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'SETTINGS' ? 'border-primary text-primary' : 'border-transparent text-slate-400'}`}>Admin</button>
              </>
            )}
            {role === UserRole.USER && (
              <button onClick={() => setView('INPUT')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'INPUT' ? 'border-primary text-primary' : 'border-transparent text-slate-400'}`}>Input</button>
            )}
            <button onClick={() => setView('TABLE')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'TABLE' ? 'border-primary text-primary' : 'border-transparent text-slate-400'}`}>Data</button>
          </nav>
        </div>
      </header>

      <main className="flex-1 max-w-7xl w-full mx-auto px-4 py-8">
        {view === 'CONFIG' && <LoginConfig role={role!} masterData={masterData} onConfirm={handleConfigConfirm} onBack={() => setView('LOGIN')} appLogo={APP_LOGO} />}
        {view === 'DASHBOARD' && <Dashboard reports={filteredReportsForTable} />}
        {view === 'REKAP' && <AdminRekap reports={reports} masterData={masterData} />}
        {view === 'SETTINGS' && <AdminSettings masterData={masterData} onAddPetugas={()=>{}} onDeletePetugas={()=>{}} onAddPenyulang={()=>{}} onDeletePenyulang={()=>{}} />}
        {view === 'INPUT' && (
          <InputForm 
            onSubmit={handleSaveReport}
            onCancel={() => setView('TABLE')}
            masterData={masterData}
            sessionData={session}
            editData={editingReport}
          />
        )}
        {view === 'TABLE' && (
          <div className="space-y-6">
             <div className="bg-white p-5 rounded-2xl shadow-sm border border-slate-200 flex flex-wrap gap-4 items-end">
                <div className="flex-1 min-w-[200px]">
                  <label className="block text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1.5 ml-1">Rentang Tanggal</label>
                  <div className="flex gap-2">
                    <input type="date" className="flex-1 px-3 py-2 border border-slate-200 rounded-xl text-xs font-bold" value={tableStartDate} onChange={(e) => setTableStartDate(e.target.value)} />
