import React, { useState } from 'react';
import { ReportData } from '../types';

interface DataTableProps {
  reports: ReportData[];
  pendingIds?: Set<string>;
  onEdit?: (report: ReportData) => void;
}

export const DataTable: React.FC<DataTableProps> = ({ reports, pendingIds, onEdit }) => {
  const [previewImage, setPreviewImage] = useState<{ url: string } | null>(null);

  if (reports.length === 0) {
    return (
      <div className="bg-white p-12 text-center rounded-[2rem] shadow-sm border border-slate-200">
        <p className="text-slate-500 font-black uppercase tracking-widest text-sm">
          Belum ada data laporan
        </p>
      </div>
    );
  }

  const formatImageUrl = (url: any): string => {
    if (!url || typeof url !== 'string') return '';
    let clean = url.trim();
    if (clean.startsWith('data:image')) {
      const parts = clean.split(',');
      if (parts.length > 1) {
        return parts[0] + ',' + parts[1].replace(/\s/g, '+');
      }
      return clean;
    }
    return clean;
  };

  const isValidImage = (str: any): boolean => {
    if (!str || typeof str !== 'string') return false;
    const s = str.trim();
    return s.startsWith('data:image') || s.startsWith('http');
  };

  const PhotoCard = ({ url, label, type }: { url: string; label: string; type: 'sebelum' | 'sesudah' }) => {
    const finalUrl = formatImageUrl(url);
    if (!finalUrl) return null;
    return (
      <div className="group relative flex flex-col items-center gap-0.5 cursor-pointer" onClick={() => setPreviewImage({ url: finalUrl })}>
        <div className={`w-10 h-10 rounded-lg border-2 overflow-hidden shadow-sm transition-transform group-hover:scale-110 ${type === 'sebelum' ? 'border-amber-300' : 'border-cyan-300'}`}>
          <img src={finalUrl} alt={label} className="w-full h-full object-cover" loading="lazy" />
        </div>
      </div>
    );
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
      <div className="overflow-x-auto">
        <table className="w-full text-sm text-left text-slate-600 min-w-[900px]">
          <thead className="text-[10px] text-slate-700 uppercase bg-slate-50 border-b border-slate-200">
            <tr>
              <th className="px-6 py-4 font-black tracking-widest">Waktu & Status</th>
              <th className="px-6 py-4 font-black tracking-widest">No. Penugasan</th>
              <th className="px-6 py-4 font-black tracking-widest">Unit / Petugas</th>
              <th className="px-6 py-4 font-black tracking-widest">Lokasi & Keypoint</th>
              <th className="px-6 py-4 font-black tracking-widest text-center">Dokumentasi</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {reports.map((report) => {
              const isPending = pendingIds?.has(report.id);
              const validSebelum = report.photos.sebelum.filter(isValidImage);
              const validSesudah = report.photos.sesudah.filter(isValidImage);

              // Safety date check
              const dateObj = new Date(report.timestamp);
              const isValidDate = !isNaN(dateObj.getTime());
              const dateStr = isValidDate ? dateObj.toLocaleDateString('id-ID') : '-';
              const timeStr = isValidDate ? dateObj.toLocaleTimeString('id-ID') : '-';

              return (
                <tr key={report.id} className={`hover:bg-slate-50 transition-colors ${isPending ? 'bg-blue-50/30' : ''}`}>
                  <td className="px-6 py-4 whitespace-nowrap align-top">
                    <div className="flex flex-col gap-1">
                      <div className="font-bold text-slate-900 text-xs">{dateStr}</div>
                      <div className="text-[10px] text-slate-400 font-bold">{timeStr} WIB</div>
                      {isPending ? (
                        <div className="mt-1 inline-flex items-center px-2 py-0.5 rounded text-[8px] font-black bg-blue-100 text-blue-600 uppercase tracking-widest animate-pulse">
                          ⏳ Proses Sync
                        </div>
                      ) : (
                        <div className="mt-1 inline-flex items-center px-2 py-0.5 rounded text-[8px] font-black bg-green-100 text-green-600 uppercase tracking-widest">
                          ✓ Tersimpan
                        </div>
                      )}
                    </div>
                  </td>
                  <td className="px-6 py-4 font-mono text-slate-700 align-top font-bold text-xs">
                      {report.noPenugasan}
                  </td>
                  <td className="px-6 py-4 align-top">
                    <div className="font-black text-primary text-xs uppercase">{report.ulp}</div>
                    <div className="text-[9px] text-slate-500 mt-1 uppercase font-bold">Penyulang: {report.penyulang}</div>
                    <div className="mt-2 flex flex-col gap-0.5">
                      <div className="text-[10px] font-bold text-slate-700 uppercase">1. {report.petugas1}</div>
                      <div className="text-[10px] font-bold text-slate-700 uppercase">2. {report.petugas2}</div>
                    </div>
                  </td>
                  <td className="px-6 py-4 align-top">
                     <div className="text-[10px] font-black text-slate-800 mb-1 uppercase tracking-tight">{report.keypoint}</div>
                     <div className="text-[9px] text-slate-400 font-bold flex items-center gap-1 uppercase">
                       <span className="w-1.5 h-1.5 rounded-full bg-green-400"></span> Start: {report.titikStart}
                     </div>
                     <div className="text-[9px] text-slate-400 font-bold flex items-center gap-1 uppercase mt-0.5">
                       <span className="w-1.5 h-1.5 rounded-full bg-red-400"></span> Finish: {report.titikFinish}
                     </div>
                  </td>
                  <td className="px-4 py-4 align-top">
                    <div className="flex flex-col gap-2">
                       <div className="flex gap-1 overflow-x-auto no-scrollbar max-w-[150px]">
                         {validSebelum.map((u, i) => <PhotoCard key={i} url={u!} label="SB" type="sebelum" />)}
                       </div>
                       <div className="flex gap-1 overflow-x-auto no-scrollbar max-w-[150px]">
                         {validSesudah.map((u, i) => <PhotoCard key={i} url={u!} label="SS" type="sesudah" />)}
                       </div>
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {previewImage && (
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-sm z-[100] flex flex-col items-center justify-center p-4" onClick={() => setPreviewImage(null)}>
          <div className="relative max-w-lg w-full">
            <img src={previewImage.url} alt="Preview" className="w-full h-auto rounded-2xl shadow-2xl border-4 border-white/10" />
            <button className="absolute -top-4 -right-4 bg-red-500 text-white w-10 h-10 rounded-full font-bold">✕</button>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { ReportData, ULPData, ULPName } from '../types';

interface AdminRekapProps {
  reports: ReportData[];
  masterData: Record<string, ULPData>;
}

export const AdminRekap: React.FC<AdminRekapProps> = ({ reports, masterData }) => {
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [filterUlp, setFilterUlp] = useState<ULPName | ''>('');

  const rekapData = useMemo(() => {
    const filteredReports = reports.filter(report => {
      const dateObj = new Date(report.timestamp);
      if (isNaN(dateObj.getTime())) return false;
      const reportDate = dateObj.toISOString().split('T')[0];
      const startMatch = !startDate || reportDate >= startDate;
      const endMatch = !endDate || reportDate <= endDate;
      return startMatch && endMatch;
    });

    const rawResult: any[] = [];

    Object.values(masterData).forEach((ulpData: ULPData) => {
      if (filterUlp && ulpData.name !== filterUlp) return;

      ulpData.petugas.forEach(namaPetugas => {
        const totalRealisasi = filteredReports.filter(r => 
          r.ulp === ulpData.name && 
          (r.petugas1 === namaPetugas || r.petugas2 === namaPetugas)
        ).length;

        let bulanLabel = "Semua";
        try {
          if (startDate && endDate) {
            const sDate = new Date(startDate);
            const eDate = new Date(endDate);
            if (!isNaN(sDate.getTime()) && !isNaN(eDate.getTime())) {
              const s = sDate.toLocaleString('id-ID', { month: 'short', year: '2-digit' });
              const e = eDate.toLocaleString('id-ID', { month: 'short', year: '2-digit' });
              bulanLabel = s === e ? s : `${s} - ${e}`;
            }
          } else if (startDate) {
            const sDate = new Date(startDate);
            if (!isNaN(sDate.getTime())) {
              bulanLabel = `Sejak ${sDate.toLocaleString('id-ID', { month: 'short' })}`;
            }
          }
        } catch (e) {
          bulanLabel = "Filter Aktif";
        }

        rawResult.push({
          bulan: bulanLabel,
          nama: namaPetugas,
          ulp: ulpData.name,
          total: totalRealisasi
        });
      });
    });

    rawResult.sort((a, b) => {
      if (b.total !== a.total) {
        return b.total - a.total;
      }
      return a.nama.localeCompare(b.nama);
    });

    return rawResult.map((item, index) => ({
      ...item,
      no: index + 1
    }));
  }, [reports, masterData, startDate, endDate, filterUlp]);

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-4">
          <h2 className="text-xl font-bold text-slate-800">Rekap Realisasi Petugas</h2>
          <div className="px-3 py-1 bg-blue-50 text-blue-700 rounded-lg text-xs font-bold border border-blue-100">
            Urutan: Realisasi Terbanyak
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-6 p-4 bg-slate-50 rounded-lg border border-slate-100">
          <div>
            <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Dari Tanggal</label>
            <input 
              type="date" 
              className="w-full px-3 py-2 border border-slate-300 rounded-md text-sm focus:ring-2 focus:ring-primary focus:border-transparent"
              value={startDate}
              onChange={(e) => setStartDate(e.target.value)}
            />
          </div>
          <div>
            <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Sampai Tanggal</label>
            <input 
              type="date" 
              className="w-full px-3 py-2 border border-slate-300 rounded-md text-sm focus:ring-2 focus:ring-primary focus:border-transparent"
              value={endDate}
              onChange={(e) => setEndDate(e.target.value)}
            />
          </div>
          <div>
            <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Filter ULP</label>
            <select 
              className="w-full px-3 py-2 border border-slate-300 rounded-md text-sm bg-white focus:ring-2 focus:ring-primary focus:border-transparent"
              value={filterUlp}
              onChange={(e) => setFilterUlp(e.target.value as ULPName)}
            >
              <option value="">Semua ULP</option>
              {Object.values(ULPName).map(u => <option key={u} value={u}>{u}</option>)}
            </select>
          </div>
          <div className="flex items-end">
            <button 
              onClick={() => { setStartDate(''); setEndDate(''); setFilterUlp(''); }}
              className="w-full py-2 px-4 bg-slate-200 hover:bg-slate-300 text-slate-700 font-semibold rounded-md text-sm transition-colors"
            >
              Reset Filter
            </button>
          </div>
        </div>

        <div className="overflow-x-auto border border-slate-200 rounded-lg">
          <table className="w-full text-sm text-left text-slate-600">
            <thead className="text-xs text-slate-700 uppercase bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-3 font-bold">No. Urut</th>
                <th className="px-6 py-3 font-bold">Bulan / Periode</th>
                <th className="px-6 py-3 font-bold">Nama Petugas</th>
                <th className="px-6 py-3 font-bold">ULP</th>
                <th className="px-6 py-3 font-bold text-center">Total Realisasi</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {rekapData.length > 0 ? (
                rekapData.map((item) => (
                  <tr key={`${item.ulp}-${item.nama}`} className={`hover:bg-slate-50 transition-colors ${item.no <= 3 && item.total > 0 ? 'bg-yellow-50/30' : ''}`}>
                    <td className="px-6 py-3 font-medium text-slate-400">
                      {item.no === 1 && item.total > 0 ? '🥇' : item.no === 2 && item.total > 0 ? '🥈' : item.no === 3 && item.total > 0 ? '🥉' : item.no}
                    </td>
                    <td className="px-6 py-3 text-slate-500">{item.bulan}</td>
                    <td className="px-6 py-3 font-bold text-slate-800">{item.nama}</td>
                    <td className="px-6 py-3">
                      <span className="px-2 py-1 bg-cyan-50 text-cyan-700 text-[10px] font-bold rounded uppercase border border-cyan-100">
                        {item.ulp.replace('ULP ', '')}
                      </span>
