import { ReportData, ULPData } from '../types';

/**
 * URL Google Apps Script
 * PENTING: Gunakan URL dari 'New Deployment' terbaru Anda.
 * Pastikan Akses disetel ke 'Anyone' (Siapa Saja).
 */
const GOOGLE_SCRIPT_URL: string = 'https://script.google.com/macros/s/AKfycbxQMSfcuFSwzhMHkUJO9UWwOCS3G0NJVEDHB0XhY2cBGllIPV6pu149JdGy-E2XBzQN/exec'; 

/**
 * Helper function for resilient fetch with retries
 */
async function resilientFetch(url: string, options: RequestInit, retries: number = 3): Promise<Response> {
  try {
    const response = await fetch(url, options);
    if (!response.ok && retries > 0) {
      await new Promise(res => setTimeout(res, 1000));
      return resilientFetch(url, options, retries - 1);
    }
    return response;
  } catch (error) {
    if (retries > 0) {
      await new Promise(res => setTimeout(res, 1000));
      return resilientFetch(url, options, retries - 1);
    }
    throw error;
  }
}

export const api = {
  getAllData: async () => {
    try {
      // Menambahkan timestamp cache-buster untuk menghindari hasil cache browser yang korup
      const response = await resilientFetch(`${GOOGLE_SCRIPT_URL}?action=getAll&t=${Date.now()}`, {
        method: 'GET',
        // Kita tidak menggunakan mode 'no-cors' di GET agar bisa membaca JSON
        mode: 'cors',
        headers: {
          'Accept': 'application/json'
        }
      });

      if (!response.ok) throw new Error(`HTTP Error: ${response.status}`);

      const data = await response.json();
      return data;
    } catch (error: any) {
      console.error("API Error (GetAll):", error);
      // Jika error adalah "Failed to fetch", kemungkinan besar karena CORS atau URL salah
      if (error.message === 'Failed to fetch') {
        throw new Error("Gagal terhubung ke server. Pastikan URL Script benar dan izin akses disetel ke 'Anyone'.");
      }
      throw error;
    }
  },

  saveReport: async (report: ReportData, isEdit: boolean = false) => {
    try {
      const action = isEdit ? 'updateReport' : 'saveReport';
      const payload = JSON.stringify({
        action: action,
        data: report
      });

      /**
       * PENTING UNTUK GOOGLE APPS SCRIPT:
       * Menggunakan mode 'no-cors' dan Content-Type 'text/plain' adalah cara paling stabil 
       * untuk mengirim data besar (seperti foto Base64) ke GAS tanpa terbentur masalah pre-flight CORS.
       */
      await resilientFetch(`${GOOGLE_SCRIPT_URL}?action=${action}`, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 
          'Content-Type': 'text/plain;charset=utf-8' 
        },
        body: payload
      });

      return true;
    } catch (error) {
      console.error("Gagal mengirim ke GAS:", error);
      throw error;
    }
  },

  updateMasterData: async (masterData: Record<string, ULPData>) => {
    try {
      await resilientFetch(`${GOOGLE_SCRIPT_URL}?action=updateMaster`, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'text/plain' },
        body: JSON.stringify({ action: 'updateMaster', data: masterData })
      });
      return true;
    } catch (error) {
      console.error("Gagal update master:", error);
      return true; // Return true as fallback to not block UI
    }
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { UserRole, ViewState, ReportData, ULPName, ULPData, LoginSession } from './types';
