/**
 * URL Google Apps Script
 * PENTING: Gunakan URL dari 'New Deployment' terbaru Anda di Google Sheets.
 * Pastikan:
 * 1. Deploy -> New Deployment
 * 2. Select type: Web App
 * 3. Execute as: Me (Email Anda)
 * 4. Who has access: Anyone (PENTING!)
 */
const GOOGLE_SCRIPT_URL: string = 'https://script.google.com/macros/s/AKfycbxQMSfcuFSwzhMHkUJO9UWwOCS3G0NJVEDHB0XhY2cBGllIPV6pu149JdGy-E2XBzQN/exec'; 

export const api = {
  getAllData: async () => {
    try {
      // Menambahkan timestamp cache-buster agar browser tidak mengambil data lama dari cache
      const url = `${GOOGLE_SCRIPT_URL}?action=getAll&t=${Date.now()}`;

      const response = await fetch(url, {
        method: 'GET',
        // 'follow' adalah default, tapi kita set eksplisit karena GAS selalu redirect
        redirect: 'follow',
      });

      if (!response.ok) {
        throw new Error(`Server merespon dengan status: ${response.status}`);
      }

      const data = await response.json();
      return data;
    } catch (error: any) {
      console.error("API Error (GetAll):", error);

      // Pesan error lebih deskriptif untuk user
      if (error.message === 'Failed to fetch') {
        throw new Error("Koneksi gagal: Browser memblokir permintaan atau URL Script salah. Pastikan Deployment di Google Sheets sudah diatur ke 'Anyone'.");
      }
      throw error;
    }
  },

  saveReport: async (report: ReportData, isEdit: boolean = false) => {
    try {
      const action = isEdit ? 'updateReport' : 'saveReport';
      const payload = JSON.stringify({
        action: action,
        data: report
      });

      /**
       * PENTING: Untuk POST ke Google Apps Script dengan data besar (Base64 foto), 
       * mode 'no-cors' dengan Content-Type 'text/plain' adalah yang paling stabil.
       */
      await fetch(`${GOOGLE_SCRIPT_URL}?action=${action}`, {
        method: 'POST',
        mode: 'no-cors',
        cache: 'no-cache',
        headers: { 
          'Content-Type': 'text/plain;charset=utf-8' 
        },
        body: payload
      });

      return true;
    } catch (error) {
      console.error("Gagal mengirim data ke Spreadsheet:", error);
      throw error;
    }
  },

  updateMasterData: async (masterData: Record<string, ULPData>) => {
    try {
      await fetch(`${GOOGLE_SCRIPT_URL}?action=updateMaster`, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'text/plain' },
        body: JSON.stringify({ action: 'updateMaster', data: masterData })
      });
      return true;
    } catch (error) {
      console.error("Gagal update master data:", error);
      return false;
    }
  }
};

