  const [editingReport, setEditingReport] = useState<ReportData | null>(null);

  const [tableStartDate, setTableStartDate] = useState('');
  const [tableEndDate, setTableEndDate] = useState('');
  const [tableUlpFilter, setTableUlpFilter] = useState<ULPName | ''>('');

  const [pendingIds, setPendingIds] = useState<Set<string>>(new Set());

  useEffect(() => {
    const cached = localStorage.getItem('yandal_reports_cache');
    if (cached) setReports(JSON.parse(cached));

    const pending = localStorage.getItem('yandal_pending_ids');
    if (pending) setPendingIds(new Set(JSON.parse(pending)));

    fetchData(true);
  }, []);

  useEffect(() => {
    localStorage.setItem('yandal_pending_ids', JSON.stringify(Array.from(pendingIds)));
  }, [pendingIds]);

  const fetchData = async (showLoading = true) => {
    if (showLoading) {
      setIsLoading(true);
      setFetchError(null);
    }

    try {
      const result = await api.getAllData();
      if (result && result.reports) {
        setReports(prev => {
          const reportMap = new Map<string, ReportData>();
          result.reports.forEach((r: ReportData) => reportMap.set(r.id, r));
          prev.forEach(r => {
            if (pendingIds.has(r.id) && !reportMap.has(r.id)) {
              reportMap.set(r.id, r);
            }
          });
          const combined = Array.from(reportMap.values());
          localStorage.setItem('yandal_reports_cache', JSON.stringify(combined));
          return combined;
        });

        setPendingIds(prevPending => {
          const next = new Set(prevPending);
          result.reports.forEach((r: ReportData) => next.delete(r.id));
          return next;
        });

        if (result.masterData) setMasterData(result.masterData);
      }
    } catch (e: any) {
      console.error("Fetch data failed:", e);
      setFetchError(e.message || "Gagal menghubungi database.");
    } finally {
      if (showLoading) setIsLoading(false);
    }
  };

  const handleUpdateUrl = () => {
    if (api.setScriptUrl(tempUrl)) {
      setShowUrlConfig(false);
