import { ReportData, ULPData } from '../types';

/**
 * DEFAULT_URL: Gunakan ini sebagai cadangan jika localStorage kosong.
 * PENTING: Gunakan URL dari 'New Deployment' terbaru Anda.
 * Pastikan Akses disetel ke 'Anyone' (Siapa Saja).
 */
const DEFAULT_URL = 'https://script.google.com/macros/s/AKfycbxQMSfcuFSwzhMHkUJO9UWwOCS3G0NJVEDHB0XhY2cBGllIPV6pu149JdGy-E2XBzQN/exec';

let currentUrl = localStorage.getItem('yandal_gas_url') || DEFAULT_URL;

export const api = {
  getScriptUrl: () => currentUrl,

  setScriptUrl: (url: string) => {
    const cleanUrl = url.trim();
    if (cleanUrl.startsWith('https://script.google.com')) {
      currentUrl = cleanUrl;
      localStorage.setItem('yandal_gas_url', cleanUrl);
      return true;
    }
    return false;
  },

  getAllData: async () => {
    const url = `${currentUrl}?action=getAll&t=${Date.now()}`;
    console.log("Fetching from URL:", url);

    try {
      // Menggunakan fetch minimalis untuk menghindari preflight CORS yang tidak perlu
      const response = await fetch(url, {
        method: 'GET',
        mode: 'cors', // Penting untuk bisa membaca response body
        cache: 'no-store'
      });

      if (!response.ok) {
        throw new Error(`Server merespon dengan status: ${response.status}`);
      }

      const data = await response.json();
      return data;
    } catch (error: any) {
      console.error("API GET Detail Error:", error);

      if (error.message === 'Failed to fetch') {
        throw new Error("Koneksi ditolak (Failed to fetch). Hal ini biasanya terjadi jika: 1. URL salah, 2. Script belum di-deploy sebagai 'Anyone', atau 3. Browser memblokir redirect Google.");
      }
      throw error;
    }
  },

  saveReport: async (report: ReportData, isEdit: boolean = false) => {
    try {
      const action = isEdit ? 'updateReport' : 'saveReport';
      const payload = JSON.stringify({ action, data: report });

      // Mode no-cors wajib untuk POST ke GAS agar browser mengizinkan redirect tanpa preflight
      await fetch(`${currentUrl}?action=${action}`, {
        method: 'POST',
        mode: 'no-cors',
        cache: 'no-cache',
        headers: { 
          'Content-Type': 'text/plain;charset=utf-8' 
        },
        body: payload
      });

      return true;
    } catch (error) {
      console.error("API POST Error:", error);
      throw error;
    }
  },

  updateMasterData: async (masterData: Record<string, ULPData>) => {
    try {
      await fetch(`${currentUrl}?action=updateMaster`, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'text/plain' },
        body: JSON.stringify({ action: 'updateMaster', data: masterData })
      });
      return true;
    } catch (error) {
      return false;
    }
  }
};

