import { ReportData, ULPData } from '../types';

/**
 * DEFAULT_URL: URL default aplikasi. 
 * PENTING: Jika Anda mendeploy script baru, ganti URL ini atau gunakan fitur "Ubah URL" di aplikasi.
 */
const DEFAULT_URL = 'https://script.google.com/macros/s/AKfycbxQMSfcuFSwzhMHkUJO9UWwOCS3G0NJVEDHB0XhY2cBGllIPV6pu149JdGy-E2XBzQN/exec';

let currentUrl = localStorage.getItem('yandal_gas_url') || DEFAULT_URL;

export const api = {
  getScriptUrl: () => currentUrl,
  getDefaultUrl: () => DEFAULT_URL,

  setScriptUrl: (url: string) => {
    const cleanUrl = url.trim();
    if (cleanUrl.startsWith('https://script.google.com')) {
      currentUrl = cleanUrl;
      localStorage.setItem('yandal_gas_url', cleanUrl);
      return true;
    }
    return false;
  },

  resetUrl: () => {
    currentUrl = DEFAULT_URL;
    localStorage.removeItem('yandal_gas_url');
    return DEFAULT_URL;
  },

  getAllData: async () => {
    // Menambahkan cache buster (timestamp) agar tidak mengambil data lama dari cache browser/CDN
    const url = `${currentUrl}?action=getAll&t=${Date.now()}`;

    try {
      /**
       * PENTING: Google Apps Script Web App memerlukan pengalihan (redirect).
       * Fetch secara otomatis mengikuti redirect. 
       * 'mode: cors' diperlukan untuk membaca isi JSON.
       */
      const response = await fetch(url, {
        method: 'GET',
        mode: 'cors',
        credentials: 'omit', // Mengurangi kemungkinan masalah CORS pada beberapa browser
      });

      if (!response.ok) {
        throw new Error(`HTTP Error: ${response.status} ${response.statusText}`);
      }

      const data = await response.json();
      return data;
    } catch (error: any) {
      console.error("Network Detail Error:", error);

      // Menangani error "Failed to fetch" yang umum terjadi pada GAS
      if (error instanceof TypeError && error.message === 'Failed to fetch') {
        throw new Error("Koneksi gagal (Network Error). Ini biasanya disebabkan oleh URL yang salah, script belum di-deploy sebagai 'Anyone', atau browser memblokir koneksi ke Google.");
      }

      throw error;
    }
  },

  saveReport: async (report: ReportData, isEdit: boolean = false) => {
    try {
      const action = isEdit ? 'updateReport' : 'saveReport';
      const payload = JSON.stringify({ action, data: report });

      /**
       * POST ke Google Apps Script sering mengalami masalah CORS Preflight.
       * Menggunakan 'mode: no-cors' dengan Content-Type 'text/plain' adalah 
       * cara paling stabil untuk mengirim data (meskipun kita tidak bisa membaca response body).
       */
      await fetch(`${currentUrl}?action=${action}`, {
        method: 'POST',
        mode: 'no-cors',
        cache: 'no-cache',
        headers: { 
          'Content-Type': 'text/plain;charset=utf-8' 
        },
        body: payload
      });

      return true;
    } catch (error) {
      console.error("API POST Error:", error);
      throw error;
    }
  },

  updateMasterData: async (masterData: Record<string, ULPData>) => {
    try {
      await fetch(`${currentUrl}?action=updateMaster`, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'text/plain' },
        body: JSON.stringify({ action: 'updateMaster', data: masterData })
      });
      return true;
    } catch (error) {
      return false;
    }
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { UserRole, ViewState, ReportData, ULPName, ULPData, LoginSession } from './types';
import { InputForm } from './components/InputForm';
import { Dashboard } from './components/Dashboard';
import { DataTable } from './components/DataTable';
import { AdminSettings } from './components/AdminSettings';
import { AdminRekap } from './components/AdminRekap';
import { LoginConfig } from './components/LoginConfig';
import { DATA_ULP as INITIAL_DATA_ULP } from './constants';
import { api } from './services/api';

const LOGO_URL = "https://plnes.co.id/_next/image?url=https%3A%2F%2Fcms.plnes.co.id%2Fuploads%2FLogo_HP_New_Temporary_09a9c5a521.png&w=750&q=75"; 
const APP_LOGO = "https://raw.githubusercontent.com/plnesbukittinggi-ai/yandal_patrol/main/ChatGPT%20Image%2018%20Des%202025%2C%2011.11.52.png";

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [view, setView] = useState<ViewState>('LOGIN');
  const [isLoading, setIsLoading] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [fetchError, setFetchError] = useState<string | null>(null);

  // UI States for URL troubleshooting
  const [tempUrl, setTempUrl] = useState(api.getScriptUrl());
  const [showUrlConfig, setShowUrlConfig] = useState(false);

  const [session, setSession] = useState<LoginSession>({ ulp: null, petugas1: null, petugas2: null });
  const [reports, setReports] = useState<ReportData[]>([]);
  const [masterData, setMasterData] = useState<Record<string, ULPData>>(INITIAL_DATA_ULP);
  const [editingReport, setEditingReport] = useState<ReportData | null>(null);

  const [tableStartDate, setTableStartDate] = useState('');
  const [tableEndDate, setTableEndDate] = useState('');
  const [tableUlpFilter, setTableUlpFilter] = useState<ULPName | ''>('');

  const [pendingIds, setPendingIds] = useState<Set<string>>(new Set());

  useEffect(() => {
    const cached = localStorage.getItem('yandal_reports_cache');
    if (cached) setReports(JSON.parse(cached));

    const pending = localStorage.getItem('yandal_pending_ids');
    if (pending) setPendingIds(new Set(JSON.parse(pending)));

    fetchData(true);
  }, []);

  useEffect(() => {
    localStorage.setItem('yandal_pending_ids', JSON.stringify(Array.from(pendingIds)));
  }, [pendingIds]);

  const fetchData = async (showLoading = true) => {
    if (showLoading) {
      setIsLoading(true);
      setFetchError(null);
    }

    try {
      const result = await api.getAllData();
      if (result && result.reports) {
        setReports(prev => {
          const reportMap = new Map<string, ReportData>();
          result.reports.forEach((r: ReportData) => reportMap.set(r.id, r));
          prev.forEach(r => {
            if (pendingIds.has(r.id) && !reportMap.has(r.id)) {
              reportMap.set(r.id, r);
            }
          });
          const combined = Array.from(reportMap.values());
          localStorage.setItem('yandal_reports_cache', JSON.stringify(combined));
          return combined;
        });

        setPendingIds(prevPending => {
          const next = new Set(prevPending);
          result.reports.forEach((r: ReportData) => next.delete(r.id));
          return next;
        });

        if (result.masterData) setMasterData(result.masterData);
      }
    } catch (e: any) {
      console.error("Connection failed:", e);
      setFetchError(e.message || "Gagal menghubungi database.");
    } finally {
      if (showLoading) setIsLoading(false);
    }
  };

  const handleUpdateUrl = () => {
    if (api.setScriptUrl(tempUrl)) {
      setShowUrlConfig(false);
      fetchData(true);
    } else {
      alert("URL tidak valid! Harus diawali dengan https://script.google.com");
    }
  };

  const handleResetUrl = () => {
    const defaultUrl = api.resetUrl();
    setTempUrl(defaultUrl);
    setShowUrlConfig(false);
    fetchData(true);
  };

  const handleSaveReport = async (data: ReportData, isEdit: boolean) => {
    setIsSyncing(true);
    setPendingIds(prev => new Set(prev).add(data.id));
    setReports(prev => [data, ...prev.filter(r => r.id !== data.id)]);

    try {
      await api.saveReport(data, isEdit);
      setTimeout(() => {
        fetchData(false).then(() => setIsSyncing(false));
      }, 5000);
      setEditingReport(null);
      setView('TABLE');
    } catch (e) {
      alert("Koneksi bermasalah. Laporan tersimpan di HP ini dan akan disinkronkan otomatis saat koneksi kembali normal.");
      setIsSyncing(false);
    }
  };

  const handleAdminLoginSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const pass = (e.currentTarget.elements.namedItem('password') as HTMLInputElement).value;
