                <button onClick={() => setShowUrlConfig(!showUrlConfig)} className="text-[10px] text-primary font-black uppercase tracking-widest hover:underline">
                  {showUrlConfig ? 'Batal' : 'Ubah URL'}
                </button>
                {api.getScriptUrl() !== api.getDefaultUrl() && (
                  <button onClick={handleResetUrl} className="text-[10px] text-red-500 font-black uppercase tracking-widest hover:underline">
                    Reset
                  </button>
                )}
              </div>
            </div>

            {showUrlConfig ? (
              <div className="space-y-3">
                <textarea 
                  className="w-full p-3 border border-slate-200 rounded-xl text-[11px] font-mono leading-relaxed h-20 focus:ring-2 focus:ring-primary/20 outline-none"
                  value={tempUrl}
                  onChange={(e) => setTempUrl(e.target.value)}
                  placeholder="Paste URL Script baru di sini..."
                />
                <button 
                  onClick={handleUpdateUrl}
                  className="w-full bg-slate-800 text-white font-black py-3 rounded-xl uppercase text-[10px] tracking-widest"
                >
                  Simpan & Hubungkan
                </button>
              </div>
            ) : (
              <p className="text-[10px] text-slate-500 font-mono break-all line-clamp-1">{api.getScriptUrl()}</p>
            )}
          </div>

          <div className="space-y-3">
            <button 
              onClick={() => fetchData(true)}
              className="w-full bg-primary text-white font-black py-4 rounded-2xl shadow-lg shadow-cyan-100 uppercase text-[10px] tracking-widest hover:bg-cyan-800 transition-all"
            >
              Coba Hubungkan Lagi
            </button>
            <button 
              onClick={() => setView('LOGIN')}
              className="w-full bg-slate-100 text-slate-600 font-black py-4 rounded-2xl uppercase text-[10px] tracking-widest hover:bg-slate-200 transition-all"
            >
              Kembali ke Login (Mode Offline)
            </button>
          </div>

          <div className="mt-8 pt-6 border-t border-slate-100">
             <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Tips Troubleshooting:</h4>
             <ul className="text-[10px] text-slate-500 list-disc pl-4 space-y-2">
