               <li>Matikan ekstensi browser seperti <b>AdBlocker</b> atau <b>VPN</b>.</li>
               <li>Pastikan deployment di Google Sheets disetel ke <b>"Anyone"</b>.</li>
               <li>Gunakan <b>URL Deployment baru</b> jika Anda baru saja mengubah kode di Apps Script.</li>
             </ul>
          </div>
        </div>
      </div>
    );
  }

  if (view === 'LOGIN') {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
        <div className="bg-white p-8 rounded-2xl shadow-xl max-w-md w-full border border-slate-200">
          <div className="text-center mb-8">
