              const updated = { ...masterData };
              updated[ulp].penyulang = [...new Set([...updated[ulp].penyulang, ...names])];
              setMasterData(updated);
              api.updateMasterData(updated);
            }} 
            onDeletePenyulang={(ulp, name) => {
              const updated = { ...masterData };
              updated[ulp].penyulang = updated[ulp].penyulang.filter(n => n !== name);
              setMasterData(updated);
              api.updateMasterData(updated);
            }} 
          />
