                  <div className="flex gap-2">
                    <input type="date" className="flex-1 px-3 py-2 border border-slate-200 rounded-xl text-xs font-bold" value={tableStartDate} onChange={(e) => setTableStartDate(e.target.value)} />
                    <input type="date" className="flex-1 px-3 py-2 border border-slate-200 rounded-xl text-xs font-bold" value={tableEndDate} onChange={(e) => setTableEndDate(e.target.value)} />
                  </div>
                </div>
                <button onClick={() => fetchData(true)} className="bg-slate-100 hover:bg-slate-200 p-2.5 rounded-xl transition-all">
                  <svg className="w-5 h-5 text-slate-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                  </svg>
                </button>
             </div>
             <DataTable 
                reports={filteredReportsForTable} 
                pendingIds={pendingIds}
                onEdit={(r) => { setEditingReport(r); setView('INPUT'); }} 
             />
          </div>
        )}
      </main>
    </div>
  );
};

