import React, { useState, useMemo } from 'react';
import { ReportData, ULPData, ULPName } from '../types';

interface AdminRekapProps {
  reports: ReportData[];
  masterData: Record<string, ULPData>;
}

export const AdminRekap: React.FC<AdminRekapProps> = ({ reports, masterData }) => {
  // Helper to get current month date range
  const getCurrentMonthRange = () => {
    const now = new Date();
    const firstDay = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
    const lastDay = new Date(now.getFullYear(), now.getMonth() + 1, 0).toISOString().split('T')[0];
    return { firstDay, lastDay };
  };

  const { firstDay: initStart, lastDay: initEnd } = getCurrentMonthRange();

  const [startDate, setStartDate] = useState(initStart);
  const [endDate, setEndDate] = useState(initEnd);
  const [filterUlp, setFilterUlp] = useState<ULPName | ''>('');

  const rekapData = useMemo(() => {
    // 1. Filter laporan berdasarkan tanggal
    const filteredReports = reports.filter(report => {
      const reportDate = new Date(report.timestamp).toISOString().split('T')[0];
      const startMatch = !startDate || reportDate >= startDate;
      const endMatch = !endDate || reportDate <= endDate;
      return startMatch && endMatch;
    });

    const rawResult: any[] = [];

    // 2. Iterasi melalui semua ULP di masterData
    Object.values(masterData).forEach((ulpData: ULPData) => {
      if (filterUlp && ulpData.name !== filterUlp) return;

      ulpData.petugas.forEach(namaPetugas => {
        const totalRealisasi = filteredReports.filter(r => 
          r.ulp === ulpData.name && 
          (r.petugas1 === namaPetugas || r.petugas2 === namaPetugas)
        ).length;

        let bulanLabel = "Bulan Ini";
        if (startDate && endDate) {
          const s = new Date(startDate).toLocaleString('id-ID', { month: 'short', year: '2-digit' });
          const e = new Date(endDate).toLocaleString('id-ID', { month: 'short', year: '2-digit' });
          bulanLabel = s === e ? s : `${s} - ${e}`;
        }

        rawResult.push({
          bulan: bulanLabel,
          nama: namaPetugas,
          ulp: ulpData.name,
          total: totalRealisasi
        });
      });
    });

    rawResult.sort((a, b) => {
      if (b.total !== a.total) {
        return b.total - a.total;
      }
      return a.nama.localeCompare(b.nama);
    });

    return rawResult.map((item, index) => ({
      ...item,
      no: index + 1
    }));
  }, [reports, masterData, startDate, endDate, filterUlp]);

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-4">
          <h2 className="text-xl font-bold text-slate-800">Rekap Realisasi Petugas (Bulan Berjalan)</h2>
          <div className="px-3 py-1 bg-blue-50 text-blue-700 rounded-lg text-xs font-bold border border-blue-100">
            Urutan: Realisasi Terbanyak
          </div>
        </div>

        {/* Filter Section */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-6 p-4 bg-slate-50 rounded-lg border border-slate-100">
          <div>
            <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Dari Tanggal</label>
            <input 
              type="date" 
              className="w-full px-3 py-2 border border-slate-300 rounded-md text-sm focus:ring-2 focus:ring-primary focus:border-transparent"
              value={startDate}
              onChange={(e) => setStartDate(e.target.value)}
            />
          </div>
          <div>
            <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Sampai Tanggal</label>
            <input 
              type="date" 
              className="w-full px-3 py-2 border border-slate-300 rounded-md text-sm focus:ring-2 focus:ring-primary focus:border-transparent"
              value={endDate}
              onChange={(e) => setEndDate(e.target.value)}
            />
          </div>
          <div>
            <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Filter ULP</label>
            <select 
              className="w-full px-3 py-2 border border-slate-300 rounded-md text-sm bg-white focus:ring-2 focus:ring-primary focus:border-transparent"
              value={filterUlp}
              onChange={(e) => setFilterUlp(e.target.value as ULPName)}
            >
              <option value="">Semua ULP</option>
              {Object.values(ULPName).map(u => <option key={u} value={u}>{u}</option>)}
            </select>
          </div>
          <div className="flex items-end">
            <button 
              onClick={() => { setStartDate(initStart); setEndDate(initEnd); setFilterUlp(''); }}
              className="w-full py-2 px-4 bg-slate-200 hover:bg-slate-300 text-slate-700 font-semibold rounded-md text-sm transition-colors"
            >
              Reset (Bulan Ini)
            </button>
          </div>
        </div>

        {/* Table Section */}
        <div className="overflow-x-auto border border-slate-200 rounded-lg">
          <table className="w-full text-sm text-left text-slate-600">
            <thead className="text-xs text-slate-700 uppercase bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-3 font-bold">No. Urut</th>
                <th className="px-6 py-3 font-bold">Bulan / Periode</th>
                <th className="px-6 py-3 font-bold">Nama Petugas</th>
                <th className="px-6 py-3 font-bold">ULP</th>
                <th className="px-6 py-3 font-bold text-center">Total Realisasi</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {rekapData.length > 0 ? (
                rekapData.map((item) => (
                  <tr key={`${item.ulp}-${item.nama}`} className={`hover:bg-slate-50 transition-colors ${item.no <= 3 && item.total > 0 ? 'bg-yellow-50/30' : ''}`}>
                    <td className="px-6 py-3 font-medium text-slate-400">
                      {item.no === 1 && item.total > 0 ? '🥇' : item.no === 2 && item.total > 0 ? '🥈' : item.no === 3 && item.total > 0 ? '🥉' : item.no}
                    </td>
                    <td className="px-6 py-3 text-slate-500">{item.bulan}</td>
                    <td className="px-6 py-3 font-bold text-slate-800">{item.nama}</td>
                    <td className="px-6 py-3">
                      <span className="px-2 py-1 bg-cyan-50 text-cyan-700 text-[10px] font-bold rounded uppercase border border-cyan-100">
                        {item.ulp.replace('ULP ', '')}
                      </span>
                    </td>
                    <td className="px-6 py-3 text-center">
                      <span className={`inline-block min-w-[32px] px-2 py-1 rounded-full font-bold text-sm ${item.total > 0 ? 'bg-green-100 text-green-700' : 'bg-slate-100 text-slate-400'}`}>
                        {item.total}
                      </span>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan={5} className="px-6 py-10 text-center text-slate-400 italic">
                    Data tidak ditemukan untuk bulan ini.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
        <div className="mt-4 text-[10px] text-slate-400 italic">
          * Menampilkan data petugas berdasarkan realisasi pada bulan berjalan ({initStart} s/d {initEnd}).
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { UserRole, ViewState, ReportData, ULPName, ULPData, LoginSession } from './types';
import { InputForm } from './components/InputForm';
import { Dashboard } from './components/Dashboard';
import { DataTable } from './components/DataTable';
import { AdminSettings } from './components/AdminSettings';
import { AdminRekap } from './components/AdminRekap';
import { LoginConfig } from './components/LoginConfig';
import { DATA_ULP as INITIAL_DATA_ULP, APP_VERSION } from './constants';
import { api } from './services/api';

const LOGO_URL = "https://plnes.co.id/_next/image?url=https%3A%2F%2Fcms.plnes.co.id%2Fuploads%2FLogo_HP_New_Temporary_09a9c5a521.png&w=750&q=75"; 
const APP_LOGO = "https://raw.githubusercontent.com/plnesbukittinggi-ai/yandal_patrol/main/ChatGPT%20Image%2018%20Des%202025%2C%2011.11.52.png";
const NOTIFICATION_SOUND = "https://assets.mixkit.co/active_storage/sfx/2869/2869-preview.mp3";

declare global {
  interface Window {
    ExcelJS: any;
  }
}

const App: React.FC = () => {
  // Helper to get current month date range
  const getCurrentMonthRange = () => {
    const now = new Date();
    const firstDay = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
    const lastDay = new Date(now.getFullYear(), now.getMonth() + 1, 0).toISOString().split('T')[0];
    return { firstDay, lastDay };
  };

  const { firstDay: initStart, lastDay: initEnd } = getCurrentMonthRange();

  const [role, setRole] = useState<UserRole | null>(null);
  const [view, setView] = useState<ViewState>('LOGIN');
  const [isLoading, setIsLoading] = useState(false);
  const [errorLoad, setErrorLoad] = useState<string | null>(null);
  const [isDemoMode, setIsDemoMode] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [notifPermission, setNotifPermission] = useState<NotificationPermission>('default');

  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [adminPassword, setAdminPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  const [session, setSession] = useState<LoginSession>({ ulp: null, petugas1: null, petugas2: null });

  const [tableStartDate, setTableStartDate] = useState(initStart);
  const [tableEndDate, setTableEndDate] = useState(initEnd);
  const [tableUlpFilter, setTableUlpFilter] = useState<ULPName | ''>('');

  const [reports, setReports] = useState<ReportData[]>([]);
  const [masterData, setMasterData] = useState<Record<string, ULPData>>(INITIAL_DATA_ULP);
  const [editingReport, setEditingReport] = useState<ReportData | null>(null);

  const pendingUpdatesRef = useRef<Map<string, string>>(new Map());
  const lastReportIdRef = useRef<string | null>(null);
  const lastPeriodicNotifyRef = useRef<number>(0);

  // --- NOTIFICATION FEATURE ---

  const requestNotificationPermission = async () => {
    if ('Notification' in window) {
      const permission = await Notification.requestPermission();
      setNotifPermission(permission);
      return permission;
    }
    return 'denied';
  };

  const playNotificationSound = () => {
    const audio = new Audio(NOTIFICATION_SOUND);
    audio.play().catch(e => console.log("Audio play blocked by browser policy"));
  };

  const updateAppBadge = (count: number) => {
    if ('setAppBadge' in navigator) {
      const nav = navigator as any;
      if (count > 0) {
        nav.setAppBadge(count).catch(() => {});
      } else {
        nav.clearAppBadge().catch(() => {});
      }
    }
  };

  const sendBrowserNotification = (title: string, body: string) => {
    if (!('Notification' in window)) return;

    if (Notification.permission === 'granted') {
      playNotificationSound();

      if ('serviceWorker' in navigator) {
        navigator.serviceWorker.ready.then(registration => {
          registration.showNotification(title, {
            body,
            icon: APP_LOGO,
            badge: APP_LOGO,
            tag: 'yandal-patrol-notif',
            renotify: true,
            vibrate: [200, 100, 200],
            data: { url: window.location.origin }
          } as any);
        });
      } else {
        new Notification(title, { body, icon: APP_LOGO });
      }
    }
  };

  const handleTestNotification = async () => {
    const perm = await requestNotificationPermission();
    if (perm === 'granted') {
      sendBrowserNotification("Tes Notifikasi Berhasil", "Notifikasi Yandal Patrol aktif di perangkat ini.");
      updateAppBadge(5);
      setTimeout(() => updateAppBadge(0), 5000);
    } else {
      alert("Izin notifikasi ditolak. Silakan aktifkan di pengaturan browser Anda.");
    }
  };

  const generateSummaryMessage = (currentReports: ReportData[]) => {
    const today = new Date().toISOString().split('T')[0];
    const todayReports = currentReports.filter(r => r.timestamp.startsWith(today));

    const counts: Record<string, number> = {};
    Object.values(ULPName).forEach(name => {
      counts[name] = todayReports.filter(r => r.ulp === name).length;
    });

    const dateOptions: Intl.DateTimeFormatOptions = { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' };
    const dateStr = new Date().toLocaleDateString('id-ID', dateOptions);

    let message = `Laporan Yandal Patrol Hari ini : ${dateStr}\n`;
    message += `- ULP Bukittinggi : ${counts[ULPName.BUKITTINGGI] || 0}\n`;
    message += `- ULP Padang Panjang : ${counts[ULPName.PADANG_PANJANG] || 0}\n`;
    message += `- ULP Lubuk Sikaping : ${counts[ULPName.LUBUK_SIKAPING] || 0}\n`;
    message += `- ULP Lubuk Basung : ${counts[ULPName.LUBUK_BASUNG] || 0}\n`;
    message += `- ULP Simpang Empat : ${counts[ULPName.SIMPANG_EMPAT] || 0}\n`;
    message += `- ULP Baso : ${counts[ULPName.BASO] || 0}\n`;
    message += `- ULP Koto Tuo : ${counts[ULPName.KOTO_TUO] || 0}\n`;
    message += `\nMohon untuk ULP yang belum lapor untuk segera melaksanakannya.`;

    return { message, totalToday: todayReports.length };
  };

  const checkPeriodicNotification = (currentReports: ReportData[]) => {
    const now = new Date();
    const currentHour = now.getHours();
    if (currentHour >= 10 && currentHour <= 18) {
      if (currentHour % 2 === 0 && lastPeriodicNotifyRef.current !== currentHour) {
        lastPeriodicNotifyRef.current = currentHour;
        const { message, totalToday } = generateSummaryMessage(currentReports);
        sendBrowserNotification("Update Berkala Yandal Patrol", message);
        updateAppBadge(totalToday);
      }
    }
  };

  // --- END NOTIFICATION FEATURE ---

  useEffect(() => {
    if ('Notification' in window) {
      setNotifPermission(Notification.permission);
      if (Notification.permission === 'default') {
        requestNotificationPermission();
      }
    }

    const savedDemo = localStorage.getItem('yandal_demo_mode');
    if (savedDemo === 'true') {
      setIsDemoMode(true);
      const savedReports = localStorage.getItem('yandal_local_reports');
      if (savedReports) setReports(JSON.parse(savedReports));
    }
    fetchData(true);

    const poller = setInterval(() => {
      fetchData(false);
    }, 120000);

    return () => clearInterval(poller);
  }, []);

  useEffect(() => {
    if (view === 'TABLE' && !isDemoMode) {
      fetchData(false);
    }
  }, [tableStartDate, tableEndDate, tableUlpFilter, view]);

  const fetchData = async (showLoading = true) => {
    if (isDemoMode) return;

    if (showLoading) {
      setIsLoading(true);
      setErrorLoad(null);
    }
    try {
      const data = await api.getAllData();
      if (data && data.reports) {
        const serverReports = data.reports as ReportData[];

        if (serverReports.length > 0) {
          const sorted = [...serverReports].sort((a,b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
          const latest = sorted[0];

          if (lastReportIdRef.current && latest.id !== lastReportIdRef.current) {
            const { message, totalToday } = generateSummaryMessage(serverReports);
            sendBrowserNotification("Input Laporan Patrol Baru!", `Oleh: ${latest.petugas1} (${latest.ulp})\n\n${message}`);
            updateAppBadge(totalToday);
          }
          lastReportIdRef.current = latest.id;
        }

        checkPeriodicNotification(serverReports);

        setReports(prevReports => {
          const reportMap = new Map<string, ReportData>();
          prevReports.forEach(r => reportMap.set(r.id, r));
          serverReports.forEach((serverReport: ReportData) => {
            const pendingTimestamp = pendingUpdatesRef.current.get(serverReport.id);
            if (pendingTimestamp && new Date(serverReport.timestamp) < new Date(pendingTimestamp)) {
              return; 
            }
            reportMap.set(serverReport.id, serverReport);
          });
          return Array.from(reportMap.values());
        });

        if (data.masterData) {
            const updatedMaster = { ...data.masterData };
            Object.keys(updatedMaster).forEach(k => {
                if (!updatedMaster[k].keypoints) updatedMaster[k].keypoints = {};
            });
            setMasterData(updatedMaster);
        }
      }
    } catch (error: any) {
      console.error("Fetch failed:", error);
      if (showLoading) setErrorLoad(error.message || "Gagal terhubung ke database.");
    } finally {
      if (showLoading) setIsLoading(false);
    }
  };

  const handleInitialRoleSelect = (selectedRole: UserRole) => {
    setRole(selectedRole);
    if (selectedRole === UserRole.ADMIN) return; 
    setView('CONFIG');
  };

  const handleAdminLoginSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminPassword === 'Adminbkt') {
      setRole(UserRole.ADMIN);
      setView('DASHBOARD');
      setShowAdminLogin(false);
    } else {
      setLoginError('Password salah!');
    }
  };

  const handleConfigConfirm = (conf: LoginSession) => {
    setSession(conf);
    setView(role === UserRole.GUEST ? 'TABLE' : 'INPUT');
  };

  const handleLogout = () => {
    setRole(null);
    setView('LOGIN');
    setShowAdminLogin(false);
    setSession({ ulp: null, petugas1: null, petugas2: null });
    setEditingReport(null);
    updateAppBadge(0);
  };

  const handleBackToMenu = () => {
     if (view === 'CONFIG') {
        setView('LOGIN');
        setRole(null);
     } else {
        if (role === UserRole.ADMIN) {
           setView('DASHBOARD');
        } else {
           setView('LOGIN');
           setRole(null);
        }
     }
     setEditingReport(null);
  };

  const handleSaveReport = async (data: ReportData, isEditMode: boolean) => {
    setIsSyncing(true);
    pendingUpdatesRef.current.set(data.id, data.timestamp);
    setReports(prev => [data, ...prev.filter(r => r.id !== data.id)]);

    try {
      if (isDemoMode) {
        localStorage.setItem('yandal_local_reports', JSON.stringify([data, ...reports.filter(r => r.id !== data.id)]));
      } else {
        await api.saveReport(data, isEditMode);
        setTimeout(() => {
          fetchData(false);
          pendingUpdatesRef.current.delete(data.id);
        }, 8000);
      }
      setEditingReport(null);
      setView('TABLE');
    } catch (e) {
      alert("Gagal sinkronisasi otomatis. Data tersimpan lokal, silakan refresh nanti.");
    } finally {
      setIsSyncing(false);
    }
  };

  const openEditForm = (report: ReportData) => {
    setEditingReport(report);
    setView('INPUT');
  };

  const filteredReportsForTable = useMemo(() => {
    const uniqueMap = new Map<string, ReportData>();
    [...reports].sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime())
      .forEach(r => uniqueMap.set(r.id, r));

    return Array.from(uniqueMap.values())
      .filter(r => {
        if (session.ulp && r.ulp !== session.ulp) return false;
        if (role === UserRole.ADMIN && tableUlpFilter && r.ulp !== tableUlpFilter) return false;
        const reportDate = new Date(r.timestamp).toISOString().split('T')[0];
        if (tableStartDate && reportDate < tableStartDate) return false;
        if (tableEndDate && reportDate > tableEndDate) return false;
        return true;
      })
      .sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
  }, [reports, session.ulp, role, tableUlpFilter, tableStartDate, tableEndDate]);

  const handleDownloadExcel = async () => {
    const ExcelJS = (window as any).ExcelJS;
    if (!ExcelJS) return alert("Library ExcelJS tidak tersedia. Pastikan koneksi internet stabil.");

    setIsSyncing(true);
    try {
      const workbook = new ExcelJS.Workbook();
      const worksheet = workbook.addWorksheet('Laporan Patrol');

      // Setup Kolom
      const columns = [
        { header: 'No', key: 'no', width: 6 },
        { header: 'Tanggal', key: 'tanggal', width: 12 },
        { header: 'No. Penugasan', key: 'noPenugasan', width: 20 },
        { header: 'Unit (ULP)', key: 'ulp', width: 18 },
        { header: 'Petugas 1', key: 'petugas1', width: 18 },
        { header: 'Petugas 2', key: 'petugas2', width: 18 },
        { header: 'Penyulang', key: 'penyulang', width: 15 },
        { header: 'Keypoint', key: 'keypoint', width: 22 },
        { header: 'Titik Start', key: 'start', width: 25 },
        { header: 'Titik Finish', key: 'finish', width: 25 },
        // Kolom untuk Foto (Placeholder teks saja, gambar akan di-overlay)
        { header: 'Foto Sblm 1', key: 'sblm1', width: 18 },
        { header: 'Foto Sblm 2', key: 'sblm2', width: 18 },
        { header: 'Foto Sblm 3', key: 'sblm3', width: 18 },
        { header: 'Foto Sblm 4', key: 'sblm4', width: 18 },
        { header: 'Foto Sblm 5', key: 'sblm5', width: 18 },
        { header: 'Foto Sblm 6', key: 'sblm6', width: 18 },
        { header: 'Foto Ssdh 1', key: 'ssdh1', width: 18 },
        { header: 'Foto Ssdh 2', key: 'ssdh2', width: 18 },
        { header: 'Foto Ssdh 3', key: 'ssdh3', width: 18 },
        { header: 'Foto Ssdh 4', key: 'ssdh4', width: 18 },
        { header: 'Foto Ssdh 5', key: 'ssdh5', width: 18 },
        { header: 'Foto Ssdh 6', key: 'ssdh6', width: 18 },
      ];
      worksheet.columns = columns;

      // Styling Header
      const headerRow = worksheet.getRow(1);
      headerRow.font = { bold: true, color: { argb: 'FFFFFFFF' } };
      headerRow.fill = {
        type: 'pattern',
        pattern: 'solid',
        fgColor: { argb: 'FF0E7490' } // Cyan-700
      };
      headerRow.alignment = { vertical: 'middle', horizontal: 'center' };

      // Isi Data Laporan
      for (let i = 0; i < filteredReportsForTable.length; i++) {
        const r = filteredReportsForTable[i];
        const rowIndex = i + 2;
        const currentRow = worksheet.getRow(rowIndex);

        // Atur tinggi baris untuk foto (sekitar 80 pixel)
        currentRow.height = 80;

        currentRow.values = [
          i + 1,
          new Date(r.timestamp).toLocaleDateString('id-ID'),
          r.noPenugasan,
          r.ulp,
          r.petugas1,
          r.petugas2,
          r.penyulang,
          r.keypoint,
          r.titikStart,
          r.titikFinish,
          // Placeholder kolom foto
          '', '', '', '', '', '', '', '', '', '', '', ''
        ];

        currentRow.alignment = { vertical: 'middle', horizontal: 'center', wrapText: true };

        // Fungsi Helper untuk memasukkan gambar
        const addImageToCell = (base64Data: string | null, colIndex: number) => {
          if (!base64Data || !base64Data.startsWith('data:image')) return;
          try {
            const imageId = workbook.addImage({
              base64: base64Data,
              extension: 'jpeg',
            });
            worksheet.addImage(imageId, {
              tl: { col: colIndex - 1, row: rowIndex - 1 },
              ext: { width: 120, height: 100 },
              editAs: 'oneCell'
            });
          } catch (e) {
            console.warn("Gagal menyematkan gambar ke Excel sel:", colIndex);
          }
        };

        // Sematkan Foto Sebelum (Kolom 11 - 16)
        r.photos.sebelum.forEach((photo, pIdx) => {
           if (photo) addImageToCell(photo, 11 + pIdx);
        });

        // Sematkan Foto Sesudah (Kolom 17 - 22)
        r.photos.sesudah.forEach((photo, pIdx) => {
           if (photo) addImageToCell(photo, 17 + pIdx);
        });
      }

      // Tambahkan border ke semua sel yang terisi
      worksheet.eachRow((row) => {
        row.eachCell((cell) => {
          cell.border = {
            top: { style: 'thin' },
            left: { style: 'thin' },
            bottom: { style: 'thin' },
            right: { style: 'thin' }
          };
        });
      });

      // Generate File
      const buffer = await workbook.xlsx.writeBuffer();
      const blob = new Blob([buffer], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' });
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `Laporan_Patrol_Lengkap_${new Date().toISOString().split('T')[0]}.xlsx`;
      a.click();
      window.URL.revokeObjectURL(url);

    } catch (err: any) {
      console.error("Export Error:", err);
      alert("Gagal ekspor Excel: " + err.message);
    } finally {
      setIsSyncing(false);
    }
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50 gap-4 p-4 text-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary"></div>
        <p className="text-slate-700 font-bold">Menghubungkan ke Database...</p>
      </div>
    );
  }

  if (view === 'LOGIN') {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
        <div className="bg-white p-8 rounded-2xl shadow-xl max-w-md w-full border border-slate-200">
          <div className="text-center mb-8">
            <img src={LOGO_URL} alt="Logo PLN" className="h-16 mx-auto mb-4 object-contain" />
            <h2 className="text-sm font-bold text-slate-500 uppercase tracking-widest mb-1">PLN Electricity Services</h2>
            <h1 className="text-lg font-extrabold text-slate-800 mb-6 uppercase tracking-tight">Unit Layanan Bukittinggi</h1>
            <img src={APP_LOGO} alt="Logo App" className="h-48 mx-auto object-contain mb-6 hover:scale-110 transition-transform" />
            <h2 className="text-2xl font-bold text-primary mb-2 uppercase">Yandal Patrol Monitoring</h2>
          </div>
          <div className="space-y-4">
            <button onClick={() => handleInitialRoleSelect(UserRole.USER)} className="w-full bg-primary hover:bg-cyan-800 text-white font-black py-4 rounded-2xl transition-all shadow-lg text-xs uppercase tracking-widest">Login Petugas</button>
            {!showAdminLogin ? (
              <>
                <button onClick={() => setShowAdminLogin(true)} className="w-full bg-slate-800 hover:bg-slate-900 text-white font-black py-4 rounded-2xl text-xs uppercase tracking-widest">Login Admin</button>
                <button onClick={() => handleInitialRoleSelect(UserRole.GUEST)} className="w-full bg-white border-2 border-slate-200 hover:border-primary text-slate-600 font-black py-4 rounded-2xl text-xs uppercase tracking-widest">Tampilkan Data</button>
              </>
            ) : (
              <form onSubmit={handleAdminLoginSubmit} className="bg-slate-50 p-5 rounded-2xl border border-slate-200 animate-fade-in">
                <input type="password" autoFocus className="w-full px-4 py-3 border rounded-xl mb-3 outline-none" value={adminPassword} onChange={(e) => setAdminPassword(e.target.value)} placeholder="Password Admin..." />
                <div className="flex gap-2">
                  <button type="button" onClick={() => setShowAdminLogin(false)} className="flex-1 py-3 text-xs font-bold text-slate-600 bg-white border border-slate-300 rounded-xl">Batal</button>
                  <button type="submit" className="flex-1 py-3 text-xs font-black bg-slate-800 text-white rounded-xl">Masuk</button>
                </div>
              </form>
            )}
          </div>
        </div>
      </div>
    );
  }

  if (view === 'CONFIG' && role) {
    return <LoginConfig role={role} masterData={masterData} appLogo={APP_LOGO} onBack={() => { setView('LOGIN'); setRole(null); }} onConfirm={handleConfigConfirm} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {isSyncing && (
        <div className="fixed top-4 right-4 z-50 bg-white shadow-xl rounded-full px-5 py-2.5 flex items-center gap-2 border border-slate-200 animate-fade-in">
          <div className="animate-spin h-4 w-4 border-2 border-primary border-t-transparent rounded-full"></div>
          <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest">Memproses...</span>
        </div>
      )}

      <header className="bg-white shadow-sm z-20 sticky top-0">
        <div className="max-w-7xl mx-auto px-4 h-16 flex justify-between items-center">
            <div className="flex items-center gap-4">
               <button onClick={handleBackToMenu} className="p-2 hover:bg-slate-100 rounded-full transition-all text-slate-600 group flex items-center gap-1">
                 <svg className="w-5 h-5 group-hover:-translate-x-1 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
                 <span className="hidden sm:inline text-[10px] font-black uppercase tracking-widest">Kembali</span>
               </button>
               <div className="w-px h-8 bg-slate-200"></div>
               <div className="flex items-center gap-2 cursor-pointer" onClick={() => setView('ABOUT')}>
                 <img src={APP_LOGO} alt="App" className="h-8 object-contain" />
                 <div className="flex flex-col leading-none">
                   <span className="font-black text-sm text-slate-800 tracking-tight">Yandal Patrol</span>
                   <span className="text-[9px] text-primary font-black uppercase tracking-widest">{session.ulp || 'UP3 BUKITTINGGI'}</span>
                 </div>
               </div>
            </div>
            <button onClick={handleLogout} className="text-[10px] text-red-600 font-black px-4 py-2 rounded-xl hover:bg-red-50 uppercase tracking-widest">Logout</button>
        </div>
        <div className="max-w-7xl mx-auto px-4">
          <nav className="-mb-px flex space-x-8 overflow-x-auto no-scrollbar">
            {role === UserRole.ADMIN && (
              <>
                <button onClick={() => setView('DASHBOARD')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'DASHBOARD' ? 'border-primary text-primary' : 'border-transparent text-slate-400 hover:text-slate-600'}`}>Dashboard</button>
                <button onClick={() => setView('REKAP')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'REKAP' ? 'border-primary text-primary' : 'border-transparent text-slate-400 hover:text-slate-600'}`}>Rekap Petugas</button>
                <button onClick={() => setView('SETTINGS')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'SETTINGS' ? 'border-primary text-primary' : 'border-transparent text-slate-400 hover:text-slate-600'}`}>Kelola Data</button>
              </>
            )}
            {role === UserRole.USER && <button onClick={() => setView('INPUT')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'INPUT' ? 'border-primary text-primary' : 'border-transparent text-slate-400 hover:text-slate-600'}`}>Input Data</button>}
            <button onClick={() => setView('TABLE')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'TABLE' ? 'border-primary text-primary' : 'border-transparent text-slate-400 hover:text-slate-600'}`}>Data Laporan</button>
            <button onClick={() => setView('ABOUT')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'ABOUT' ? 'border-primary text-primary' : 'border-transparent text-slate-400 hover:text-slate-600'}`}>Tentang</button>
          </nav>
        </div>
      </header>

      <main className="flex-1 max-w-7xl w-full mx-auto px-4 py-8">
        {view === 'DASHBOARD' && <Dashboard reports={filteredReportsForTable.filter(r => !session.ulp || r.ulp === session.ulp)} />}
        {view === 'REKAP' && role === UserRole.ADMIN && <AdminRekap reports={reports} masterData={masterData} />}
        {view === 'SETTINGS' && role === UserRole.ADMIN && (
          <AdminSettings 
            masterData={masterData}
            onAddPetugas={(ulp, names) => { const nd = {...masterData, [ulp]: {...masterData[ulp], petugas: [...masterData[ulp].petugas, ...names]}}; setMasterData(nd); if(!isDemoMode) api.updateMasterData(nd); }}
            onDeletePetugas={(ulp, n) => { const nd = {...masterData, [ulp]: {...masterData[ulp], petugas: masterData[ulp].petugas.filter(p => p !== n)}}; setMasterData(nd); if(!isDemoMode) api.updateMasterData(nd); }}
            onAddPenyulang={(ulp, names) => { const nd = {...masterData, [ulp]: {...masterData[ulp], penyulang: [...masterData[ulp].penyulang, ...names]}}; setMasterData(nd); if(!isDemoMode) api.updateMasterData(nd); }}
            onDeletePenyulang={(ulp, n) => { const nd = {...masterData, [ulp]: {...masterData[ulp], penyulang: masterData[ulp].penyulang.filter(p => p !== n)}}; setMasterData(nd); if(!isDemoMode) api.updateMasterData(nd); }}
            onAddKeypoint={(ulp, penyulang, kps) => {
              const nd = { ...masterData };
              if (!nd[ulp].keypoints) nd[ulp].keypoints = {};
              if (!nd[ulp].keypoints[penyulang]) nd[ulp].keypoints[penyulang] = [];
              nd[ulp].keypoints[penyulang] = [...new Set([...nd[ulp].keypoints[penyulang], ...kps])];
              setMasterData(nd); if(!isDemoMode) api.updateMasterData(nd);
            }}
            onDeleteKeypoint={(ulp, penyulang, kp) => {
              const nd = { ...masterData };
              if (nd[ulp].keypoints?.[penyulang]) nd[ulp].keypoints[penyulang] = nd[ulp].keypoints[penyulang].filter(item => item !== kp);
              setMasterData(nd); if(!isDemoMode) api.updateMasterData(nd);
            }}
          />
        )}
        {view === 'INPUT' && role !== UserRole.GUEST && <InputForm key={editingReport?.id || 'new-report'} onSubmit={handleSaveReport} onCancel={() => setView('TABLE')} masterData={masterData} sessionData={session} editData={editingReport} />}
        {view === 'TABLE' && (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <h2 className="text-2xl font-black text-slate-800 uppercase">Riwayat Penugasan</h2>
              <div className="flex gap-2">
                <button onClick={() => fetchData(true)} className="p-2.5 bg-slate-200 rounded-2xl hover:bg-slate-300 transition-all"><svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg></button>
                {role === UserRole.USER && <button onClick={() => setView('INPUT')} className="bg-primary text-white px-5 py-2.5 rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-lg">Tambah Laporan</button>}
              </div>
            </div>
            <div className="bg-white p-5 rounded-2xl shadow-sm border border-slate-200 grid grid-cols-1 md:grid-cols-5 gap-5 items-end">
              <input type="date" className="w-full px-4 py-2.5 border rounded-xl text-xs font-bold" value={tableStartDate} onChange={(e) => setTableStartDate(e.target.value)} placeholder="Mulai" />
              <input type="date" className="w-full px-4 py-2.5 border rounded-xl text-xs font-bold" value={tableEndDate} onChange={(e) => setTableEndDate(e.target.value)} placeholder="Selesai" />
              {(role === UserRole.ADMIN || (role === UserRole.GUEST && !session.ulp)) && (
                <select className="w-full px-4 py-2.5 border rounded-xl text-xs font-bold bg-white" value={tableUlpFilter} onChange={(e) => setTableUlpFilter(e.target.value as ULPName)}>
                  <option value="">Semua ULP</option>
                  {Object.values(ULPName).map(u => <option key={u} value={u}>{u}</option>)}
                </select>
              )}
              <button onClick={() => { setTableStartDate(initStart); setTableEndDate(initEnd); setTableUlpFilter(''); }} className="w-full py-2.5 px-4 bg-slate-50 text-slate-400 font-black rounded-xl text-[10px] uppercase border transition-all">Reset</button>
              {role === UserRole.ADMIN && <button onClick={handleDownloadExcel} className="w-full py-2.5 px-4 bg-green-600 text-white font-black rounded-xl text-[10px] uppercase shadow-lg">Export Excel LENGKAP</button>}
            </div>
            <DataTable reports={filteredReportsForTable} onEdit={role !== UserRole.GUEST ? openEditForm : undefined} />
          </div>
        )}
        {view === 'ABOUT' && (
          <div className="max-w-3xl mx-auto animate-fade-in space-y-6">
            <div className="bg-white rounded-[2rem] shadow-xl overflow-hidden border border-slate-200">
               <div className="bg-primary p-12 text-white text-center flex flex-col items-center">
                  <img src={APP_LOGO} alt="App" className="h-36 w-auto object-contain z-10 mb-6" />
                  <h1 className="text-4xl font-black mb-1 uppercase">Yandal Patrol Monitoring</h1>
                  <span className="text-[10px] font-black uppercase tracking-[0.3em] bg-white/20 px-4 py-1.5 rounded-full mt-3">Version {APP_VERSION}</span>
               </div>
               <div className="p-10 space-y-10">
                  <section className="text-center space-y-4">
                    <h2 className="text-xl font-black text-slate-800 uppercase">Status Sistem Notifikasi</h2>
                    <div className="flex flex-col items-center gap-4">
                      <div className={`px-6 py-3 rounded-2xl flex items-center gap-3 border ${notifPermission === 'granted' ? 'bg-green-50 border-green-200 text-green-700' : notifPermission === 'denied' ? 'bg-red-50 border-red-200 text-red-700' : 'bg-slate-50 border-slate-200 text-slate-500'}`}>
                        <div className={`w-3 h-3 rounded-full ${notifPermission === 'granted' ? 'bg-green-500 animate-pulse' : notifPermission === 'denied' ? 'bg-red-500' : 'bg-slate-400'}`}></div>
                        <span className="text-sm font-black uppercase tracking-widest">
                          Izin Notifikasi: {notifPermission === 'granted' ? 'Aktif' : notifPermission === 'denied' ? 'Diblokir' : 'Belum Diizinkan'}
                        </span>
                      </div>
                      <button onClick={handleTestNotification} className="bg-primary text-white px-8 py-3 rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-lg hover:bg-cyan-800 active:scale-95 transition-all">Test Notifikasi & Badge</button>
                      <p className="text-[10px] text-slate-400 font-bold uppercase max-w-sm">Notifikasi memungkinkan Anda menerima update laporan terbaru meskipun aplikasi sedang ditutup.</p>
                    </div>
                  </section>
                  <div className="pt-10 border-t border-slate-100 flex flex-col items-center gap-2">
                    <p className="text-base font-black text-slate-800 uppercase">PLN Electricity Services Bukittinggi</p>
                    <p className="text-[11px] text-slate-400 font-bold uppercase">© 2025 • IT Unit Layanan Bukittinggi</p>
                  </div>
               </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { UserRole, ViewState, ReportData, ULPName, ULPData, LoginSession } from './types';
import { InputForm } from './components/InputForm';
import { Dashboard } from './components/Dashboard';
import { DataTable } from './components/DataTable';
import { AdminSettings } from './components/AdminSettings';
import { AdminRekap } from './components/AdminRekap';
import { LoginConfig } from './components/LoginConfig';
import { DATA_ULP as INITIAL_DATA_ULP, APP_VERSION } from './constants';
import { api } from './services/api';

const LOGO_URL = "https://plnes.co.id/_next/image?url=https%3A%2F%2Fcms.plnes.co.id%2Fuploads%2FLogo_HP_New_Temporary_09a9c5a521.png&w=750&q=75"; 
const APP_LOGO = "https://raw.githubusercontent.com/plnesbukittinggi-ai/yandal_patrol/main/ChatGPT%20Image%2018%20Des%202025%2C%2011.11.52.png";
const NOTIFICATION_SOUND = "https://assets.mixkit.co/active_storage/sfx/2869/2869-preview.mp3";

declare global {
  interface Window {
    ExcelJS: any;
  }
}

const App: React.FC = () => {
  const getCurrentMonthRange = () => {
    const now = new Date();
    const firstDay = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
    const lastDay = new Date(now.getFullYear(), now.getMonth() + 1, 0).toISOString().split('T')[0];
    return { firstDay, lastDay };
  };

  const { firstDay: initStart, lastDay: initEnd } = getCurrentMonthRange();

  const [role, setRole] = useState<UserRole | null>(null);
  const [view, setView] = useState<ViewState>('LOGIN');
  const [isLoading, setIsLoading] = useState(false);
  const [errorLoad, setErrorLoad] = useState<string | null>(null);
  const [isDemoMode, setIsDemoMode] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [notifPermission, setNotifPermission] = useState<NotificationPermission>('default');

  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [adminPassword, setAdminPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  const [session, setSession] = useState<LoginSession>({ ulp: null, petugas1: null, petugas2: null });

  const [tableStartDate, setTableStartDate] = useState(initStart);
  const [tableEndDate, setTableEndDate] = useState(initEnd);
  const [tableUlpFilter, setTableUlpFilter] = useState<ULPName | ''>('');

  const [reports, setReports] = useState<ReportData[]>([]);
  const [masterData, setMasterData] = useState<Record<string, ULPData>>(INITIAL_DATA_ULP);
  const [editingReport, setEditingReport] = useState<ReportData | null>(null);

  const pendingUpdatesRef = useRef<Map<string, string>>(new Map());
  const lastReportIdRef = useRef<string | null>(null);
  const lastPeriodicNotifyRef = useRef<number>(0);

  const requestNotificationPermission = async () => {
    if ('Notification' in window) {
      const permission = await Notification.requestPermission();
      setNotifPermission(permission);
      return permission;
    }
    return 'denied';
  };

  const playNotificationSound = () => {
    const audio = new Audio(NOTIFICATION_SOUND);
    audio.play().catch(e => console.log("Audio play blocked by browser policy"));
  };

  const updateAppBadge = (count: number) => {
    if ('setAppBadge' in navigator) {
      const nav = navigator as any;
      if (count > 0) {
        nav.setAppBadge(count).catch(() => {});
      } else {
        nav.clearAppBadge().catch(() => {});
      }
    }
  };

  const sendBrowserNotification = (title: string, body: string) => {
    if (!('Notification' in window)) return;
    if (Notification.permission === 'granted') {
      playNotificationSound();
      if ('serviceWorker' in navigator) {
        navigator.serviceWorker.ready.then(registration => {
          registration.showNotification(title, {
            body, icon: APP_LOGO, badge: APP_LOGO, tag: 'yandal-patrol-notif',
            renotify: true, vibrate: [200, 100, 200], data: { url: window.location.origin }
          } as any);
        });
      } else {
        new Notification(title, { body, icon: APP_LOGO });
      }
    }
  };

  const handleTestNotification = async () => {
    const perm = await requestNotificationPermission();
    if (perm === 'granted') {
      sendBrowserNotification("Tes Notifikasi Berhasil", "Notifikasi Yandal Patrol aktif di perangkat ini.");
      updateAppBadge(5);
      setTimeout(() => updateAppBadge(0), 5000);
    } else {
      alert("Izin notifikasi ditolak.");
    }
  };

  const generateSummaryMessage = (currentReports: ReportData[]) => {
    const today = new Date().toISOString().split('T')[0];
    const todayReports = currentReports.filter(r => r.timestamp.startsWith(today));
    const counts: Record<string, number> = {};
    Object.values(ULPName).forEach(name => {
      counts[name] = todayReports.filter(r => r.ulp === name).length;
    });
    const dateStr = new Date().toLocaleDateString('id-ID', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });
    let message = `Laporan Yandal Patrol Hari ini : ${dateStr}\n`;
    message += `- ULP Bukittinggi : ${counts[ULPName.BUKITTINGGI] || 0}\n`;
    message += `- ULP Padang Panjang : ${counts[ULPName.PADANG_PANJANG] || 0}\n`;
    message += `- ULP Lubuk Sikaping : ${counts[ULPName.LUBUK_SIKAPING] || 0}\n`;
    message += `- ULP Lubuk Basung : ${counts[ULPName.LUBUK_BASUNG] || 0}\n`;
    message += `- ULP Simpang Empat : ${counts[ULPName.SIMPANG_EMPAT] || 0}\n`;
    message += `- ULP Baso : ${counts[ULPName.BASO] || 0}\n`;
    message += `- ULP Koto Tuo : ${counts[ULPName.KOTO_TUO] || 0}\n`;
    message += `\nMohon untuk ULP yang belum lapor untuk segera melaksanakannya.`;
    return { message, totalToday: todayReports.length };
  };

  const checkPeriodicNotification = (currentReports: ReportData[]) => {
    const now = new Date();
    const currentHour = now.getHours();
    if (currentHour >= 10 && currentHour <= 18) {
      if (currentHour % 2 === 0 && lastPeriodicNotifyRef.current !== currentHour) {
        lastPeriodicNotifyRef.current = currentHour;
        const { message, totalToday } = generateSummaryMessage(currentReports);
        sendBrowserNotification("Update Berkala Yandal Patrol", message);
        updateAppBadge(totalToday);
      }
    }
  };

  useEffect(() => {
    if ('Notification' in window) {
      setNotifPermission(Notification.permission);
      if (Notification.permission === 'default') requestNotificationPermission();
    }
    const savedDemo = localStorage.getItem('yandal_demo_mode');
    if (savedDemo === 'true') {
      setIsDemoMode(true);
      const savedReports = localStorage.getItem('yandal_local_reports');
      if (savedReports) setReports(JSON.parse(savedReports));
    }
    fetchData(true);
    const poller = setInterval(() => fetchData(false), 120000);
    return () => clearInterval(poller);
  }, []);

  useEffect(() => {
    if (view === 'TABLE' && !isDemoMode) fetchData(false);
  }, [tableStartDate, tableEndDate, tableUlpFilter, view]);

  const fetchData = async (showLoading = true) => {
    if (isDemoMode) return;
    if (showLoading) { setIsLoading(true); setErrorLoad(null); }
    try {
      const data = await api.getAllData();
      if (data && data.reports) {
        const serverReports = data.reports as ReportData[];
        if (serverReports.length > 0) {
          const sorted = [...serverReports].sort((a,b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
          const latest = sorted[0];
          if (lastReportIdRef.current && latest.id !== lastReportIdRef.current) {
            const { message, totalToday } = generateSummaryMessage(serverReports);
            sendBrowserNotification("Input Laporan Patrol Baru!", `Oleh: ${latest.petugas1} (${latest.ulp})\n\n${message}`);
            updateAppBadge(totalToday);
          }
          lastReportIdRef.current = latest.id;
        }
        checkPeriodicNotification(serverReports);
        setReports(prevReports => {
          const reportMap = new Map<string, ReportData>();
          prevReports.forEach(r => reportMap.set(r.id, r));
          serverReports.forEach((serverReport: ReportData) => {
            const pendingTimestamp = pendingUpdatesRef.current.get(serverReport.id);
            if (pendingTimestamp && new Date(serverReport.timestamp) < new Date(pendingTimestamp)) return; 
            reportMap.set(serverReport.id, serverReport);
          });
          return Array.from(reportMap.values());
        });
        if (data.masterData) {
            const updatedMaster = { ...data.masterData };
            Object.keys(updatedMaster).forEach(k => { if (!updatedMaster[k].keypoints) updatedMaster[k].keypoints = {}; });
            setMasterData(updatedMaster);
        }
      }
    } catch (error: any) {
      if (showLoading) setErrorLoad(error.message || "Gagal terhubung ke database.");
    } finally {
      if (showLoading) setIsLoading(false);
    }
  };

  const handleInitialRoleSelect = (selectedRole: UserRole) => {
    setRole(selectedRole);
    if (selectedRole === UserRole.ADMIN) return; 
    setView('CONFIG');
  };

  const handleAdminLoginSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminPassword === 'Adminbkt') {
      setRole(UserRole.ADMIN);
      setView('DASHBOARD');
      setShowAdminLogin(false);
    } else {
      setLoginError('Password salah!');
    }
  };

  const handleConfigConfirm = (conf: LoginSession) => {
    setSession(conf);
    setView(role === UserRole.GUEST ? 'TABLE' : 'INPUT');
  };

  const handleLogout = () => {
    setRole(null);
    setView('LOGIN');
    setShowAdminLogin(false);
    setSession({ ulp: null, petugas1: null, petugas2: null });
    setEditingReport(null);
    updateAppBadge(0);
  };

  const handleBackToMenu = () => {
     if (view === 'CONFIG') { setView('LOGIN'); setRole(null); }
     else { if (role === UserRole.ADMIN) setView('DASHBOARD'); else { setView('LOGIN'); setRole(null); } }
     setEditingReport(null);
  };

  const handleSaveReport = async (data: ReportData, isEditMode: boolean) => {
    setIsSyncing(true);
    pendingUpdatesRef.current.set(data.id, data.timestamp);
    setReports(prev => [data, ...prev.filter(r => r.id !== data.id)]);
    try {
      if (isDemoMode) {
        localStorage.setItem('yandal_local_reports', JSON.stringify([data, ...reports.filter(r => r.id !== data.id)]));
      } else {
        await api.saveReport(data, isEditMode);
        setTimeout(() => { fetchData(false); pendingUpdatesRef.current.delete(data.id); }, 8000);
      }
      setEditingReport(null);
      setView('TABLE');
    } catch (e) {
      alert("Gagal sinkronisasi otomatis.");
    } finally {
      setIsSyncing(false);
    }
  };

  const openEditForm = (report: ReportData) => {
    setEditingReport(report);
    setView('INPUT');
  };

  const filteredReportsForTable = useMemo(() => {
    const uniqueMap = new Map<string, ReportData>();
    [...reports].sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime())
      .forEach(r => uniqueMap.set(r.id, r));

    return Array.from(uniqueMap.values())
      .filter(r => {
        if (session.ulp && r.ulp !== session.ulp) return false;
        if (role === UserRole.ADMIN && tableUlpFilter && r.ulp !== tableUlpFilter) return false;
        const reportDate = new Date(r.timestamp).toISOString().split('T')[0];
        if (tableStartDate && reportDate < tableStartDate) return false;
        if (tableEndDate && reportDate > tableEndDate) return false;
        return true;
      })
      .sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
  }, [reports, session.ulp, role, tableUlpFilter, tableStartDate, tableEndDate]);

  const handleDownloadExcel = async () => {
    const ExcelJS = (window as any).ExcelJS;
    if (!ExcelJS) return alert("Library ExcelJS tidak tersedia. Periksa koneksi internet.");

    setIsSyncing(true);
    try {
      const workbook = new ExcelJS.Workbook();
      const worksheet = workbook.addWorksheet('Laporan Patrol');

      const columns = [
        { header: 'No', key: 'no', width: 6 },
        { header: 'Tanggal', key: 'tanggal', width: 15 },
        { header: 'No. Penugasan', key: 'noPenugasan', width: 20 },
        { header: 'Unit (ULP)', key: 'ulp', width: 18 },
        { header: 'Petugas 1', key: 'petugas1', width: 18 },
        { header: 'Petugas 2', key: 'petugas2', width: 18 },
        { header: 'Penyulang', key: 'penyulang', width: 15 },
        { header: 'Keypoint', key: 'keypoint', width: 22 },
        { header: 'Titik Start', key: 'start', width: 25 },
        { header: 'Titik Finish', key: 'finish', width: 25 },
        ...Array(6).fill(0).map((_, i) => ({ header: `Foto Sblm ${i+1}`, key: `sblm${i+1}`, width: 25 })),
        ...Array(6).fill(0).map((_, i) => ({ header: `Foto Ssdh ${i+1}`, key: `ssdh${i+1}`, width: 25 })),
      ];
      worksheet.columns = columns;

      const headerRow = worksheet.getRow(1);
      headerRow.font = { bold: true, color: { argb: 'FFFFFFFF' } };
      headerRow.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FF0E7490' } };
      headerRow.alignment = { vertical: 'middle', horizontal: 'center' };

      for (let i = 0; i < filteredReportsForTable.length; i++) {
        const r = filteredReportsForTable[i];
        const rowIndex = i + 2;
        const currentRow = worksheet.getRow(rowIndex);
        currentRow.height = 120; // Tinggi baris untuk foto

        currentRow.values = [
          i + 1,
          new Date(r.timestamp).toLocaleDateString('id-ID'),
          r.noPenugasan,
          r.ulp,
          r.petugas1,
          r.petugas2,
          r.penyulang,
          r.keypoint,
          r.titikStart,
          r.titikFinish,
          ...Array(12).fill('')
        ];
        currentRow.alignment = { vertical: 'middle', horizontal: 'center', wrapText: true };

        const addImageToCell = (imageData: string | null, colIndex: number) => {
          if (!imageData || !imageData.startsWith('data:image')) return;
          try {
            const matches = imageData.match(/^data:image\/([a-zA-Z+]+);base64,(.+)$/);
            if (!matches) return;
            const ext = matches[1].replace('jpeg', 'jpg');
            const imageId = workbook.addImage({
              base64: matches[2],
              extension: ext as any,
            });
            worksheet.addImage(imageId, {
              tl: { col: colIndex - 1, row: rowIndex - 1 },
              br: { col: colIndex, row: rowIndex },
              editAs: 'oneCell'
            });
          } catch (e) {
            console.warn("Gagal menyematkan foto:", e);
          }
        };

        r.photos.sebelum.forEach((photo, pIdx) => { if (photo) addImageToCell(photo, 11 + pIdx); });
        r.photos.sesudah.forEach((photo, pIdx) => { if (photo) addImageToCell(photo, 17 + pIdx); });
      }

      worksheet.eachRow((row) => {
        row.eachCell((cell) => {
          cell.border = { top: { style: 'thin' }, left: { style: 'thin' }, bottom: { style: 'thin' }, right: { style: 'thin' } };
        });
      });

      const buffer = await workbook.xlsx.writeBuffer();
      const blob = new Blob([buffer], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' });
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `Laporan_Patrol_Lengkap_${new Date().toISOString().split('T')[0]}.xlsx`;
      a.click();
      window.URL.revokeObjectURL(url);
    } catch (err: any) {
      alert("Gagal ekspor Excel: " + err.message);
    } finally {
      setIsSyncing(false);
    }
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50 gap-4 p-4 text-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary"></div>
        <p className="text-slate-700 font-bold">Menghubungkan ke Database...</p>
      </div>
    );
  }

  if (view === 'LOGIN') {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
        <div className="bg-white p-8 rounded-2xl shadow-xl max-w-md w-full border border-slate-200">
          <div className="text-center mb-8">
            <img src={LOGO_URL} alt="Logo PLN" className="h-16 mx-auto mb-4 object-contain" />
            <h2 className="text-sm font-bold text-slate-500 uppercase tracking-widest mb-1">PLN Electricity Services</h2>
            <h1 className="text-lg font-extrabold text-slate-800 mb-6 uppercase tracking-tight">Unit Layanan Bukittinggi</h1>
            <img src={APP_LOGO} alt="Logo App" className="h-48 mx-auto object-contain mb-6 hover:scale-110 transition-transform" />
            <h2 className="text-2xl font-bold text-primary mb-2 uppercase">Yandal Patrol Monitoring</h2>
          </div>
          <div className="space-y-4">
            <button onClick={() => handleInitialRoleSelect(UserRole.USER)} className="w-full bg-primary hover:bg-cyan-800 text-white font-black py-4 rounded-2xl transition-all shadow-lg text-xs uppercase tracking-widest">Login Petugas</button>
            {!showAdminLogin ? (
              <>
                <button onClick={() => setShowAdminLogin(true)} className="w-full bg-slate-800 hover:bg-slate-900 text-white font-black py-4 rounded-2xl text-xs uppercase tracking-widest">Login Admin</button>
                <button onClick={() => handleInitialRoleSelect(UserRole.GUEST)} className="w-full bg-white border-2 border-slate-200 hover:border-primary text-slate-600 font-black py-4 rounded-2xl text-xs uppercase tracking-widest">Tampilkan Data</button>
              </>
            ) : (
              <form onSubmit={handleAdminLoginSubmit} className="bg-slate-50 p-5 rounded-2xl border border-slate-200 animate-fade-in">
                <input type="password" autoFocus className="w-full px-4 py-3 border rounded-xl mb-3 outline-none" value={adminPassword} onChange={(e) => setAdminPassword(e.target.value)} placeholder="Password Admin..." />
                <div className="flex gap-2">
                  <button type="button" onClick={() => setShowAdminLogin(false)} className="flex-1 py-3 text-xs font-bold text-slate-600 bg-white border border-slate-300 rounded-xl">Batal</button>
                  <button type="submit" className="flex-1 py-3 text-xs font-black bg-slate-800 text-white rounded-xl">Masuk</button>
                </div>
              </form>
            )}
          </div>
        </div>
      </div>
    );
  }

  if (view === 'CONFIG' && role) {
    return <LoginConfig role={role} masterData={masterData} appLogo={APP_LOGO} onBack={() => { setView('LOGIN'); setRole(null); }} onConfirm={handleConfigConfirm} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {isSyncing && (
        <div className="fixed top-4 right-4 z-50 bg-white shadow-xl rounded-full px-5 py-2.5 flex items-center gap-2 border border-slate-200 animate-fade-in">
          <div className="animate-spin h-4 w-4 border-2 border-primary border-t-transparent rounded-full"></div>
          <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest">Memproses...</span>
        </div>
      )}

      <header className="bg-white shadow-sm z-20 sticky top-0">
        <div className="max-w-7xl mx-auto px-4 h-16 flex justify-between items-center">
            <div className="flex items-center gap-4">
               <button onClick={handleBackToMenu} className="p-2 hover:bg-slate-100 rounded-full transition-all text-slate-600 group flex items-center gap-1">
                 <svg className="w-5 h-5 group-hover:-translate-x-1 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
                 <span className="hidden sm:inline text-[10px] font-black uppercase tracking-widest">Kembali</span>
               </button>
               <div className="w-px h-8 bg-slate-200"></div>
               <div className="flex items-center gap-2 cursor-pointer" onClick={() => setView('ABOUT')}>
                 <img src={APP_LOGO} alt="App" className="h-8 object-contain" />
                 <div className="flex flex-col leading-none">
                   <span className="font-black text-sm text-slate-800 tracking-tight">Yandal Patrol</span>
                   <span className="text-[9px] text-primary font-black uppercase tracking-widest">{session.ulp || 'UP3 BUKITTINGGI'}</span>
                 </div>
               </div>
            </div>
            <button onClick={handleLogout} className="text-[10px] text-red-600 font-black px-4 py-2 rounded-xl hover:bg-red-50 uppercase tracking-widest">Logout</button>
        </div>
        <div className="max-w-7xl mx-auto px-4">
          <nav className="-mb-px flex space-x-8 overflow-x-auto no-scrollbar">
            {role === UserRole.ADMIN && (
              <>
                <button onClick={() => setView('DASHBOARD')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'DASHBOARD' ? 'border-primary text-primary' : 'border-transparent text-slate-400 hover:text-slate-600'}`}>Dashboard</button>
                <button onClick={() => setView('REKAP')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'REKAP' ? 'border-primary text-primary' : 'border-transparent text-slate-400 hover:text-slate-600'}`}>Rekap Petugas</button>
                <button onClick={() => setView('SETTINGS')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'SETTINGS' ? 'border-primary text-primary' : 'border-transparent text-slate-400 hover:text-slate-600'}`}>Kelola Data</button>
              </>
            )}
            {role === UserRole.USER && <button onClick={() => setView('INPUT')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'INPUT' ? 'border-primary text-primary' : 'border-transparent text-slate-400 hover:text-slate-600'}`}>Input Data</button>}
            <button onClick={() => setView('TABLE')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'TABLE' ? 'border-primary text-primary' : 'border-transparent text-slate-400 hover:text-slate-600'}`}>Data Laporan</button>
            <button onClick={() => setView('ABOUT')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'ABOUT' ? 'border-primary text-primary' : 'border-transparent text-slate-400 hover:text-slate-600'}`}>Tentang</button>
          </nav>
        </div>
      </header>

      <main className="flex-1 max-w-7xl w-full mx-auto px-4 py-8">
        {view === 'DASHBOARD' && <Dashboard reports={filteredReportsForTable.filter(r => !session.ulp || r.ulp === session.ulp)} />}
        {view === 'REKAP' && role === UserRole.ADMIN && <AdminRekap reports={reports} masterData={masterData} />}
        {view === 'SETTINGS' && role === UserRole.ADMIN && (
          <AdminSettings 
            masterData={masterData}
            onAddPetugas={(ulp, names) => { const nd = {...masterData, [ulp]: {...masterData[ulp], petugas: [...masterData[ulp].petugas, ...names]}}; setMasterData(nd); if(!isDemoMode) api.updateMasterData(nd); }}
            onDeletePetugas={(ulp, n) => { const nd = {...masterData, [ulp]: {...masterData[ulp], petugas: masterData[ulp].petugas.filter(p => p !== n)}}; setMasterData(nd); if(!isDemoMode) api.updateMasterData(nd); }}
            onAddPenyulang={(ulp, names) => { const nd = {...masterData, [ulp]: {...masterData[ulp], penyulang: [...masterData[ulp].penyulang, ...names]}}; setMasterData(nd); if(!isDemoMode) api.updateMasterData(nd); }}
            onDeletePenyulang={(ulp, n) => { const nd = {...masterData, [ulp]: {...masterData[ulp], penyulang: masterData[ulp].penyulang.filter(p => p !== n)}}; setMasterData(nd); if(!isDemoMode) api.updateMasterData(nd); }}
            onAddKeypoint={(ulp, penyulang, kps) => {
              const nd = { ...masterData };
              if (!nd[ulp].keypoints) nd[ulp].keypoints = {};
              if (!nd[ulp].keypoints[penyulang]) nd[ulp].keypoints[penyulang] = [];
              nd[ulp].keypoints[penyulang] = [...new Set([...nd[ulp].keypoints[penyulang], ...kps])];
              setMasterData(nd); if(!isDemoMode) api.updateMasterData(nd);
            }}
            onDeleteKeypoint={(ulp, penyulang, kp) => {
              const nd = { ...masterData };
              if (nd[ulp].keypoints?.[penyulang]) nd[ulp].keypoints[penyulang] = nd[ulp].keypoints[penyulang].filter(item => item !== kp);
              setMasterData(nd); if(!isDemoMode) api.updateMasterData(nd);
            }}
          />
        )}
        {view === 'INPUT' && role !== UserRole.GUEST && <InputForm key={editingReport?.id || 'new-report'} onSubmit={handleSaveReport} onCancel={() => setView('TABLE')} masterData={masterData} sessionData={session} editData={editingReport} />}
        {view === 'TABLE' && (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <h2 className="text-2xl font-black text-slate-800 uppercase">Riwayat Penugasan</h2>
              <div className="flex gap-2">
                <button onClick={() => fetchData(true)} className="p-2.5 bg-slate-200 rounded-2xl hover:bg-slate-300 transition-all"><svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg></button>
                {role === UserRole.USER && <button onClick={() => setView('INPUT')} className="bg-primary text-white px-5 py-2.5 rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-lg">Tambah Laporan</button>}
              </div>
            </div>
            <div className="bg-white p-5 rounded-2xl shadow-sm border border-slate-200 grid grid-cols-1 md:grid-cols-5 gap-5 items-end">
              <input type="date" className="w-full px-4 py-2.5 border rounded-xl text-xs font-bold" value={tableStartDate} onChange={(e) => setTableStartDate(e.target.value)} />
              <input type="date" className="w-full px-4 py-2.5 border rounded-xl text-xs font-bold" value={tableEndDate} onChange={(e) => setTableEndDate(e.target.value)} />
              {(role === UserRole.ADMIN || (role === UserRole.GUEST && !session.ulp)) && (
                <select className="w-full px-4 py-2.5 border rounded-xl text-xs font-bold bg-white" value={tableUlpFilter} onChange={(e) => setTableUlpFilter(e.target.value as ULPName)}>
                  <option value="">Semua ULP</option>
                  {Object.values(ULPName).map(u => <option key={u} value={u}>{u}</option>)}
                </select>
              )}
              <button onClick={() => { setTableStartDate(initStart); setTableEndDate(initEnd); setTableUlpFilter(''); }} className="w-full py-2.5 px-4 bg-slate-50 text-slate-400 font-black rounded-xl text-[10px] uppercase border transition-all">Reset</button>
              {role === UserRole.ADMIN && <button onClick={handleDownloadExcel} className="w-full py-2.5 px-4 bg-green-600 text-white font-black rounded-xl text-[10px] uppercase shadow-lg">Export Excel LENGKAP</button>}
            </div>
            <DataTable reports={filteredReportsForTable} onEdit={role !== UserRole.GUEST ? openEditForm : undefined} />
          </div>
        )}
        {view === 'ABOUT' && (
          <div className="max-w-3xl mx-auto animate-fade-in space-y-6">
            <div className="bg-white rounded-[2rem] shadow-xl overflow-hidden border border-slate-200">
               <div className="bg-primary p-12 text-white text-center flex flex-col items-center">
                  <img src={APP_LOGO} alt="App" className="h-36 w-auto object-contain z-10 mb-6" />
                  <h1 className="text-4xl font-black mb-1 uppercase">Yandal Patrol Monitoring</h1>
                  <span className="text-[10px] font-black uppercase tracking-[0.3em] bg-white/20 px-4 py-1.5 rounded-full mt-3">Version {APP_VERSION}</span>
               </div>
               <div className="p-10 space-y-10">
                  <section className="text-center space-y-4">
                    <h2 className="text-xl font-black text-slate-800 uppercase">Status Sistem Notifikasi</h2>
                    <div className="flex flex-col items-center gap-4">
                      <div className={`px-6 py-3 rounded-2xl flex items-center gap-3 border ${notifPermission === 'granted' ? 'bg-green-50 border-green-200 text-green-700' : notifPermission === 'denied' ? 'bg-red-50 border-red-200 text-red-700' : 'bg-slate-50 border-slate-200 text-slate-500'}`}>
                        <div className={`w-3 h-3 rounded-full ${notifPermission === 'granted' ? 'bg-green-500 animate-pulse' : notifPermission === 'denied' ? 'bg-red-500' : 'bg-slate-400'}`}></div>
                        <span className="text-sm font-black uppercase tracking-widest">
                          Izin Notifikasi: {notifPermission === 'granted' ? 'Aktif' : notifPermission === 'denied' ? 'Diblokir' : 'Belum Diizinkan'}
                        </span>
                      </div>
                      <button onClick={handleTestNotification} className="bg-primary text-white px-8 py-3 rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-lg hover:bg-cyan-800 active:scale-95 transition-all">Test Notifikasi & Badge</button>
                    </div>
                  </section>
                  <div className="pt-10 border-t border-slate-100 flex flex-col items-center gap-2">
                    <p className="text-base font-black text-slate-800 uppercase">PLN Electricity Services Bukittinggi</p>
                    <p className="text-[11px] text-slate-400 font-bold uppercase">© 2025 • IT Unit Layanan Bukittinggi</p>
                  </div>
               </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

export enum UserRole {
  ADMIN = 'ADMIN',
  USER = 'USER',
  GUEST = 'GUEST'
}

export enum ULPName {
  BUKITTINGGI = 'ULP Bukittinggi',
  PADANG_PANJANG = 'ULP Padang Panjang',
  LUBUK_SIKAPING = 'ULP Lubuk Sikaping',
  LUBUK_BASUNG = 'ULP Lubuk Basung',
  SIMPANG_EMPAT = 'ULP Simpang Empat',
  BASO = 'ULP Baso',
  KOTO_TUO = 'ULP Koto Tuo'
}

export interface ReportData {
  id: string;
  timestamp: string; // ISO String
  bulan: string; // Month name
  noPenugasan: string;
  ulp: ULPName;
  petugas1: string;
  petugas2: string;
  penyulang: string;
  keypoint: string;
  titikStart: string;
  titikFinish: string;
  photos: {
    sebelum: (string | null)[]; // Array of 6 URLs/Base64
    sesudah: (string | null)[]; // Array of 6 URLs/Base64
  };
}

export interface ULPData {
  name: ULPName;
  petugas: string[];
  penyulang: string[];
  keypoints: Record<string, string[]>; // Map: Penyulang Name -> Array of Keypoints
}

export interface LoginSession {
  ulp: ULPName | null;
  petugas1: string | null;
  petugas2: string | null;
}

export type ViewState = 'LOGIN' | 'CONFIG' | 'DASHBOARD' | 'INPUT' | 'TABLE' | 'SETTINGS' | 'ABOUT' | 'REKAP' | 'UPDATE_LIST' | 'UPDATE_FORM';

import React from 'react';
import { ReportData, LoginSession } from '../types';

interface UpdateListProps {
  reports: ReportData[];
  session: LoginSession;
  onUpdate: (report: ReportData) => void;
}

export const UpdateList: React.FC<UpdateListProps> = ({ reports, session, onUpdate }) => {
  const today = new Date().toISOString().split('T')[0];

  const incompleteReports = reports.filter(r => {
    // Filter hari ini, ULP sesuai session, dan petugas sesuai session
    const isToday = r.timestamp.startsWith(today);
    const isSameUlp = r.ulp === session.ulp;
    const isSamePetugas = (r.petugas1 === session.petugas1 && r.petugas2 === session.petugas2);

    if (!isToday || !isSameUlp || !isSamePetugas) return false;

    // Cek jika ada foto yang masih null (belum lengkap 6 sebelum & 6 sesudah)
    const isBeforeIncomplete = r.photos.sebelum.some(p => p === null);
    const isAfterIncomplete = r.photos.sesudah.some(p => p === null);

    return isBeforeIncomplete || isAfterIncomplete;
  });

  if (incompleteReports.length === 0) {
    return (
      <div className="bg-white p-12 text-center rounded-[2rem] shadow-sm border border-slate-200 animate-fade-in">
        <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4 border border-slate-100">
          <svg className="w-8 h-8 text-slate-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
          </svg>
        </div>
        <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest">Semua laporan hari ini sudah lengkap</h3>
        <p className="text-[10px] text-slate-400 mt-2 font-bold uppercase tracking-widest">Tidak ada data foto yang perlu diupdate.</p>
      </div>
    );
  }

  return (
    <div className="space-y-4 animate-fade-in">
      <div className="flex items-center justify-between mb-2">
        <h3 className="text-lg font-black text-slate-800 uppercase tracking-tight">Laporan Belum Lengkap Hari Ini</h3>
        <span className="px-3 py-1 bg-amber-50 text-amber-600 rounded-full border border-amber-100 text-[10px] font-black uppercase tracking-widest">
          {incompleteReports.length} Laporan
        </span>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {incompleteReports.map(report => (
          <div key={report.id} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 hover:shadow-md transition-all group">
            <div className="flex justify-between items-start mb-4">
              <div>
                <div className="text-[10px] font-black text-primary uppercase tracking-widest mb-1">{report.noPenugasan}</div>
                <h4 className="font-black text-slate-800 text-sm uppercase tracking-tight">{report.penyulang} - {report.keypoint}</h4>
              </div>
              <button 
                onClick={() => onUpdate(report)}
                className="bg-primary text-white px-4 py-2 rounded-xl font-black text-[9px] uppercase tracking-widest shadow-lg shadow-cyan-100 hover:bg-cyan-800 transition-all active:scale-95"
              >
                Update Data Foto
              </button>
            </div>

            <div className="grid grid-cols-2 gap-4 pt-4 border-t border-slate-50">
              <div className="space-y-1">
                <div className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Foto Sebelum</div>
                <div className="flex items-center gap-1">
                  <div className="flex-1 h-1.5 bg-slate-100 rounded-full overflow-hidden">
                    <div 
                      className="h-full bg-amber-400" 
                      style={{ width: `${(report.photos.sebelum.filter(p => p !== null).length / 6) * 100}%` }}
                    ></div>
                  </div>
                  <span className="text-[9px] font-black text-slate-500">{report.photos.sebelum.filter(p => p !== null).length}/6</span>
                </div>
              </div>
              <div className="space-y-1">
                <div className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Foto Sesudah</div>
                <div className="flex items-center gap-1">
                  <div className="flex-1 h-1.5 bg-slate-100 rounded-full overflow-hidden">
                    <div 
                      className="h-full bg-cyan-400" 
                      style={{ width: `${(report.photos.sesudah.filter(p => p !== null).length / 6) * 100}%` }}
                    ></div>
                  </div>
                  <span className="text-[9px] font-black text-slate-500">{report.photos.sesudah.filter(p => p !== null).length}/6</span>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { ReportData } from '../types';
import { PhotoUpload } from './PhotoUpload';
import { PHOTO_SECTIONS } from '../constants';

interface UpdatePhotoFormProps {
  report: ReportData;
  onSubmit: (data: ReportData, isEdit: boolean) => Promise<void> | void;
  onCancel: () => void;
}

export const UpdatePhotoForm: React.FC<UpdatePhotoFormProps> = ({ report, onSubmit, onCancel }) => {
  const [photosSebelum, setPhotosSebelum] = useState<(string | null)[]>(report.photos.sebelum);
  const [photosSesudah, setPhotosSesudah] = useState<(string | null)[]>(report.photos.sesudah);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const resizeImage = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = (event) => {
        const img = new Image();
        img.src = event.target?.result as string;
        img.onload = () => {
          const canvas = document.createElement('canvas');
          const MAX_WIDTH = 400; 
          const scaleSize = MAX_WIDTH / img.width;
          canvas.width = MAX_WIDTH;
          canvas.height = img.height * scaleSize;
          const ctx = canvas.getContext('2d');
          if (ctx) {
            ctx.imageSmoothingEnabled = true;
            ctx.imageSmoothingQuality = 'medium';
            ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
          }
          resolve(canvas.toDataURL('image/jpeg', 0.5));
        };
        img.onerror = (err) => reject(err);
      };
      reader.onerror = (err) => reject(err);
    });
  };

  const handlePhotoChange = async (index: number, type: 'sebelum' | 'sesudah', file: File) => {
    try {
      const resizedImage = await resizeImage(file);
      if (type === 'sebelum') {
        const newPhotos = [...photosSebelum];
        newPhotos[index] = resizedImage;
        setPhotosSebelum(newPhotos);
      } else {
        const newPhotos = [...photosSesudah];
        newPhotos[index] = resizedImage;
        setPhotosSesudah(newPhotos);
      }
    } catch (error) {
      alert("Gagal memproses foto.");
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    const updatedReport: ReportData = {
      ...report,
      photos: {
        sebelum: photosSebelum,
        sesudah: photosSesudah
      }
    };

    try {
      await onSubmit(updatedReport, true);
    } catch (error) {
      alert("Gagal mengupdate data.");
      setIsSubmitting(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto bg-white rounded-xl shadow-lg overflow-hidden animate-fade-in mb-20 border border-slate-200">
      <div className="bg-primary px-6 py-5">
        <h2 className="text-xl font-black text-white uppercase tracking-tight">Lengkapi Dokumentasi Foto</h2>
        <div className="flex items-center gap-2 mt-1">
          <span className="w-2 h-2 rounded-full bg-cyan-300 animate-pulse"></span>
          <p className="text-cyan-100 text-[10px] font-bold uppercase tracking-widest">{report.noPenugasan} • {report.penyulang}</p>
        </div>
      </div>

      <div className="p-6 bg-slate-50 border-b border-slate-200 grid grid-cols-2 sm:grid-cols-4 gap-4">
          <div>
            <label className="block text-[8px] font-black text-slate-400 uppercase tracking-widest mb-1">Keypoint</label>
            <div className="text-xs font-bold text-slate-700 uppercase">{report.keypoint}</div>
          </div>
          <div>
            <label className="block text-[8px] font-black text-slate-400 uppercase tracking-widest mb-1">Petugas</label>
            <div className="text-xs font-bold text-slate-700 uppercase">{report.petugas1} & {report.petugas2}</div>
          </div>
          <div>
            <label className="block text-[8px] font-black text-slate-400 uppercase tracking-widest mb-1">Start</label>
            <div className="text-xs font-bold text-slate-700 uppercase truncate">{report.titikStart}</div>
          </div>
          <div>
            <label className="block text-[8px] font-black text-slate-400 uppercase tracking-widest mb-1">Finish</label>
            <div className="text-xs font-bold text-slate-700 uppercase truncate">{report.titikFinish}</div>
          </div>
      </div>

      <form onSubmit={handleSubmit} className="p-6 space-y-8">
        <div className="space-y-8">
          {PHOTO_SECTIONS.map((num, idx) => {
            const isSblmEmpty = report.photos.sebelum[idx] === null;
            const isSsdhEmpty = report.photos.sesudah[idx] === null;

            // Jika keduanya sudah ada, jangan tampilkan di form update ini
            if (!isSblmEmpty && !isSsdhEmpty) return null;

            return (
              <div key={num} className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm">
                <div className="flex items-center gap-2 mb-4">
                  <span className="w-6 h-6 rounded-full bg-primary text-white flex items-center justify-center text-[10px] font-black">0{num}</span>
                  <h4 className="font-black text-slate-700 text-xs uppercase tracking-widest">Titik Pengamatan {num}</h4>
                </div>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                  {isSblmEmpty ? (
                    <PhotoUpload 
                      id={`sebelum-${num}`}
                      label={`Kondisi Sebelum (KOSONG)`}
                      imageSrc={photosSebelum[idx]}
                      onImageChange={(file) => handlePhotoChange(idx, 'sebelum', file)}
                    />
                  ) : (
                    <div className="flex flex-col gap-2">
                       <label className="text-xs font-black text-slate-300 uppercase tracking-widest ml-1">Kondisi Sebelum (SUDAH ADA)</label>
                       <div className="relative w-full h-36 border-2 border-slate-100 rounded-2xl overflow-hidden opacity-50 bg-slate-50">
                          <img src={report.photos.sebelum[idx]!} alt="Existing" className="w-full h-full object-cover grayscale" />
                       </div>
                    </div>
                  )}

                  {isSsdhEmpty ? (
                    <PhotoUpload 
                      id={`sesudah-${num}`}
                      label={`Kondisi Sesudah (KOSONG)`}
                      imageSrc={photosSesudah[idx]}
                      onImageChange={(file) => handlePhotoChange(idx, 'sesudah', file)}
                    />
                  ) : (
                    <div className="flex flex-col gap-2">
                       <label className="text-xs font-black text-slate-300 uppercase tracking-widest ml-1">Kondisi Sesudah (SUDAH ADA)</label>
                       <div className="relative w-full h-36 border-2 border-slate-100 rounded-2xl overflow-hidden opacity-50 bg-slate-50">
                          <img src={report.photos.sesudah[idx]!} alt="Existing" className="w-full h-full object-cover grayscale" />
                       </div>
                    </div>
                  )}
                </div>
              </div>
            );
          })}
        </div>

        <div className="flex items-center justify-end gap-3 pt-6 border-t border-slate-100 sticky bottom-0 bg-white/95 backdrop-blur py-6 z-10 px-6 -mx-6">
          <button 
            type="button" 
            onClick={onCancel}
            disabled={isSubmitting}
            className="px-6 py-3.5 rounded-2xl text-slate-400 hover:text-slate-600 hover:bg-slate-100 font-black uppercase text-[10px] tracking-widest transition-all"
          >
            Batal
          </button>
          <button 
            type="submit" 
            disabled={isSubmitting}
            className="px-10 py-3.5 rounded-2xl bg-primary text-white font-black uppercase text-[10px] tracking-widest hover:bg-cyan-800 shadow-xl shadow-cyan-100 transition-all flex items-center justify-center gap-3"
          >
            {isSubmitting ? 'Mengupdate...' : 'Simpan Perubahan Foto'}
          </button>
        </div>
      </form>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { UserRole, ViewState, ReportData, ULPName, ULPData, LoginSession } from './types';
import { InputForm } from './components/InputForm';
import { Dashboard } from './components/Dashboard';
import { DataTable } from './components/DataTable';
import { AdminSettings } from './components/AdminSettings';
import { AdminRekap } from './components/AdminRekap';
import { LoginConfig } from './components/LoginConfig';
import { UpdateList } from './components/UpdateList';
import { UpdatePhotoForm } from './components/UpdatePhotoForm';
import { DATA_ULP as INITIAL_DATA_ULP, APP_VERSION } from './constants';
import { api } from './services/api';

const LOGO_URL = "https://plnes.co.id/_next/image?url=https%3A%2F%2Fcms.plnes.co.id%2Fuploads%2FLogo_HP_New_Temporary_09a9c5a521.png&w=750&q=75"; 
const APP_LOGO = "https://raw.githubusercontent.com/plnesbukittinggi-ai/yandal_patrol/main/ChatGPT%20Image%2018%20Des%202025%2C%2011.11.52.png";
const NOTIFICATION_SOUND = "https://assets.mixkit.co/active_storage/sfx/2869/2869-preview.mp3";

declare global {
  interface Window {
    ExcelJS: any;
  }
}

const App: React.FC = () => {
  const getCurrentMonthRange = () => {
    const now = new Date();
    const firstDay = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
    const lastDay = new Date(now.getFullYear(), now.getMonth() + 1, 0).toISOString().split('T')[0];
    return { firstDay, lastDay };
  };

  const { firstDay: initStart, lastDay: initEnd } = getCurrentMonthRange();

  const [role, setRole] = useState<UserRole | null>(null);
  const [view, setView] = useState<ViewState>('LOGIN');
  const [isLoading, setIsLoading] = useState(false);
  const [errorLoad, setErrorLoad] = useState<string | null>(null);
  const [isDemoMode, setIsDemoMode] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [notifPermission, setNotifPermission] = useState<NotificationPermission>('default');

  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [adminPassword, setAdminPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  const [session, setSession] = useState<LoginSession>({ ulp: null, petugas1: null, petugas2: null });

  const [tableStartDate, setTableStartDate] = useState(initStart);
  const [tableEndDate, setTableEndDate] = useState(initEnd);
  const [tableUlpFilter, setTableUlpFilter] = useState<ULPName | ''>('');

  const [reports, setReports] = useState<ReportData[]>([]);
  const [masterData, setMasterData] = useState<Record<string, ULPData>>(INITIAL_DATA_ULP);
  const [editingReport, setEditingReport] = useState<ReportData | null>(null);
  const [updatingReport, setUpdatingReport] = useState<ReportData | null>(null);

  const pendingUpdatesRef = useRef<Map<string, string>>(new Map());
  const lastReportIdRef = useRef<string | null>(null);
  const lastPeriodicNotifyRef = useRef<number>(0);

  const requestNotificationPermission = async () => {
    if ('Notification' in window) {
      const permission = await Notification.requestPermission();
      setNotifPermission(permission);
      return permission;
    }
    return 'denied';
  };

  const playNotificationSound = () => {
    const audio = new Audio(NOTIFICATION_SOUND);
    audio.play().catch(e => console.log("Audio play blocked"));
  };

  const updateAppBadge = (count: number) => {
    if ('setAppBadge' in navigator) {
      const nav = navigator as any;
      if (count > 0) nav.setAppBadge(count).catch(() => {});
      else nav.clearAppBadge().catch(() => {});
    }
  };

  const sendBrowserNotification = (title: string, body: string) => {
    if (!('Notification' in window)) return;
    if (Notification.permission === 'granted') {
      playNotificationSound();
      if ('serviceWorker' in navigator) {
        navigator.serviceWorker.ready.then(registration => {
          registration.showNotification(title, {
            body, icon: APP_LOGO, badge: APP_LOGO, tag: 'yandal-patrol-notif',
            renotify: true, vibrate: [200, 100, 200], data: { url: window.location.origin }
          } as any);
        });
      } else {
        new Notification(title, { body, icon: APP_LOGO });
      }
    }
  };

  const generateSummaryMessage = (currentReports: ReportData[]) => {
    const today = new Date().toISOString().split('T')[0];
    const todayReports = currentReports.filter(r => r.timestamp.startsWith(today));
    const counts: Record<string, number> = {};
    Object.values(ULPName).forEach(name => {
      counts[name] = todayReports.filter(r => r.ulp === name).length;
    });
    const dateStr = new Date().toLocaleDateString('id-ID', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });
    let message = `Laporan Yandal Patrol Hari ini : ${dateStr}\n`;
    message += `- ULP Bukittinggi : ${counts[ULPName.BUKITTINGGI] || 0}\n`;
    message += `- ULP Padang Panjang : ${counts[ULPName.PADANG_PANJANG] || 0}\n`;
    message += `- ULP Lubuk Sikaping : ${counts[ULPName.LUBUK_SIKAPING] || 0}\n`;
    message += `- ULP Lubuk Basung : ${counts[ULPName.LUBUK_BASUNG] || 0}\n`;
    message += `- ULP Simpang Empat : ${counts[ULPName.SIMPANG_EMPAT] || 0}\n`;
    message += `- ULP Baso : ${counts[ULPName.BASO] || 0}\n`;
    message += `- ULP Koto Tuo : ${counts[ULPName.KOTO_TUO] || 0}\n`;
    message += `\nMohon untuk ULP yang belum lapor untuk segera melaksanakannya.`;
    return { message, totalToday: todayReports.length };
  };

  const checkPeriodicNotification = (currentReports: ReportData[]) => {
    const now = new Date();
    const currentHour = now.getHours();
    if (currentHour >= 10 && currentHour <= 18) {
      if (currentHour % 2 === 0 && lastPeriodicNotifyRef.current !== currentHour) {
        lastPeriodicNotifyRef.current = currentHour;
        const { message, totalToday } = generateSummaryMessage(currentReports);
        sendBrowserNotification("Update Berkala Yandal Patrol", message);
        updateAppBadge(totalToday);
      }
    }
  };

  useEffect(() => {
    if ('Notification' in window) {
      setNotifPermission(Notification.permission);
      if (Notification.permission === 'default') requestNotificationPermission();
    }
    const savedDemo = localStorage.getItem('yandal_demo_mode');
    if (savedDemo === 'true') {
      setIsDemoMode(true);
      const savedReports = localStorage.getItem('yandal_local_reports');
      if (savedReports) setReports(JSON.parse(savedReports));
    }
    fetchData(true);
    const poller = setInterval(() => fetchData(false), 120000);
    return () => clearInterval(poller);
  }, []);

  useEffect(() => {
    if (view === 'TABLE' && !isDemoMode) fetchData(false);
  }, [tableStartDate, tableEndDate, tableUlpFilter, view]);

  const fetchData = async (showLoading = true) => {
    if (isDemoMode) return;
    if (showLoading) { setIsLoading(true); setErrorLoad(null); }
    try {
      const data = await api.getAllData();
      if (data && data.reports) {
        const serverReports = data.reports as ReportData[];
        if (serverReports.length > 0) {
          const sorted = [...serverReports].sort((a,b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
          const latest = sorted[0];
          if (lastReportIdRef.current && latest.id !== lastReportIdRef.current) {
            const { message, totalToday } = generateSummaryMessage(serverReports);
            sendBrowserNotification("Input Laporan Patrol Baru!", `Oleh: ${latest.petugas1} (${latest.ulp})\n\n${message}`);
            updateAppBadge(totalToday);
          }
          lastReportIdRef.current = latest.id;
        }
        checkPeriodicNotification(serverReports);
        setReports(prevReports => {
          const reportMap = new Map<string, ReportData>();
          prevReports.forEach(r => reportMap.set(r.id, r));
          serverReports.forEach((serverReport: ReportData) => {
            const pendingTimestamp = pendingUpdatesRef.current.get(serverReport.id);
            if (pendingTimestamp && new Date(serverReport.timestamp) < new Date(pendingTimestamp)) return; 
            reportMap.set(serverReport.id, serverReport);
          });
          return Array.from(reportMap.values());
        });
        if (data.masterData) {
            const updatedMaster = { ...data.masterData };
            Object.keys(updatedMaster).forEach(k => { if (!updatedMaster[k].keypoints) updatedMaster[k].keypoints = {}; });
            setMasterData(updatedMaster);
        }
      }
    } catch (error: any) {
      if (showLoading) setErrorLoad(error.message || "Gagal terhubung ke database.");
    } finally {
      if (showLoading) setIsLoading(false);
    }
  };

  const handleInitialRoleSelect = (selectedRole: UserRole) => {
    setRole(selectedRole);
    if (selectedRole === UserRole.ADMIN) return; 
    setView('CONFIG');
  };

  const handleAdminLoginSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminPassword === 'Adminbkt') {
      setRole(UserRole.ADMIN);
      setView('DASHBOARD');
      setShowAdminLogin(false);
    } else {
      setLoginError('Password salah!');
    }
  };

  const handleConfigConfirm = (conf: LoginSession) => {
    setSession(conf);
    setView(role === UserRole.GUEST ? 'TABLE' : 'INPUT');
  };

  const handleLogout = () => {
    setRole(null);
    setView('LOGIN');
    setShowAdminLogin(false);
    setSession({ ulp: null, petugas1: null, petugas2: null });
    setEditingReport(null);
    setUpdatingReport(null);
  };

  const handleBackToMenu = () => {
     if (view === 'CONFIG') { setView('LOGIN'); setRole(null); }
     else { if (role === UserRole.ADMIN) setView('DASHBOARD'); else { setView('LOGIN'); setRole(null); } }
     setEditingReport(null);
     setUpdatingReport(null);
  };

  const handleSaveReport = async (data: ReportData, isEditMode: boolean) => {
    setIsSyncing(true);
    pendingUpdatesRef.current.set(data.id, data.timestamp);
    setReports(prev => [data, ...prev.filter(r => r.id !== data.id)]);
    try {
      if (isDemoMode) {
        localStorage.setItem('yandal_local_reports', JSON.stringify([data, ...reports.filter(r => r.id !== data.id)]));
      } else {
        await api.saveReport(data, isEditMode);
        setTimeout(() => { fetchData(false); pendingUpdatesRef.current.delete(data.id); }, 8000);
      }
      setEditingReport(null);
      setUpdatingReport(null);
      setView('TABLE');
    } catch (e) {
      alert("Gagal sinkronisasi otomatis.");
    } finally {
      setIsSyncing(false);
    }
  };

  const handleUpdatePhoto = (report: ReportData) => {
    setUpdatingReport(report);
    setView('UPDATE_FORM');
  };

  const filteredReportsForTable = useMemo(() => {
    const uniqueMap = new Map<string, ReportData>();
    [...reports].sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime())
      .forEach(r => uniqueMap.set(r.id, r));

    return Array.from(uniqueMap.values())
      .filter(r => {
        if (session.ulp && r.ulp !== session.ulp) return false;
        if (role === UserRole.ADMIN && tableUlpFilter && r.ulp !== tableUlpFilter) return false;
        const reportDate = new Date(r.timestamp).toISOString().split('T')[0];
        if (tableStartDate && reportDate < tableStartDate) return false;
        if (tableEndDate && reportDate > tableEndDate) return false;
        return true;
      })
      .sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
  }, [reports, session.ulp, role, tableUlpFilter, tableStartDate, tableEndDate]);

  const handleDownloadExcel = async () => {
    const ExcelJS = (window as any).ExcelJS;
    if (!ExcelJS) return alert("Library ExcelJS tidak tersedia.");
    setIsSyncing(true);
    try {
      const workbook = new ExcelJS.Workbook();
      const worksheet = workbook.addWorksheet('Laporan Patrol');
      const columns = [
        { header: 'No', key: 'no', width: 6 },
        { header: 'Tanggal', key: 'tanggal', width: 15 },
        { header: 'No. Penugasan', key: 'noPenugasan', width: 20 },
        { header: 'Unit (ULP)', key: 'ulp', width: 18 },
        { header: 'Petugas 1', key: 'petugas1', width: 18 },
        { header: 'Petugas 2', key: 'petugas2', width: 18 },
        { header: 'Penyulang', key: 'penyulang', width: 15 },
        { header: 'Keypoint', key: 'keypoint', width: 22 },
        { header: 'Titik Start', key: 'start', width: 25 },
        { header: 'Titik Finish', key: 'finish', width: 25 },
        ...Array(6).fill(0).map((_, i) => ({ header: `Foto Sblm ${i+1}`, key: `sblm${i+1}`, width: 25 })),
        ...Array(6).fill(0).map((_, i) => ({ header: `Foto Ssdh ${i+1}`, key: `ssdh${i+1}`, width: 25 })),
      ];
      worksheet.columns = columns;

      const headerRow = worksheet.getRow(1);
      headerRow.font = { bold: true, color: { argb: 'FFFFFFFF' } };
      headerRow.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FF0E7490' } };
      headerRow.alignment = { vertical: 'middle', horizontal: 'center' };

      for (let i = 0; i < filteredReportsForTable.length; i++) {
        const r = filteredReportsForTable[i];
        const rowIndex = i + 2;
        const currentRow = worksheet.getRow(rowIndex);
        currentRow.height = 120;
        currentRow.values = [ i + 1, new Date(r.timestamp).toLocaleDateString('id-ID'), r.noPenugasan, r.ulp, r.petugas1, r.petugas2, r.penyulang, r.keypoint, r.titikStart, r.titikFinish, ...Array(12).fill('') ];
        currentRow.alignment = { vertical: 'middle', horizontal: 'center', wrapText: true };

        const addImageToCell = (imageData: string | null, colIndex: number) => {
          if (!imageData || !imageData.startsWith('data:image')) return;
          try {
            const matches = imageData.match(/^data:image\/([a-zA-Z+]+);base64,(.+)$/);
            if (!matches) return;
            const imageId = workbook.addImage({ base64: matches[2], extension: matches[1].replace('jpeg', 'jpg') as any });
            worksheet.addImage(imageId, { tl: { col: colIndex - 1, row: rowIndex - 1 }, br: { col: colIndex, row: rowIndex }, editAs: 'oneCell' });
          } catch (e) {}
        };
        r.photos.sebelum.forEach((photo, pIdx) => { if (photo) addImageToCell(photo, 11 + pIdx); });
        r.photos.sesudah.forEach((photo, pIdx) => { if (photo) addImageToCell(photo, 17 + pIdx); });
      }
      worksheet.eachRow((row) => {
        row.eachCell((cell) => { cell.border = { top: { style: 'thin' }, left: { style: 'thin' }, bottom: { style: 'thin' }, right: { style: 'thin' } }; });
      });
      const buffer = await workbook.xlsx.writeBuffer();
      const blob = new Blob([buffer], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' });
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `Laporan_Patrol_Lengkap_${new Date().toISOString().split('T')[0]}.xlsx`;
      a.click();
      window.URL.revokeObjectURL(url);
    } catch (err: any) {
      alert("Gagal ekspor Excel.");
    } finally {
      setIsSyncing(false);
    }
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50 gap-4 p-4 text-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary"></div>
        <p className="text-slate-700 font-bold">Menghubungkan ke Database...</p>
      </div>
    );
  }

  if (view === 'LOGIN') {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
        <div className="bg-white p-8 rounded-2xl shadow-xl max-w-md w-full border border-slate-200">
          <div className="text-center mb-8">
            <img src={LOGO_URL} alt="Logo PLN" className="h-16 mx-auto mb-4 object-contain" />
            <h2 className="text-sm font-bold text-slate-500 uppercase tracking-widest mb-1">PLN Electricity Services</h2>
            <h1 className="text-lg font-extrabold text-slate-800 mb-6 uppercase tracking-tight">Unit Layanan Bukittinggi</h1>
            <img src={APP_LOGO} alt="Logo App" className="h-48 mx-auto object-contain mb-6 hover:scale-110 transition-transform" />
            <h2 className="text-2xl font-bold text-primary mb-2 uppercase">Yandal Patrol Monitoring</h2>
          </div>
          <div className="space-y-4">
            <button onClick={() => handleInitialRoleSelect(UserRole.USER)} className="w-full bg-primary hover:bg-cyan-800 text-white font-black py-4 rounded-2xl transition-all shadow-lg text-xs uppercase tracking-widest">Login Petugas</button>
            {!showAdminLogin ? (
              <>
                <button onClick={() => setShowAdminLogin(true)} className="w-full bg-slate-800 hover:bg-slate-900 text-white font-black py-4 rounded-2xl text-xs uppercase tracking-widest">Login Admin</button>
                <button onClick={() => handleInitialRoleSelect(UserRole.GUEST)} className="w-full bg-white border-2 border-slate-200 hover:border-primary text-slate-600 font-black py-4 rounded-2xl text-xs uppercase tracking-widest">Tampilkan Data</button>
              </>
            ) : (
              <form onSubmit={handleAdminLoginSubmit} className="bg-slate-50 p-5 rounded-2xl border border-slate-200 animate-fade-in">
                <input type="password" autoFocus className="w-full px-4 py-3 border rounded-xl mb-3 outline-none transition-all" value={adminPassword} onChange={(e) => setAdminPassword(e.target.value)} placeholder="Password Admin..." />
                <div className="flex gap-2">
                  <button type="button" onClick={() => setShowAdminLogin(false)} className="flex-1 py-3 text-xs font-bold text-slate-600 bg-white border border-slate-300 rounded-xl">Batal</button>
                  <button type="submit" className="flex-1 py-3 text-xs font-black bg-slate-800 text-white rounded-xl">Masuk</button>
                </div>
              </form>
            )}
          </div>
        </div>
      </div>
    );
  }

  if (view === 'CONFIG' && role) {
    return <LoginConfig role={role} masterData={masterData} appLogo={APP_LOGO} onBack={() => { setView('LOGIN'); setRole(null); }} onConfirm={handleConfigConfirm} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {isSyncing && (
        <div className="fixed top-4 right-4 z-50 bg-white shadow-xl rounded-full px-5 py-2.5 flex items-center gap-2 border border-slate-200 animate-fade-in">
          <div className="animate-spin h-4 w-4 border-2 border-primary border-t-transparent rounded-full"></div>
          <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest">Memproses...</span>
        </div>
      )}

      <header className="bg-white shadow-sm z-20 sticky top-0">
        <div className="max-w-7xl mx-auto px-4 h-16 flex justify-between items-center">
            <div className="flex items-center gap-4">
               <button onClick={handleBackToMenu} className="p-2 hover:bg-slate-100 rounded-full transition-all text-slate-600 group flex items-center gap-1">
                 <svg className="w-5 h-5 group-hover:-translate-x-1 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
                 <span className="hidden sm:inline text-[10px] font-black uppercase tracking-widest">Kembali</span>
               </button>
               <div className="w-px h-8 bg-slate-200"></div>
               <div className="flex items-center gap-2 cursor-pointer" onClick={() => setView('ABOUT')}>
                 <img src={APP_LOGO} alt="App" className="h-8 object-contain" />
                 <div className="flex flex-col leading-none">
                   <span className="font-black text-sm text-slate-800 tracking-tight">Yandal Patrol</span>
                   <span className="text-[9px] text-primary font-black uppercase tracking-widest">{session.ulp || 'UP3 BUKITTINGGI'}</span>
                 </div>
               </div>
            </div>
            <button onClick={handleLogout} className="text-[10px] text-red-600 font-black px-4 py-2 rounded-xl hover:bg-red-50 uppercase tracking-widest">Logout</button>
        </div>
        <div className="max-w-7xl mx-auto px-4">
          <nav className="-mb-px flex space-x-8 overflow-x-auto no-scrollbar">
            {role === UserRole.ADMIN && (
              <>
                <button onClick={() => setView('DASHBOARD')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'DASHBOARD' ? 'border-primary text-primary' : 'border-transparent text-slate-400 hover:text-slate-600'}`}>Dashboard</button>
                <button onClick={() => setView('REKAP')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'REKAP' ? 'border-primary text-primary' : 'border-transparent text-slate-400 hover:text-slate-600'}`}>Rekap Petugas</button>
                <button onClick={() => setView('SETTINGS')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'SETTINGS' ? 'border-primary text-primary' : 'border-transparent text-slate-400 hover:text-slate-600'}`}>Kelola Data</button>
              </>
            )}
            {role === UserRole.USER && (
              <>
                <button onClick={() => setView('INPUT')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'INPUT' ? 'border-primary text-primary' : 'border-transparent text-slate-400 hover:text-slate-600'}`}>Input Data</button>
                <button onClick={() => setView('UPDATE_LIST')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'UPDATE_LIST' || view === 'UPDATE_FORM' ? 'border-primary text-primary' : 'border-transparent text-slate-400 hover:text-slate-600'}`}>Update Data</button>
              </>
            )}
            <button onClick={() => setView('TABLE')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'TABLE' ? 'border-primary text-primary' : 'border-transparent text-slate-400 hover:text-slate-600'}`}>Data Laporan</button>
            <button onClick={() => setView('ABOUT')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'ABOUT' ? 'border-primary text-primary' : 'border-transparent text-slate-400 hover:text-slate-600'}`}>Tentang</button>
          </nav>
        </div>
      </header>

      <main className="flex-1 max-w-7xl w-full mx-auto px-4 py-8">
        {view === 'DASHBOARD' && <Dashboard reports={filteredReportsForTable.filter(r => !session.ulp || r.ulp === session.ulp)} />}
        {view === 'REKAP' && role === UserRole.ADMIN && <AdminRekap reports={reports} masterData={masterData} />}
        {view === 'SETTINGS' && role === UserRole.ADMIN && (
          <AdminSettings 
            masterData={masterData}
            onAddPetugas={(ulp, names) => { const nd = {...masterData, [ulp]: {...masterData[ulp], petugas: [...masterData[ulp].petugas, ...names]}}; setMasterData(nd); if(!isDemoMode) api.updateMasterData(nd); }}
            onDeletePetugas={(ulp, n) => { const nd = {...masterData, [ulp]: {...masterData[ulp], petugas: masterData[ulp].petugas.filter(p => p !== n)}}; setMasterData(nd); if(!isDemoMode) api.updateMasterData(nd); }}
            onAddPenyulang={(ulp, names) => { const nd = {...masterData, [ulp]: {...masterData[ulp], penyulang: [...masterData[ulp].penyulang, ...names]}}; setMasterData(nd); if(!isDemoMode) api.updateMasterData(nd); }}
            onDeletePenyulang={(ulp, n) => { const nd = {...masterData, [ulp]: {...masterData[ulp], penyulang: masterData[ulp].penyulang.filter(p => p !== n)}}; setMasterData(nd); if(!isDemoMode) api.updateMasterData(nd); }}
            onAddKeypoint={(ulp, penyulang, kps) => {
              const nd = { ...masterData };
              if (!nd[ulp].keypoints) nd[ulp].keypoints = {};
              if (!nd[ulp].keypoints[penyulang]) nd[ulp].keypoints[penyulang] = [];
              nd[ulp].keypoints[penyulang] = [...new Set([...nd[ulp].keypoints[penyulang], ...kps])];
              setMasterData(nd); if(!isDemoMode) api.updateMasterData(nd);
            }}
            onDeleteKeypoint={(ulp, penyulang, kp) => {
              const nd = { ...masterData };
              if (nd[ulp].keypoints?.[penyulang]) nd[ulp].keypoints[penyulang] = nd[ulp].keypoints[penyulang].filter(item => item !== kp);
              setMasterData(nd); if(!isDemoMode) api.updateMasterData(nd);
            }}
          />
        )}
        {view === 'INPUT' && role !== UserRole.GUEST && <InputForm key={editingReport?.id || 'new-report'} onSubmit={handleSaveReport} onCancel={() => setView('TABLE')} masterData={masterData} sessionData={session} editData={editingReport} />}
        {view === 'UPDATE_LIST' && <UpdateList reports={reports} session={session} onUpdate={handleUpdatePhoto} />}
        {view === 'UPDATE_FORM' && updatingReport && <UpdatePhotoForm report={updatingReport} onSubmit={handleSaveReport} onCancel={() => setView('UPDATE_LIST')} />}
        {view === 'TABLE' && (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <h2 className="text-2xl font-black text-slate-800 uppercase">Riwayat Penugasan</h2>
              <div className="flex gap-2">
                <button onClick={() => fetchData(true)} className="p-2.5 bg-slate-200 rounded-2xl hover:bg-slate-300 transition-all"><svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg></button>
                {role === UserRole.USER && <button onClick={() => setView('INPUT')} className="bg-primary text-white px-5 py-2.5 rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-lg">Tambah Laporan</button>}
              </div>
            </div>
            <div className="bg-white p-5 rounded-2xl shadow-sm border border-slate-200 grid grid-cols-1 md:grid-cols-5 gap-5 items-end">
              <input type="date" className="w-full px-4 py-2.5 border rounded-xl text-xs font-bold" value={tableStartDate} onChange={(e) => setTableStartDate(e.target.value)} />
              <input type="date" className="w-full px-4 py-2.5 border rounded-xl text-xs font-bold" value={tableEndDate} onChange={(e) => setTableEndDate(e.target.value)} />
              {(role === UserRole.ADMIN || (role === UserRole.GUEST && !session.ulp)) && (
                <select className="w-full px-4 py-2.5 border rounded-xl text-xs font-bold bg-white" value={tableUlpFilter} onChange={(e) => setTableUlpFilter(e.target.value as ULPName)}>
                  <option value="">Semua ULP</option>
                  {Object.values(ULPName).map(u => <option key={u} value={u}>{u}</option>)}
                </select>
              )}
              <button onClick={() => { setTableStartDate(initStart); setTableEndDate(initEnd); setTableUlpFilter(''); }} className="w-full py-2.5 px-4 bg-slate-50 text-slate-400 font-black rounded-xl text-[10px] uppercase border transition-all">Reset</button>
              {role === UserRole.ADMIN && <button onClick={handleDownloadExcel} className="w-full py-2.5 px-4 bg-green-600 text-white font-black rounded-xl text-[10px] uppercase shadow-lg">Export Excel LENGKAP</button>}
            </div>
            <DataTable reports={filteredReportsForTable} onEdit={role !== UserRole.GUEST ? openEditForm : undefined} />
          </div>
        )}
        {view === 'ABOUT' && (
          <div className="max-w-3xl mx-auto animate-fade-in">
            <div className="bg-white rounded-[2rem] shadow-xl overflow-hidden border border-slate-200">
               <div className="bg-primary p-12 text-white text-center flex flex-col items-center">
                  <img src={APP_LOGO} alt="App" className="h-36 w-auto object-contain z-10 mb-6" />
                  <h1 className="text-4xl font-black mb-1 uppercase">Yandal Patrol Monitoring</h1>
                  <span className="text-[10px] font-black uppercase tracking-[0.3em] bg-white/20 px-4 py-1.5 rounded-full mt-3">Version {APP_VERSION}</span>
               </div>
               <div className="p-10 space-y-10">
                  <section className="text-center space-y-4">
                    <h2 className="text-xl font-black text-slate-800 uppercase">Status Sistem Notifikasi</h2>
                    <div className="flex flex-col items-center gap-4">
                      <div className={`px-6 py-3 rounded-2xl flex items-center gap-3 border ${notifPermission === 'granted' ? 'bg-green-50 border-green-200 text-green-700' : notifPermission === 'denied' ? 'bg-red-50 border-red-200 text-red-700' : 'bg-slate-50 border-slate-200 text-slate-500'}`}>
                        <div className={`w-3 h-3 rounded-full ${notifPermission === 'granted' ? 'bg-green-500 animate-pulse' : notifPermission === 'denied' ? 'bg-red-500' : 'bg-slate-400'}`}></div>
                        <span className="text-sm font-black uppercase tracking-widest">Izin Notifikasi: {notifPermission === 'granted' ? 'Aktif' : notifPermission === 'denied' ? 'Diblokir' : 'Belum Diizinkan'}</span>
                      </div>
                    </div>
                  </section>
                  <div className="pt-10 border-t border-slate-100 flex flex-col items-center gap-2">
                    <p className="text-base font-black text-slate-800 uppercase">PLN Electricity Services Bukittinggi</p>
                    <p className="text-[11px] text-slate-400 font-bold uppercase">© 2025 • IT Unit Layanan Bukittinggi</p>
                  </div>
               </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { UserRole, ViewState, ReportData, ULPName, ULPData, LoginSession } from './types';
import { InputForm } from './components/InputForm';
import { Dashboard } from './components/Dashboard';
import { DataTable } from './components/DataTable';
import { AdminSettings } from './components/AdminSettings';
import { AdminRekap } from './components/AdminRekap';
import { LoginConfig } from './components/LoginConfig';
import { UpdateList } from './components/UpdateList';
import { UpdatePhotoForm } from './components/UpdatePhotoForm';
import { DATA_ULP as INITIAL_DATA_ULP, APP_VERSION } from './constants';
import { api } from './services/api';

const LOGO_URL = "https://plnes.co.id/_next/image?url=https%3A%2F%2Fcms.plnes.co.id%2Fuploads%2FLogo_HP_New_Temporary_09a9c5a521.png&w=750&q=75"; 
const APP_LOGO = "https://raw.githubusercontent.com/plnesbukittinggi-ai/yandal_patrol/main/ChatGPT%20Image%2018%20Des%202025%2C%2011.11.52.png";
const NOTIFICATION_SOUND = "https://assets.mixkit.co/active_storage/sfx/2869/2869-preview.mp3";

declare global {
  interface Window {
    ExcelJS: any;
  }
}

const App: React.FC = () => {
  const getCurrentMonthRange = () => {
    const now = new Date();
    const firstDay = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
    const lastDay = new Date(now.getFullYear(), now.getMonth() + 1, 0).toISOString().split('T')[0];
    return { firstDay, lastDay };
  };

  const { firstDay: initStart, lastDay: initEnd } = getCurrentMonthRange();

  const [role, setRole] = useState<UserRole | null>(null);
  const [view, setView] = useState<ViewState>('LOGIN');
  const [isLoading, setIsLoading] = useState(false);
  const [errorLoad, setErrorLoad] = useState<string | null>(null);
  const [isDemoMode, setIsDemoMode] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [notifPermission, setNotifPermission] = useState<NotificationPermission>('default');

  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [adminPassword, setAdminPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  const [session, setSession] = useState<LoginSession>({ ulp: null, petugas1: null, petugas2: null });

  const [tableStartDate, setTableStartDate] = useState(initStart);
  const [tableEndDate, setTableEndDate] = useState(initEnd);
  const [tableUlpFilter, setTableUlpFilter] = useState<ULPName | ''>('');

  const [reports, setReports] = useState<ReportData[]>([]);
  const [masterData, setMasterData] = useState<Record<string, ULPData>>(INITIAL_DATA_ULP);
  const [editingReport, setEditingReport] = useState<ReportData | null>(null);
  const [updatingReport, setUpdatingReport] = useState<ReportData | null>(null);

  const pendingUpdatesRef = useRef<Map<string, string>>(new Map());
  const lastReportIdRef = useRef<string | null>(null);
  const lastPeriodicNotifyRef = useRef<number>(0);

  const requestNotificationPermission = async () => {
    if ('Notification' in window) {
      const permission = await Notification.requestPermission();
      setNotifPermission(permission);
      return permission;
    }
    return 'denied';
  };

  const playNotificationSound = () => {
    const audio = new Audio(NOTIFICATION_SOUND);
    audio.play().catch(e => console.log("Audio play blocked"));
  };

  const updateAppBadge = (count: number) => {
    if ('setAppBadge' in navigator) {
      const nav = navigator as any;
      if (count > 0) nav.setAppBadge(count).catch(() => {});
      else nav.clearAppBadge().catch(() => {});
    }
  };

  const sendBrowserNotification = (title: string, body: string) => {
    if (!('Notification' in window)) return;
    if (Notification.permission === 'granted') {
      playNotificationSound();
      if ('serviceWorker' in navigator) {
        navigator.serviceWorker.ready.then(registration => {
          registration.showNotification(title, {
            body, icon: APP_LOGO, badge: APP_LOGO, tag: 'yandal-patrol-notif',
            renotify: true, vibrate: [200, 100, 200], data: { url: window.location.origin }
          } as any);
        });
      } else {
        new Notification(title, { body, icon: APP_LOGO });
      }
    }
  };

  const generateSummaryMessage = (currentReports: ReportData[]) => {
    const today = new Date().toISOString().split('T')[0];
    const todayReports = currentReports.filter(r => r.timestamp.startsWith(today));
    const counts: Record<string, number> = {};
    Object.values(ULPName).forEach(name => {
      counts[name] = todayReports.filter(r => r.ulp === name).length;
    });
    const dateStr = new Date().toLocaleDateString('id-ID', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });
    let message = `Laporan Yandal Patrol Hari ini : ${dateStr}\n`;
    message += `- ULP Bukittinggi : ${counts[ULPName.BUKITTINGGI] || 0}\n`;
    message += `- ULP Padang Panjang : ${counts[ULPName.PADANG_PANJANG] || 0}\n`;
    message += `- ULP Lubuk Sikaping : ${counts[ULPName.LUBUK_SIKAPING] || 0}\n`;
    message += `- ULP Lubuk Basung : ${counts[ULPName.LUBUK_BASUNG] || 0}\n`;
    message += `- ULP Simpang Empat : ${counts[ULPName.SIMPANG_EMPAT] || 0}\n`;
    message += `- ULP Baso : ${counts[ULPName.BASO] || 0}\n`;
    message += `- ULP Koto Tuo : ${counts[ULPName.KOTO_TUO] || 0}\n`;
    message += `\nMohon untuk ULP yang belum lapor untuk segera melaksanakannya.`;
    return { message, totalToday: todayReports.length };
  };

  const checkPeriodicNotification = (currentReports: ReportData[]) => {
    const now = new Date();
    const currentHour = now.getHours();
    if (currentHour >= 10 && currentHour <= 18) {
      if (currentHour % 2 === 0 && lastPeriodicNotifyRef.current !== currentHour) {
        lastPeriodicNotifyRef.current = currentHour;
        const { message, totalToday } = generateSummaryMessage(currentReports);
        sendBrowserNotification("Update Berkala Yandal Patrol", message);
        updateAppBadge(totalToday);
      }
    }
  };

  useEffect(() => {
    if ('Notification' in window) {
      setNotifPermission(Notification.permission);
      if (Notification.permission === 'default') requestNotificationPermission();
    }
    const savedDemo = localStorage.getItem('yandal_demo_mode');
    if (savedDemo === 'true') {
      setIsDemoMode(true);
      const savedReports = localStorage.getItem('yandal_local_reports');
      if (savedReports) setReports(JSON.parse(savedReports));
    }
    fetchData(true);
    const poller = setInterval(() => fetchData(false), 120000);
    return () => clearInterval(poller);
  }, []);

  useEffect(() => {
    if (view === 'TABLE' && !isDemoMode) fetchData(false);
  }, [tableStartDate, tableEndDate, tableUlpFilter, view]);

  const fetchData = async (showLoading = true) => {
    if (isDemoMode) return;
    if (showLoading) { setIsLoading(true); setErrorLoad(null); }
    try {
      const data = await api.getAllData();
      if (data && data.reports) {
        const serverReports = data.reports as ReportData[];
        if (serverReports.length > 0) {
          const sorted = [...serverReports].sort((a,b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
          const latest = sorted[0];
          if (lastReportIdRef.current && latest.id !== lastReportIdRef.current) {
            const { message, totalToday = 0 } = generateSummaryMessage(serverReports);
            sendBrowserNotification("Input Laporan Patrol Baru!", `Oleh: ${latest.petugas1} (${latest.ulp})\n\n${message}`);
            updateAppBadge(totalToday);
          }
          lastReportIdRef.current = latest.id;
        }
        checkPeriodicNotification(serverReports);
        setReports(prevReports => {
          const reportMap = new Map<string, ReportData>();
          prevReports.forEach(r => reportMap.set(r.id, r));
          serverReports.forEach((serverReport: ReportData) => {
            const pendingTimestamp = pendingUpdatesRef.current.get(serverReport.id);
            if (pendingTimestamp && new Date(serverReport.timestamp) < new Date(pendingTimestamp)) return; 
            reportMap.set(serverReport.id, serverReport);
          });
          return Array.from(reportMap.values());
        });
        if (data.masterData) {
            const updatedMaster = { ...data.masterData };
            Object.keys(updatedMaster).forEach(k => { if (!updatedMaster[k].keypoints) updatedMaster[k].keypoints = {}; });
            setMasterData(updatedMaster);
        }
      }
    } catch (error: any) {
      if (showLoading) setErrorLoad(error.message || "Gagal terhubung ke database.");
    } finally {
      if (showLoading) setIsLoading(false);
    }
  };

  const handleInitialRoleSelect = (selectedRole: UserRole) => {
    setRole(selectedRole);
    if (selectedRole === UserRole.ADMIN) return; 
    setView('CONFIG');
  };

  const handleAdminLoginSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminPassword === 'Adminbkt') {
      setRole(UserRole.ADMIN);
      setView('DASHBOARD');
      setShowAdminLogin(false);
    } else {
      setLoginError('Password salah!');
    }
  };

  const handleConfigConfirm = (conf: LoginSession) => {
    setSession(conf);
    setView(role === UserRole.GUEST ? 'TABLE' : 'INPUT');
  };

  const handleLogout = () => {
    setRole(null);
    setView('LOGIN');
    setShowAdminLogin(false);
    setSession({ ulp: null, petugas1: null, petugas2: null });
    setEditingReport(null);
    setUpdatingReport(null);
  };

  const handleBackToMenu = () => {
     if (view === 'CONFIG') { setView('LOGIN'); setRole(null); }
     else { if (role === UserRole.ADMIN) setView('DASHBOARD'); else { setView('LOGIN'); setRole(null); } }
     setEditingReport(null);
     setUpdatingReport(null);
  };

  const handleSaveReport = async (data: ReportData, isEditMode: boolean) => {
    setIsSyncing(true);
    pendingUpdatesRef.current.set(data.id, data.timestamp);
    setReports(prev => [data, ...prev.filter(r => r.id !== data.id)]);
    try {
      if (isDemoMode) {
        localStorage.setItem('yandal_local_reports', JSON.stringify([data, ...reports.filter(r => r.id !== data.id)]));
      } else {
        await api.saveReport(data, isEditMode);
        setTimeout(() => { fetchData(false); pendingUpdatesRef.current.delete(data.id); }, 8000);
      }
      setEditingReport(null);
      setUpdatingReport(null);
      setView('TABLE');
    } catch (e) {
      alert("Gagal sinkronisasi otomatis.");
    } finally {
      setIsSyncing(false);
    }
  };

  const handleUpdatePhoto = (report: ReportData) => {
    setUpdatingReport(report);
    setView('UPDATE_FORM');
  };

  // Fix: Missing openEditForm function added to handle report editing
  const openEditForm = (report: ReportData) => {
    setEditingReport(report);
    setView('INPUT');
  };

  const filteredReportsForTable = useMemo(() => {
    const uniqueMap = new Map<string, ReportData>();
    [...reports].sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime())
      .forEach(r => uniqueMap.set(r.id, r));

    return Array.from(uniqueMap.values())
      .filter(r => {
        if (session.ulp && r.ulp !== session.ulp) return false;
        if (role === UserRole.ADMIN && tableUlpFilter && r.ulp !== tableUlpFilter) return false;
        const reportDate = new Date(r.timestamp).toISOString().split('T')[0];
        if (tableStartDate && reportDate < tableStartDate) return false;
        if (tableEndDate && reportDate > tableEndDate) return false;
        return true;
      })
      .sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
  }, [reports, session.ulp, role, tableUlpFilter, tableStartDate, tableEndDate]);

  const handleDownloadExcel = async () => {
    const ExcelJS = (window as any).ExcelJS;
    if (!ExcelJS) return alert("Library ExcelJS tidak tersedia.");
    setIsSyncing(true);
    try {
      const workbook = new ExcelJS.Workbook();
      const worksheet = workbook.addWorksheet('Laporan Patrol');
      const columns = [
        { header: 'No', key: 'no', width: 6 },
        { header: 'Tanggal', key: 'tanggal', width: 15 },
        { header: 'No. Penugasan', key: 'noPenugasan', width: 20 },
        { header: 'Unit (ULP)', key: 'ulp', width: 18 },
        { header: 'Petugas 1', key: 'petugas1', width: 18 },
        { header: 'Petugas 2', key: 'petugas2', width: 18 },
        { header: 'Penyulang', key: 'penyulang', width: 15 },
        { header: 'Keypoint', key: 'keypoint', width: 22 },
        { header: 'Titik Start', key: 'start', width: 25 },
        { header: 'Titik Finish', key: 'finish', width: 25 },
        ...Array(6).fill(0).map((_, i) => ({ header: `Foto Sblm ${i+1}`, key: `sblm${i+1}`, width: 25 })),
        ...Array(6).fill(0).map((_, i) => ({ header: `Foto Ssdh ${i+1}`, key: `ssdh${i+1}`, width: 25 })),
      ];
      worksheet.columns = columns;

      const headerRow = worksheet.getRow(1);
      headerRow.font = { bold: true, color: { argb: 'FFFFFFFF' } };
      headerRow.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FF0E7490' } };
      headerRow.alignment = { vertical: 'middle', horizontal: 'center' };

      for (let i = 0; i < filteredReportsForTable.length; i++) {
        const r = filteredReportsForTable[i];
        const rowIndex = i + 2;
        const currentRow = worksheet.getRow(rowIndex);
        currentRow.height = 120;
        currentRow.values = [ i + 1, new Date(r.timestamp).toLocaleDateString('id-ID'), r.noPenugasan, r.ulp, r.petugas1, r.petugas2, r.penyulang, r.keypoint, r.titikStart, r.titikFinish, ...Array(12).fill('') ];
        currentRow.alignment = { vertical: 'middle', horizontal: 'center', wrapText: true };

        const addImageToCell = (imageData: string | null, colIndex: number) => {
          if (!imageData || !imageData.startsWith('data:image')) return;
          try {
            const matches = imageData.match(/^data:image\/([a-zA-Z+]+);base64,(.+)$/);
            if (!matches) return;
            const imageId = workbook.addImage({ base64: matches[2], extension: matches[1].replace('jpeg', 'jpg') as any });
            worksheet.addImage(imageId, { tl: { col: colIndex - 1, row: rowIndex - 1 }, br: { col: colIndex, row: rowIndex }, editAs: 'oneCell' });
          } catch (e) {}
        };
        r.photos.sebelum.forEach((photo, pIdx) => { if (photo) addImageToCell(photo, 11 + pIdx); });
        r.photos.sesudah.forEach((photo, pIdx) => { if (photo) addImageToCell(photo, 17 + pIdx); });
      }
      worksheet.eachRow((row) => {
        row.eachCell((cell) => { cell.border = { top: { style: 'thin' }, left: { style: 'thin' }, bottom: { style: 'thin' }, right: { style: 'thin' } }; });
      });
      const buffer = await workbook.xlsx.writeBuffer();
      const blob = new Blob([buffer], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' });
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `Laporan_Patrol_Lengkap_${new Date().toISOString().split('T')[0]}.xlsx`;
      a.click();
      window.URL.revokeObjectURL(url);
    } catch (err: any) {
      alert("Gagal ekspor Excel.");
    } finally {
      setIsSyncing(false);
    }
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50 gap-4 p-4 text-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary"></div>
        <p className="text-slate-700 font-bold">Menghubungkan ke Database...</p>
      </div>
    );
  }

  if (view === 'LOGIN') {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
        <div className="bg-white p-8 rounded-2xl shadow-xl max-w-md w-full border border-slate-200">
          <div className="text-center mb-8">
            <img src={LOGO_URL} alt="Logo PLN" className="h-16 mx-auto mb-4 object-contain" />
            <h2 className="text-sm font-bold text-slate-500 uppercase tracking-widest mb-1">PLN Electricity Services</h2>
            <h1 className="text-lg font-extrabold text-slate-800 mb-6 uppercase tracking-tight">Unit Layanan Bukittinggi</h1>
            <img src={APP_LOGO} alt="Logo App" className="h-48 mx-auto object-contain mb-6 hover:scale-110 transition-transform" />
            <h2 className="text-2xl font-bold text-primary mb-2 uppercase">Yandal Patrol Monitoring</h2>
          </div>
          <div className="space-y-4">
            <button onClick={() => handleInitialRoleSelect(UserRole.USER)} className="w-full bg-primary hover:bg-cyan-800 text-white font-black py-4 rounded-2xl transition-all shadow-lg text-xs uppercase tracking-widest">Login Petugas</button>
            {!showAdminLogin ? (
              <>
                <button onClick={() => setShowAdminLogin(true)} className="w-full bg-slate-800 hover:bg-slate-900 text-white font-black py-4 rounded-2xl text-xs uppercase tracking-widest">Login Admin</button>
                <button onClick={() => handleInitialRoleSelect(UserRole.GUEST)} className="w-full bg-white border-2 border-slate-200 hover:border-primary text-slate-600 font-black py-4 rounded-2xl text-xs uppercase tracking-widest">Tampilkan Data</button>
              </>
            ) : (
              <form onSubmit={handleAdminLoginSubmit} className="bg-slate-50 p-5 rounded-2xl border border-slate-200 animate-fade-in">
                <input type="password" autoFocus className="w-full px-4 py-3 border rounded-xl mb-3 outline-none transition-all" value={adminPassword} onChange={(e) => setAdminPassword(e.target.value)} placeholder="Password Admin..." />
                <div className="flex gap-2">
                  <button type="button" onClick={() => setShowAdminLogin(false)} className="flex-1 py-3 text-xs font-bold text-slate-600 bg-white border border-slate-300 rounded-xl">Batal</button>
                  <button type="submit" className="flex-1 py-3 text-xs font-black bg-slate-800 text-white rounded-xl">Masuk</button>
                </div>
              </form>
            )}
          </div>
        </div>
      </div>
    );
  }

  if (view === 'CONFIG' && role) {
    return <LoginConfig role={role} masterData={masterData} appLogo={APP_LOGO} onBack={() => { setView('LOGIN'); setRole(null); }} onConfirm={handleConfigConfirm} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {isSyncing && (
        <div className="fixed top-4 right-4 z-50 bg-white shadow-xl rounded-full px-5 py-2.5 flex items-center gap-2 border border-slate-200 animate-fade-in">
          <div className="animate-spin h-4 w-4 border-2 border-primary border-t-transparent rounded-full"></div>
          <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest">Memproses...</span>
        </div>
      )}

      <header className="bg-white shadow-sm z-20 sticky top-0">
        <div className="max-w-7xl mx-auto px-4 h-16 flex justify-between items-center">
            <div className="flex items-center gap-4">
               <button onClick={handleBackToMenu} className="p-2 hover:bg-slate-100 rounded-full transition-all text-slate-600 group flex items-center gap-1">
                 <svg className="w-5 h-5 group-hover:-translate-x-1 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
                 <span className="hidden sm:inline text-[10px] font-black uppercase tracking-widest">Kembali</span>
               </button>
               <div className="w-px h-8 bg-slate-200"></div>
               <div className="flex items-center gap-2 cursor-pointer" onClick={() => setView('ABOUT')}>
                 <img src={APP_LOGO} alt="App" className="h-8 object-contain" />
                 <div className="flex flex-col leading-none">
                   <span className="font-black text-sm text-slate-800 tracking-tight">Yandal Patrol</span>
                   <span className="text-[9px] text-primary font-black uppercase tracking-widest">{session.ulp || 'UP3 BUKITTINGGI'}</span>
                 </div>
               </div>
            </div>
            <button onClick={handleLogout} className="text-[10px] text-red-600 font-black px-4 py-2 rounded-xl hover:bg-red-50 uppercase tracking-widest">Logout</button>
        </div>
        <div className="max-w-7xl mx-auto px-4">
          <nav className="-mb-px flex space-x-8 overflow-x-auto no-scrollbar">
            {role === UserRole.ADMIN && (
              <>
                <button onClick={() => setView('DASHBOARD')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'DASHBOARD' ? 'border-primary text-primary' : 'border-transparent text-slate-400 hover:text-slate-600'}`}>Dashboard</button>
                <button onClick={() => setView('REKAP')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'REKAP' ? 'border-primary text-primary' : 'border-transparent text-slate-400 hover:text-slate-600'}`}>Rekap Petugas</button>
                <button onClick={() => setView('SETTINGS')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'SETTINGS' ? 'border-primary text-primary' : 'border-transparent text-slate-400 hover:text-slate-600'}`}>Kelola Data</button>
              </>
            )}
            {role === UserRole.USER && (
              <>
                <button onClick={() => setView('INPUT')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'INPUT' ? 'border-primary text-primary' : 'border-transparent text-slate-400 hover:text-slate-600'}`}>Input Data</button>
                <button onClick={() => setView('UPDATE_LIST')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'UPDATE_LIST' || view === 'UPDATE_FORM' ? 'border-primary text-primary' : 'border-transparent text-slate-400 hover:text-slate-600'}`}>Update Data</button>
              </>
            )}
            <button onClick={() => setView('TABLE')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'TABLE' ? 'border-primary text-primary' : 'border-transparent text-slate-400 hover:text-slate-600'}`}>Data Laporan</button>
            <button onClick={() => setView('ABOUT')} className={`pb-4 px-1 border-b-4 font-black text-[10px] uppercase tracking-widest whitespace-nowrap ${view === 'ABOUT' ? 'border-primary text-primary' : 'border-transparent text-slate-400 hover:text-slate-600'}`}>Tentang</button>
          </nav>
        </div>
      </header>

      <main className="flex-1 max-w-7xl w-full mx-auto px-4 py-8">
        {view === 'DASHBOARD' && <Dashboard reports={filteredReportsForTable.filter(r => !session.ulp || r.ulp === session.ulp)} />}
        {view === 'REKAP' && role === UserRole.ADMIN && <AdminRekap reports={reports} masterData={masterData} />}
        {view === 'SETTINGS' && role === UserRole.ADMIN && (
          <AdminSettings 
            masterData={masterData}
            onAddPetugas={(ulp, names) => { const nd = {...masterData, [ulp]: {...masterData[ulp], petugas: [...masterData[ulp].petugas, ...names]}}; setMasterData(nd); if(!isDemoMode) api.updateMasterData(nd); }}
            onDeletePetugas={(ulp, n) => { const nd = {...masterData, [ulp]: {...masterData[ulp], petugas: masterData[ulp].petugas.filter(p => p !== n)}}; setMasterData(nd); if(!isDemoMode) api.updateMasterData(nd); }}
            onAddPenyulang={(ulp, names) => { const nd = {...masterData, [ulp]: {...masterData[ulp], penyulang: [...masterData[ulp].penyulang, ...names]}}; setMasterData(nd); if(!isDemoMode) api.updateMasterData(nd); }}
            onDeletePenyulang={(ulp, n) => { const nd = {...masterData, [ulp]: {...masterData[ulp], penyulang: masterData[ulp].penyulang.filter(p => p !== n)}}; setMasterData(nd); if(!isDemoMode) api.updateMasterData(nd); }}
            onAddKeypoint={(ulp, penyulang, kps) => {
              const nd = { ...masterData };
              if (!nd[ulp].keypoints) nd[ulp].keypoints = {};
              if (!nd[ulp].keypoints[penyulang]) nd[ulp].keypoints[penyulang] = [];
              nd[ulp].keypoints[penyulang] = [...new Set([...nd[ulp].keypoints[penyulang], ...kps])];
              setMasterData(nd); if(!isDemoMode) api.updateMasterData(nd);
            }}
            onDeleteKeypoint={(ulp, penyulang, kp) => {
              const nd = { ...masterData };
              if (nd[ulp].keypoints?.[penyulang]) nd[ulp].keypoints[penyulang] = nd[ulp].keypoints[penyulang].filter(item => item !== kp);
              setMasterData(nd); if(!isDemoMode) api.updateMasterData(nd);
            }}
          />
        )}
        {view === 'INPUT' && role !== UserRole.GUEST && <InputForm key={editingReport?.id || 'new-report'} onSubmit={handleSaveReport} onCancel={() => setView('TABLE')} masterData={masterData} sessionData={session} editData={editingReport} />}
        {view === 'UPDATE_LIST' && <UpdateList reports={reports} session={session} onUpdate={handleUpdatePhoto} />}
        {view === 'UPDATE_FORM' && updatingReport && <UpdatePhotoForm report={updatingReport} onSubmit={handleSaveReport} onCancel={() => setView('UPDATE_LIST')} />}
        {view === 'TABLE' && (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <h2 className="text-2xl font-black text-slate-800 uppercase">Riwayat Penugasan</h2>
              <div className="flex gap-2">
                <button onClick={() => fetchData(true)} className="p-2.5 bg-slate-200 rounded-2xl hover:bg-slate-300 transition-all"><svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg></button>
                {role === UserRole.USER && <button onClick={() => setView('INPUT')} className="bg-primary text-white px-5 py-2.5 rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-lg">Tambah Laporan</button>}
              </div>
            </div>
            <div className="bg-white p-5 rounded-2xl shadow-sm border border-slate-200 grid grid-cols-1 md:grid-cols-5 gap-5 items-end">
              <input type="date" className="w-full px-4 py-2.5 border rounded-xl text-xs font-bold" value={tableStartDate} onChange={(e) => setTableStartDate(e.target.value)} />
              <input type="date" className="w-full px-4 py-2.5 border rounded-xl text-xs font-bold" value={tableEndDate} onChange={(e) => setTableEndDate(e.target.value)} />
              {(role === UserRole.ADMIN || (role === UserRole.GUEST && !session.ulp)) && (
                <select className="w-full px-4 py-2.5 border rounded-xl text-xs font-bold bg-white" value={tableUlpFilter} onChange={(e) => setTableUlpFilter(e.target.value as ULPName)}>
                  <option value="">Semua ULP</option>
                  {Object.values(ULPName).map(u => <option key={u} value={u}>{u}</option>)}
                </select>
              )}
              <button onClick={() => { setTableStartDate(initStart); setTableEndDate(initEnd); setTableUlpFilter(''); }} className="w-full py-2.5 px-4 bg-slate-50 text-slate-400 font-black rounded-xl text-[10px] uppercase border transition-all">Reset</button>
              {role === UserRole.ADMIN && <button onClick={handleDownloadExcel} className="w-full py-2.5 px-4 bg-green-600 text-white font-black rounded-xl text-[10px] uppercase shadow-lg">Export Excel LENGKAP</button>}
            </div>
            <DataTable reports={filteredReportsForTable} onEdit={role !== UserRole.GUEST ? openEditForm : undefined} />
          </div>
        )}
        {view === 'ABOUT' && (
          <div className="max-w-3xl mx-auto animate-fade-in">
            <div className="bg-white rounded-[2rem] shadow-xl overflow-hidden border border-slate-200">
               <div className="bg-primary p-12 text-white text-center flex flex-col items-center">
                  <img src={APP_LOGO} alt="App" className="h-36 w-auto object-contain z-10 mb-6" />
                  <h1 className="text-4xl font-black mb-1 uppercase">Yandal Patrol Monitoring</h1>
                  <span className="text-[10px] font-black uppercase tracking-[0.3em] bg-white/20 px-4 py-1.5 rounded-full mt-3">Version {APP_VERSION}</span>
               </div>
               <div className="p-10 space-y-10">
                  <section className="text-center space-y-4">
                    <h2 className="text-xl font-black text-slate-800 uppercase">Status Sistem Notifikasi</h2>
                    <div className="flex flex-col items-center gap-4">
                      <div className={`px-6 py-3 rounded-2xl flex items-center gap-3 border ${notifPermission === 'granted' ? 'bg-green-50 border-green-200 text-green-700' : notifPermission === 'denied' ? 'bg-red-50 border-red-200 text-red-700' : 'bg-slate-50 border-slate-200 text-slate-500'}`}>
                        <div className={`w-3 h-3 rounded-full ${notifPermission === 'granted' ? 'bg-green-500 animate-pulse' : notifPermission === 'denied' ? 'bg-red-500' : 'bg-slate-400'}`}></div>
                        <span className="text-sm font-black uppercase tracking-widest">Izin Notifikasi: {notifPermission === 'granted' ? 'Aktif' : notifPermission === 'denied' ? 'Diblokir' : 'Belum Diizinkan'}</span>
                      </div>
                    </div>
                  </section>
                  <div className="pt-10 border-t border-slate-100 flex flex-col items-center gap-2">
                    <p className="text-base font-black text-slate-800 uppercase">PLN Electricity Services Bukittinggi</p>
                    <p className="text-[11px] text-slate-400 font-bold uppercase">© 2025 • IT Unit Layanan Bukittinggi</p>
                  </div>
               </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React from 'react';
import { ReportData, LoginSession } from '../types';

interface UpdateListProps {
  reports: ReportData[];
  session: LoginSession;
  onUpdate: (report: ReportData) => void;
}

export const UpdateList: React.FC<UpdateListProps> = ({ reports, session, onUpdate }) => {
  // Mendapatkan tanggal lokal (YYYY-MM-DD) untuk akurasi hari ini di zona waktu Indonesia
  const localDate = new Date();
  const year = localDate.getFullYear();
  const month = String(localDate.getMonth() + 1).padStart(2, '0');
  const day = String(localDate.getDate()).padStart(2, '0');
  const todayLocal = `${year}-${month}-${day}`;

  const incompleteReports = reports.filter(r => {
    // 1. Filter berdasarkan tanggal lokal (hari ini)
    const reportDate = new Date(r.timestamp);
    const rYear = reportDate.getFullYear();
    const rMonth = String(reportDate.getMonth() + 1).padStart(2, '0');
    const rDay = String(reportDate.getDate()).padStart(2, '0');
    const rDateString = `${rYear}-${rMonth}-${rDay}`;

    const isToday = rDateString === todayLocal;

    // 2. Filter ULP sesuai session (Petugas hanya melihat ULP-nya sendiri)
    const isSameUlp = r.ulp === session.ulp;

    // 3. Filter Petugas sesuai session (Petugas hanya mengupdate laporan milik timnya)
    // Menggunakan perbandingan case-insensitive dan trimming untuk keamanan data
    const sP1 = session.petugas1?.trim().toLowerCase();
    const sP2 = session.petugas2?.trim().toLowerCase();
    const rP1 = r.petugas1?.trim().toLowerCase();
    const rP2 = r.petugas2?.trim().toLowerCase();

    const isSamePetugas = (rP1 === sP1 && rP2 === sP2) || (rP1 === sP2 && rP2 === sP1);

    if (!isToday || !isSameUlp || !isSamePetugas) return false;

    // 4. Cek jika ada foto yang masih null (belum lengkap 6 sebelum & 6 sesudah)
    const isBeforeIncomplete = r.photos.sebelum.some(p => p === null || p === '');
    const isAfterIncomplete = r.photos.sesudah.some(p => p === null || p === '');

    return isBeforeIncomplete || isAfterIncomplete;
  });

  if (incompleteReports.length === 0) {
    return (
      <div className="bg-white p-12 text-center rounded-[2rem] shadow-sm border border-slate-200 animate-fade-in">
        <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4 border border-slate-100">
          <svg className="w-8 h-8 text-slate-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
          </svg>
        </div>
        <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest">Semua laporan anda hari ini sudah lengkap</h3>
        <p className="text-[10px] text-slate-400 mt-2 font-bold uppercase tracking-widest">Tidak ada data foto yang perlu diupdate untuk tim {session.petugas1} & {session.petugas2}.</p>
      </div>
    );
  }

  return (
    <div className="space-y-4 animate-fade-in">
      <div className="flex items-center justify-between mb-2">
        <div>
          <h3 className="text-lg font-black text-slate-800 uppercase tracking-tight">Update Dokumentasi Hari Ini</h3>
          <p className="text-[9px] font-bold text-primary uppercase tracking-widest">{session.ulp} • {session.petugas1} & {session.petugas2}</p>
        </div>
        <span className="px-3 py-1 bg-amber-50 text-amber-600 rounded-full border border-amber-100 text-[10px] font-black uppercase tracking-widest">
          {incompleteReports.length} Laporan Belum Lengkap
        </span>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {incompleteReports.map(report => (
          <div key={report.id} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 hover:shadow-md transition-all group border-l-4 border-l-amber-400">
            <div className="flex justify-between items-start mb-4">
              <div>
                <div className="text-[10px] font-black text-primary uppercase tracking-widest mb-1">{report.noPenugasan}</div>
                <h4 className="font-black text-slate-800 text-sm uppercase tracking-tight">{report.penyulang}</h4>
                <div className="text-[11px] font-bold text-slate-500 uppercase">Keypoint: {report.keypoint}</div>
              </div>
              <button 
                onClick={() => onUpdate(report)}
                className="bg-primary text-white px-4 py-2 rounded-xl font-black text-[9px] uppercase tracking-widest shadow-lg shadow-cyan-100 hover:bg-cyan-800 transition-all active:scale-95"
              >
                Lengkapi Foto
              </button>
            </div>

            <div className="grid grid-cols-2 gap-4 pt-4 border-t border-slate-50">
              <div className="space-y-1">
                <div className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Foto Sebelum</div>
                <div className="flex items-center gap-1">
                  <div className="flex-1 h-1.5 bg-slate-100 rounded-full overflow-hidden">
                    <div 
                      className="h-full bg-amber-400 transition-all duration-500" 
