                      style={{ width: `${(report.photos.sesudah.filter(p => p !== null && p !== '').length / 6) * 100}%` }}
                    ></div>
                  </div>
                  <span className="text-[9px] font-black text-slate-500">{report.photos.sesudah.filter(p => p !== null && p !== '').length}/6</span>
                </div>
