                          <img src={formatImageUrl(report.photos.sebelum[idx]!)} alt="Done" className="w-full h-full object-cover" />
                       </div>
                    </div>
                  )}

                  {isSsdhEmpty ? (
                    <PhotoUpload 
                      id={`sesudah-${num}`}
                      label={`Kondisi Sesudah`}
                      imageSrc={photosSesudah[idx]}
                      onImageChange={(file) => handlePhotoChange(idx, 'sesudah', file)}
                    />
                  ) : (
                    <div className="flex flex-col gap-2 opacity-40">
                       <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1 italic">Kondisi Sesudah (Terisi)</label>
                       <div 
                        className="w-full h-36 bg-slate-100 rounded-2xl flex items-center justify-center border-2 border-slate-200 overflow-hidden cursor-pointer grayscale hover:grayscale-0 transition-all"
