                          <img src={formatImageUrl(report.photos.sesudah[idx]!)} alt="Done" className="w-full h-full object-cover" />
                       </div>
                    </div>
                  )}
                </div>
              </div>
            );
          })}
        </div>

        <div className="flex items-center justify-end gap-3 pt-6 border-t border-slate-100 sticky bottom-0 bg-white/95 backdrop-blur py-6 z-10 px-6 -mx-6">
          <button 
            type="button" 
            onClick={onCancel}
            disabled={isSubmitting}
            className="px-6 py-3.5 rounded-2xl text-slate-400 hover:text-slate-600 hover:bg-slate-100 font-black uppercase text-[10px] tracking-widest transition-all"
          >
            Batal
          </button>
          <button 
            type="submit" 
            disabled={isSubmitting}
            className="px-10 py-3.5 rounded-2xl bg-primary text-white font-black uppercase text-[10px] tracking-widest hover:bg-cyan-800 shadow-xl shadow-cyan-100 transition-all flex items-center justify-center gap-3"
          >
            {isSubmitting ? 'Mengupdate...' : 'Simpan Update'}
