      </form>

      {/* Modal Pratinjau Gambar */}
      {previewImage && (
        <div 
          className="fixed inset-0 bg-slate-900/95 backdrop-blur-md z-[100] flex flex-col items-center justify-center p-4 animate-fade-in" 
