      photos: {
        sebelum: photosSebelum,
        sesudah: photosSesudah
      }
    };

    try {
      // Log ukuran payload untuk pemantauan (opsional)
      const payloadSize = JSON.stringify(updatedReport).length;
      console.log(`Payload size: ${(payloadSize / 1024).toFixed(2)} KB`);

      await onSubmit(updatedReport, true);
    } catch (error) {
      alert("Gagal mengupdate data ke server.");
      setIsSubmitting(false);
    }
  };

